INSERT INTO `wp_options` VALUES (206,'_site_transient_feed_d117b5738fbd35bd8c0391cda1f2b5d9','a:6:{s:5:\"child\";a:1:{s:0:\"\";a:1:{s:3:\"rss\";a:1:{i:0;a:6:{s:4:\"data\";s:3:\"\n\n\n\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:7:\"version\";s:3:\"2.0\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:1:{s:7:\"channel\";a:1:{i:0;a:6:{s:4:\"data\";s:112:\"\n	\n	\n	\n	\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:1:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"WordPress Planet\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://planet.wordpress.org/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"language\";a:1:{i:0;a:5:{s:4:\"data\";s:2:\"en\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:47:\"WordPress Planet - http://planet.wordpress.org/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"item\";a:50:{i:0;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:101:\"Open Channels FM: The Real Challenge of Technological Solutions: Exclusion in the Age of Verification\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2556720\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:107:\"https://openchannels.fm/the-real-challenge-of-technological-solutions-exclusion-in-the-age-of-verification/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:419:\"David Snead, director of the Secure Hosting Alliance and a long-time Internet policy leader, shares his perspective on the complexities that emerge when technological solutions like age verification are implemented in the digital infrastructure space. Dave&#8217;s reflection highlights how the push for more secure, regulated environments can unintentionally create barriers for vulnerable or less tech-savvy [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 10 Jul 2026 14:34:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:1;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"Dennis Snell: See DATA, CDATA, RCDATA, and PCDATA oh my!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:36:\"https://fluffyandflakey.blog/?p=3943\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://fluffyandflakey.blog/2026/07/10/see-data-cdata-rcdata-and-pcdata-oh-my/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:30966:\"<p class=\"wp-block-paragraph\">HTML and XML are markup languages based on plaintext files. This means that any given character <em>could</em> be part of a syntax form (a tag, a comment, a character reference, etc…) <em>or</em> it could be representing itself the way it reads in the file literally.</p>\n\n\n<div class=\"wp-block-code\">\n	<div class=\"cm-editor\">\n		<div class=\"cm-scroller\">\n			\n<pre>\n<code class=\"language-html\"><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">tag</span><span class=\"tok-punctuation\">&gt;</span><span class=\"tok-string\">&amp;middot;</span> Text node<span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">tag</span><span class=\"tok-punctuation\">&gt;</span></div></code></pre>\n		</div>\n	</div>\n</div>\n\n\n<p class=\"wp-block-paragraph\">Whenever a character might be ambiguous, both languages require explicit indication of the intent of the character. In HTML this occurs via <em>escaping</em>, while XML allows escaping <em>or</em> wrapping the content in a <em>marked section</em>, specifically a <code>CDATA section</code>.</p>\n\n\n<div class=\"wp-block-code\">\n	<div class=\"cm-editor\">\n		<div class=\"cm-scroller\">\n			\n<pre>\n<code class=\"language-xml\"><div class=\"cm-line\"><span class=\"tok-string\">&amp;lt;</span>tag<span class=\"tok-string\">&amp;gt;</span></div><div class=\"cm-line\"><span class=\"tok-string2\">&lt;![CDATA[&lt;tag&gt;· Text node&lt;/tag&gt;]]&gt;</span></div></code></pre>\n		</div>\n	</div>\n</div>\n\n\n<p class=\"wp-block-paragraph\">These terms confuse me at times, especially since <code>CDATA</code> and <code>CDATA sections</code> are distinct forms of the same content, and it’s easy to conflate each term. This post is here to disambiguate the terms, their meanings, and why they exist.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#summary\">The punchline comes at the end</a>, but the story is hopefully worth the read.</p>\n\n\n\n<span id=\"more-3943\"></span>\n\n\n\n<h2 class=\"wp-block-heading\">Markup and mixed content</h2>\n\n\n\n<p class=\"wp-block-paragraph\">One of the first jobs of a parser for any plaintext-oriented format is to determine if the next input character represents real text or is part of a syntax form that carries special meaning. If it’s a syntax form we would call it <em>markup</em>, but if the characters are part of real text meant for display or rendering or reading then we call it <em>data</em>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Anything that is not syntax is data.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The interpretation of the next character depends on the region of the document in which it’s parsed. While the rules for syntax forms are complicated<sup class=\"fn\"><a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#0ba56e66-ab0f-4fbd-93d2-df22a6984fd7\" id=\"0ba56e66-ab0f-4fbd-93d2-df22a6984fd7-link\">1</a></sup>, this post will focus on the data forms.</p>\n\n\n\n<h3 class=\"wp-block-heading\">PCDATA — “parsed character data”</h3>\n\n\n\n<p class=\"is-style-plain wp-block-paragraph\"><em>May form: tags, comments, sections, character references, literal text.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\">Characters in this region could be data or could form the start of a new markup element. It’s “parsed” because it needs parsing before determining what it represents.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The HTML specification renames this to <code>Data</code>, which is simpler and a bit harder to search for. In XML, however, it’s used in a document-type definition (DTD). When an element may contain content — text — its data model must include <code>#PCDATA</code>. Otherwise the only characters allowable within that element are other elements, comments, and whitespace. XML documents are required to be valid SGML documents, so its own specification adopts the terminology from SGML’s.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Those who have worked with DTDs might note that <em>elements</em> in XML may contain <code>#PCDATA</code> while <em>attributes</em> contain <code>CDATA</code> instead. First of all, the <code>#</code> is there only to make it explicit that <code>PCDATA</code> is referring to the reserved keyword, rather than a <code>&lt;pcdata&gt;</code> element. Secondly, there’s a good reason for this, which is that attributes can only contain text — they can’t contain other elements of markup. If an attribute value could contain a <code>&lt;span&gt;</code> element, for example, then the attribute value would need to be <code>#PCDATA</code> instead, but this is prevented by design.</p>\n\n\n\n<p class=\"wp-block-paragraph\">PCDATA actually contains more than just literal text and elements. In addition to comments, processing instructions, and other node-like syntax, one important feature of PCDATA is the <em>character reference</em>. These make it possible to represent characters that would conflate with syntax (such as ‘<code>&lt;</code>’ — <code>&amp;lt;</code>) or which might be cumbersome to enter on a keyboard (such as ‘§’ — <code>&amp;sect;</code>). When parsing, each character in these sequences neither creates an element nor  displays as the text itself; rather, the entire sequence is parsed and translates into the character it refers to.</p>\n\n\n\n<p class=\"wp-block-paragraph\">HTML pre-specifies <a href=\"https://github.com/w3c/html/blob/master/entities.json\">a fixed set of named character references</a>, but any Unicode code point may be referenced by its decimal or hexadecimal numeric index. While XML also allows referencing code points by their index<sup class=\"fn\"><a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#6d3de5b9-f8a6-4f46-853b-3d407731feca\" id=\"6d3de5b9-f8a6-4f46-853b-3d407731feca-link\">2</a></sup>, it only pre-specifies the five named characters which correspond to its main markup introducers: <code>&lt;</code>, <code>></code>, <code>&amp;</code>, <code>\'</code>, and <code>\"</code>. In XML, any additional named character references are created through the DTD by defining <em>entities</em>.</p>\n\n\n\n<h3 class=\"wp-block-heading\"> CDATA — “character data”</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><em>May form: [character references], literal text.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\">If a character isn’t markup, then it’s <em>character data</em>, which means that it’s representing its literal self or it’s part of a <em>character reference</em>. Once the parser has entered this region it will not create markup elements.</p>\n\n\n\n<p class=\"wp-block-paragraph\">CDATA is the most confusable kind of character data; this is because there are many kinds of CDATA that share the same name:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>XML attributes may contain CDATA, where character references are decoded.</li>\n\n\n\n<li>XML CDATA sections only contain CDATA, but character references are not decoded.</li>\n\n\n\n<li>HTML <em>kind of</em> has the same CDATA sections, but only in <em>foreign elements</em> (inlined SVG and MathML elements).</li>\n\n\n\n<li>SGML elements may be declared to have a CDATA content model, in which case all content until the appropriate closing tag is to be parsed as character data, where character references are not decoded.</li>\n</ul>\n\n\n\n<h4 class=\"wp-block-heading\">CDATA sections contain only literal text</h4>\n\n\n\n<p class=\"wp-block-paragraph\">Many people are familiar with <code>CDATA sections</code>, but it took me far longer to understand them than my intuition led on. They are the vestige of SGML “marked regions” which tell the parser to handle a specific range of bytes in a special way. The <code>CDATA</code> section is one of those, which tells the parser to <em>completely turn off until it reaches <code>]]&gt;</code></em>.</p>\n\n\n<div class=\"wp-block-code\">\n	<div class=\"cm-editor\">\n		<div class=\"cm-scroller\">\n			\n<pre>\n<code class=\"language-xml\"><div class=\"cm-line\"><span class=\"tok-string2\">&lt;![CDATA[literal characters only in here]]&gt;</span></div></code></pre>\n		</div>\n	</div>\n</div>\n\n\n<p class=\"wp-block-paragraph\">It had other marked sections, however, which served different purposes.</p>\n\n\n<div class=\"wp-block-code\">\n	<div class=\"cm-editor\">\n		<div class=\"cm-scroller\">\n			\n<pre>\n<code class=\"language-xml\"><div class=\"cm-line\">&lt;![IGNORE[everything in here is ignored; it doesn’t exist.]]&gt;</div><div class=\"cm-line\">&lt;![INCLUDE[in here things <span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">em</span><span class=\"tok-punctuation\">&gt;</span>do<span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">em</span><span class=\"tok-punctuation\">&gt;</span> exist as normal.]]&gt;</div><div class=\"cm-line\">&lt;![RCDATA[read on to learn about RCDATA!]]&gt;</div></code></pre>\n		</div>\n	</div>\n</div>\n\n\n<p class=\"wp-block-paragraph\">The <code>IGNORE</code> and <code>INCLUDE</code> sections may seem strange, since SGML already has comments, and <code>INCLUDE</code> effectively does nothing, but the sections can be marked by replaced <em>entities</em>, making for conditional inclusion which can be overwritten via command-line arguments when invoking the SGML parser.</p>\n\n\n<div class=\"wp-block-code\">\n	<div class=\"cm-editor\">\n		<div class=\"cm-scroller\">\n			\n<pre>\n<code class=\"language-xml\"><div class=\"cm-line\">&lt;!ENTITY % review-only &quot;IGNORE&quot;&gt;</div><div class=\"cm-line\"></div><div class=\"cm-line\">...</div><div class=\"cm-line\"></div><div class=\"cm-line\">&lt;![%review-only;[</div><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">aside</span><span class=\"tok-punctuation\">&gt;</span></div><div class=\"cm-line\">Add `-Dreview-only=INCLUDE` when building drafts.</div><div class=\"cm-line\">This note won’t appear otherwise.</div><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">aside</span><span class=\"tok-punctuation\">&gt;</span></div><div class=\"cm-line\">]]&gt;</div></code></pre>\n		</div>\n	</div>\n</div>\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://www.w3.org/XML/9712-reports.html#:~:text=XML%20will%20have%20CDATA%20marked%20sections\">XML only retained CDATA sections</a> from SGML, while HTML never included them. They are useful because they are so easy to parse. All characters inside of them are to be treated as literal text, up until the first occurrence of the terminating <code>]]&gt;</code>. Unlike elements, the marked sections do not nest.</p>\n\n\n\n<h4 class=\"wp-block-heading\">There are no CDATA sections in HTML</h4>\n\n\n\n<p class=\"wp-block-paragraph\">The Internet is full of discussions about the use of CDATA sections in HTML, but there are no such things, mostly. HTML itself is an amalgam of pure HTML and embedded SVG and MathML. Content inside of those <em>embedded</em> SVG and MathML elements is parsed differently, and within this “foreign content” there <em>are</em> <code>CDATA section</code> nodes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">When something which <em>look like a CDATA section</em> appears in an HTML document, it’s transformed into a “bogus” HTML comment and considered a snippet of malformed markup. To make things more confusing, the parsing rules differ inside an HTML document for these regions depending on whether they are found within HTML elements or foreign elements.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>When a real CDATA section appears within SVG and MathML, it parses as in XML or SGML — everything is  literal text <em>until</em> the nearest <code>]]&gt;</code>.</li>\n\n\n\n<li>When a malformed CDATA look-alike appears in an HTML element, it gets special treatment — the parser only turns off until the nearest <code>&gt;</code>. This means that these sections end even without a closing <code>]]&gt;</code>, and when they do, all of their contained content disappears from the page.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">That small difference confuses naïve parsers and is a regular source of bugs.</p>\n\n\n<div class=\"wp-block-code\">\n	<div class=\"cm-editor\">\n		<div class=\"cm-scroller\">\n			\n<pre>\n<code class=\"language-html\"><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">div</span><span class=\"tok-punctuation\">&gt;</span>&lt;![CDATA[There are no tags in here.]]&gt;<span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">div</span><span class=\"tok-punctuation\">&gt;</span></div><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">svg</span><span class=\"tok-punctuation\">&gt;</span><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">text</span><span class=\"tok-punctuation\">&gt;</span>&lt;![CDATA[<span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">none</span><span class=\"tok-punctuation\">&gt;</span> here either.]]&gt;<span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">text</span><span class=\"tok-punctuation\">&gt;</span><span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">svg</span><span class=\"tok-punctuation\">&gt;</span></div><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">div</span><span class=\"tok-punctuation\">&gt;</span>&lt;![CDATA[But there <span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">em</span><span class=\"tok-punctuation\">&gt;</span>are<span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">em</span><span class=\"tok-punctuation\">&gt;</span> tags in here]]&gt;<span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">div</span><span class=\"tok-punctuation\">&gt;</span></div><div class=\"cm-line\">     the section ends here ╯   ╰ start of a real end tag</div><div class=\"cm-line\"></div><div class=\"cm-line\">The following is the equivalent markup to the third line.</div><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">div</span><span class=\"tok-punctuation\">&gt;</span><span class=\"tok-comment\">&lt;!--But there &lt;em--&gt;</span>are<span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName tok-invalid\">em</span><span class=\"tok-punctuation\">&gt;</span> tags in here]]&gt;<span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">div</span><span class=\"tok-punctuation\">&gt;</span></div></code></pre>\n		</div>\n	</div>\n</div>\n\n\n<h4 class=\"wp-block-heading\">SGML contains CDATA regions outside of marked CDATA sections</h4>\n\n\n\n<p class=\"wp-block-paragraph\">SGML made it possible to define more kinds of content than XML does for a given element. For example, an element in SGML can be declared to have a CDATA content model, in which case the element itself behaves like a CDATA section. All characters after the opening tag are treated as literal text until the parser finds the nearest appropriate end tag<sup class=\"fn\"><a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#2d0aee27-cf77-4b19-a4c5-3b1cc4192c53\" id=\"2d0aee27-cf77-4b19-a4c5-3b1cc4192c53-link\">3</a></sup>. XML rejected this ability because it increases the complexity of the parser and requires that every document also contains a full DTD when parsing. For example, if an element were declared to have CDATA content, then <code>a &lt;at> b</code> would represent that literal string; on the other hand, if it were declared like any other normal element, it would have three children: “<code>a </code>”, the <code>&lt;at></code> opening tag, and “<code> b</code>”.</p>\n\n\n<div class=\"wp-block-code\">\n	<div class=\"cm-editor\">\n		<div class=\"cm-scroller\">\n			\n<pre>\n<code class=\"language-xml\"><div class=\"cm-line\">&lt;!ELEMENT verbatim - - CDATA&gt;</div><div class=\"cm-line\"></div><div class=\"cm-line\">...</div><div class=\"cm-line\"></div><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">verbatim</span><span class=\"tok-punctuation\">&gt;</span></div><div class=\"cm-line\">There are <span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">no</span><span class=\"tok-punctuation\">&gt;</span> tags in here, because this is CDATA,</div><div class=\"cm-line\">but you wouldn’t know without reading the DTD,</div><div class=\"cm-line\">overcomplicating the demands on the parser.</div><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">verbatim</span><span class=\"tok-punctuation\">&gt;</span></div></code></pre>\n		</div>\n	</div>\n</div>\n\n\n<p class=\"wp-block-paragraph\">These kinds of elements do exist in HTML, though a few were modified when HTML5 was standardized in 2008. Inside of the elements, the parser essentially turns off, which makes them easy to parse and can help avoid the need to extensively escape content. These elements are, of course, <code>&lt;script></code> and <code>&lt;style></code><sup class=\"fn\"><a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#68152c30-bf36-4e5b-a7df-3f0610daeadb\" id=\"68152c30-bf36-4e5b-a7df-3f0610daeadb-link\">4</a></sup>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Were it not for the CDATA declared content model, every angle bracket and ampersand would have to be escaped in included JavaScript and CSS. In XHTML this was required, because it had no CDATA declared content model (since it was XML)<sup class=\"fn\"><a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#21aeab38-6e1f-4700-a8f4-27c96ebe0c3b\" id=\"21aeab38-6e1f-4700-a8f4-27c96ebe0c3b-link\">5</a></sup>.</p>\n\n\n\n<h4 class=\"wp-block-heading\">All text in XML is CDATA</h4>\n\n\n\n<p class=\"wp-block-paragraph\">Herein lies the most-confusing aspect of discussing CDATA — XML contains CDATA sections as well as <em>CDATA</em> as normal text. After parsing there is no distinction between <code>&amp;lt;tag&amp;gt;</code> and <code>&lt;![CDATA[&lt;tag&gt;]]&gt;</code> in the parsed content.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Many XML generators (or serializers) provide two mechanisms for creating text content: one wraps text in a <code>CDATA section</code> and leaves the text as it came (apart from avoiding including the terminating sequence); the other escapes syntax characters instead. While there are times where it would be appropriate to intentionally pick one over the other, a good library design would at least offer a third mechanism (if not <em>only</em> providing this third mechanism) which simply produces <em>CDATA</em>, itself determining when to wrap and when to escape<sup class=\"fn\"><a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#6e56b2ce-8156-4bf5-a4d3-d297a401c1a3\" id=\"6e56b2ce-8156-4bf5-a4d3-d297a401c1a3-link\">6</a></sup>, and whether or not to produce chunks of wrapped text interspersed with chunks of escaped text.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The real difference between these two kinds of CDATA is purely presentational in the source document, as the XML snippet below only contains one text node, not two. <em>Creating CDATA does not imply creating a <code>CDATA section</code>!</em></p>\n\n\n<div class=\"wp-block-code\">\n	<div class=\"cm-editor\">\n		<div class=\"cm-scroller\">\n			\n<pre>\n<code class=\"language-xml\"><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">rule</span><span class=\"tok-punctuation\">&gt;</span><span class=\"tok-string2\">&lt;![CDATA[#X13&lt;d&amp;r&gt;]]&gt;</span> (<span class=\"tok-string\">&amp;pp;</span>4 <span class=\"tok-string\">&amp;ss;</span>3.11)<span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">rule</span><span class=\"tok-punctuation\">&gt;</span></div></code></pre>\n		</div>\n	</div>\n</div>\n\n\n<h3 class=\"wp-block-heading\">RCDATA — “replaceable character data”</h3>\n\n\n\n<p class=\"wp-block-paragraph\"><em>May form: character references, literal text.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\">There’s one more confusing designation for characters in the HTML and XML input streams: <em>RCDATA</em>. RCDATA is almost identical to CDATA, except that in contexts where CDATA does not decode character references and entities, RCDATA <em>will</em> decode them <em>into</em> CDATA. This is confusing, because in the context of an XML attribute, the <code>CDATA</code> designation in a DTD automatically implies that character references are decoded, unlike the <code>CDATA</code> sections in <em>content</em>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">To this end there are no RCDATA attributes, since character references are always decoded inside attribute values. The RCDATA declaration is like the SGML CDATA content declaration: all characters following the opening tag for this element will be treated as text until the nearest matching closing tag (the difference being only that character references are recognized and decoded).</p>\n\n\n\n<p class=\"wp-block-paragraph\">It’s worth remembering that XML rejected the CDATA content type because of how it complicates parsing, and it also rejected the RCDATA type. On the other hand, RCDATA was incorporated into HTML, but statically so. HTML has no configurable DTD, but in its specification two elements contain RCDATA content:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><code>TITLE</code></li>\n\n\n\n<li><code>TEXTAREA</code></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">While it’s easy to comprehend the way that <code>&lt;textarea></code> works, and that’s probably because we are used to entering text into one on a web page, the behavior of <code>&lt;title></code> is consistently confused in all manner of programming languages, platforms, and HTML-parsing code.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The TITLE element <em>only</em> contains character data — it cannot contain other markup. The parsing is among the easiest sections of an HTML document to parse: once the <code>&lt;title&gt;</code> opening tag is detected, the parser can capture everything until the nearest <code>&lt;/title&gt;</code> closing tag. Everything it captured is literal text, after decoding character references.</p>\n\n\n<div class=\"wp-block-code\">\n	<div class=\"cm-editor\">\n		<div class=\"cm-scroller\">\n			\n<pre>\n<code class=\"language-html\"><div class=\"cm-line\"><span class=\"tok-comment\">&lt;!-- the title is &quot;&lt;title&gt;&quot; --&gt;</span></div><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">title</span><span class=\"tok-punctuation\">&gt;</span><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">title</span><span class=\"tok-punctuation\">&gt;</span><span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">title</span><span class=\"tok-punctuation\">&gt;</span></div><div class=\"cm-line\"></div><div class=\"cm-line\"><span class=\"tok-comment\">&lt;!-- equivalent HTML --&gt;</span></div><div class=\"cm-line\"><span class=\"tok-punctuation\">&lt;</span><span class=\"tok-typeName\">title</span><span class=\"tok-punctuation\">&gt;</span><span class=\"tok-string\">&amp;lt;</span>title<span class=\"tok-string\">&amp;gt;</span><span class=\"tok-punctuation\">&lt;/</span><span class=\"tok-typeName\">title</span><span class=\"tok-punctuation\">&gt;</span></div></code></pre>\n		</div>\n	</div>\n</div>\n\n\n<p class=\"wp-block-paragraph\">This complicates content management systems like WordPress which allow posts to have HTML in their <em>post titles</em>, because a page can show richly-formatted article titles which cannot be represented in the browser tab’s label, and care must be taken to extract the plaintext content from that HTML before display in those contexts.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"summary\">Coda</h2>\n\n\n\n<p class=\"wp-block-paragraph\">HTML and XML both speak about different kinds of characters in their source documents and content models, which traces from the complicated ways that SGML documents could be constructed. SGML’s complexity almost always stems from the central idea that computers should do extra work to remove the hassle for humans to enter structured content in plaintext documents.</p>\n\n\n\n<p class=\"wp-block-paragraph\">HTML, inspired by SGML, adopted some of the names and mechanisms for parsing those regions of text in distinct ways, but codified a single parsing standard independent of SGML. When XML was later developed, it was meant to form a simplified subset of SGML. This subset flipped the tradeoffs, leaning on humans performing extra work to remove the hassle for computers to parse structure in plaintext documents. For these text forms, this meant rejecting a few of the constructs while retaining others.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This is also another demonstration of how <em>balanced tags are not enough</em> to have well-behaved HTML with a naïve parser. A well-formed XML document <a href=\"https://www.ch.imperial.ac.uk/rzepa/talks/pmr11/xml-dev/9708/0152.html\">may be parsed with a terse PERL script and regular expression</a>, but HTML relies heavily on the context in which characters are found. Any HTML parser <em>must</em> know the special rules for each kind of element’s content model.</p>\n\n\n\n<h3 class=\"wp-block-heading\">In summary</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li>When it’s unclear whether a character forms text or markup, that is PCDATA. Once parsed, there is no PCDATA anymore; it’s either a form of DATA or MARKUP.</li>\n\n\n\n<li>All text nodes in HTML are “DATA.”</li>\n\n\n\n<li>“CDATA” just means “character data” and means that after parsing, the content is text. It does not indicate whether character references are to be decoded or not; that comes from the region in the document, based on its context.</li>\n\n\n\n<li>There are no CDATA sections in HTML<sup class=\"fn\"><a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#31e75dae-1847-44df-92e1-8ae5756eeec6\" id=\"31e75dae-1847-44df-92e1-8ae5756eeec6-link\">7</a></sup>.</li>\n\n\n\n<li>All text nodes in XML are CDATA, but only after being parsed.</li>\n\n\n\n<li>CDATA sections offer a convenient way to avoid escaping, but are indistinguishable from the equivalent escaped text.</li>\n\n\n\n<li>HTML contains two special RCDATA elements which <em>only</em> and <em>always</em> contain a single text node child: <code>&lt;title&gt;</code> and <code>&lt;textarea&gt;</code>. Everything until the closing tag will be parsed as text, even if it looks like markup.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">This post is already long and still over-simplifies the picture. SGML is a rich and robust specification and includes <code>NDATA</code> and <code>SDATA</code>, HTML includes a <em>latching</em> <code>PLAINTEXT</code> parsing mode in which <em>the rest of the entire document is parsed as literal character data</em>, and there are other surprising goodies in how entities interact with the character mode.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Thanks for making it through to the end, or jumping directly here if you couldn’t wait.</p>\n\n\n<ol class=\"wp-block-footnotes\"><li id=\"0ba56e66-ab0f-4fbd-93d2-df22a6984fd7\">As an example, each part of a tag — its name, attribute names, attribute values — carries its own parsing rules. The same is true for comments, DOCTYPE declarations, and every other syntax form. <a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#0ba56e66-ab0f-4fbd-93d2-df22a6984fd7-link\"><img alt=\"↩\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/21a9.png\" style=\"height: 1em;\" />︎</a></li><li id=\"6d3de5b9-f8a6-4f46-853b-3d407731feca\">XML only allows character references to the characters in its “character set,” which is <em>almost</em> all Unicode code points, but excludes some control characters and U+FFFE and U+FFFF. <a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#6d3de5b9-f8a6-4f46-853b-3d407731feca-link\"><img alt=\"↩\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/21a9.png\" style=\"height: 1em;\" />︎</a></li><li id=\"2d0aee27-cf77-4b19-a4c5-3b1cc4192c53\">Because SGML was designed to minimize the amount of necessary syntax, it’s not necessary to have a full end tag for an open element, but that’s a simple-enough model to understand the concept. <a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#2d0aee27-cf77-4b19-a4c5-3b1cc4192c53-link\"><img alt=\"↩\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/21a9.png\" style=\"height: 1em;\" />︎</a></li><li id=\"68152c30-bf36-4e5b-a7df-3f0610daeadb\">The <code>&lt;style&gt;</code> element is straightforward, but <a href=\"https://sirre.al/2025/08/06/safe-json-in-script-tags-how-not-to-break-a-site/\">the <code>&lt;script&gt;</code> element has its own complicated modification</a> of the CDATA content model. It’s mostly CDATA, but makes it possible to escape the closing tag so that very old pages won’t break. HTML also applies this parsing mode for the <code>&lt;iframe&gt;</code>, <code>&lt;noembed&gt;</code>, <code>&lt;noframes&gt;</code>, and <code>&lt;noscript&gt;</code> elements (as well as for the deprecated <code>&lt;xmp&gt;</code> element), but these nominally should have no content inside of them (or shouldn’t be used); applying the CDATA content model prevents creating other elements as their children. <a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#68152c30-bf36-4e5b-a7df-3f0610daeadb-link\"><img alt=\"↩\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/21a9.png\" style=\"height: 1em;\" />︎</a></li><li id=\"21aeab38-6e1f-4700-a8f4-27c96ebe0c3b\">Frustratingly, in XHTML one <em>must</em> escape JavaScript and CSS in the page to avoid parsing failure, while in HTML one <em>must not</em>. This alone makes for a complicated stage in any reliable HTML/XHTML converter. <a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#21aeab38-6e1f-4700-a8f4-27c96ebe0c3b-link\"><img alt=\"↩\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/21a9.png\" style=\"height: 1em;\" />︎</a></li><li id=\"6e56b2ce-8156-4bf5-a4d3-d297a401c1a3\">Wrapping a language like HTML inside a CDATA section is a convenient way to represent the HTML visually and retain the ability to easily modify it, but entities present a problem. The serializer must either pre-translate the entity into its resolved character content, losing the macro-like behavior and its name; or leave the entity in place, thus nullifying it because it will not be recognized as an entity on parse. However, in such a situation, a serializer is free to terminate the CDATA section, append the entity, and open a new one to continue. <a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#6e56b2ce-8156-4bf5-a4d3-d297a401c1a3-link\"><img alt=\"↩\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/21a9.png\" style=\"height: 1em;\" />︎</a></li><li id=\"31e75dae-1847-44df-92e1-8ae5756eeec6\">As mentioned in the discussion about CDATA, embedded SVG and MathML elements <em>can</em> contain CDATA sections, but these are not technically HTML elements. <a href=\"https://fluffyandflakey.blog/tag/wordpress/feed/#31e75dae-1847-44df-92e1-8ae5756eeec6-link\"><img alt=\"↩\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/21a9.png\" style=\"height: 1em;\" />︎</a></li></ol>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 10 Jul 2026 11:07:27 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Dennis Snell\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:2;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:113:\"Gutenberg Times: WordPress 7.0.1 Fixes Registration Spam, wp_kses() CSS Corruption, and 7.0 Admin Design Glitches\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://gutenbergtimes.com/?p=45920\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:120:\"https://gutenbergtimes.com/wordpress-7-0-1-fixes-registration-spam-wp_kses-css-corruption-and-7-0-admin-design-glitches/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:7735:\"<p class=\"wp-block-paragraph\">WordPress 7.0.1 is now available. As the first maintenance release of the 7.0 cycle, it&#8217;s strictly a bug-fix release: every included ticket addresses either a regression introduced during 7.0 development or an issue intentionally deferred at the end of the cycle.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The release ships fixes for 17 core Trac tickets and 14 Gutenberg PRs. Because this is a maintenance release, sites with automatic background updates enabled will update to 7.0.1 automatically — everyone else should update as soon as possible. Here&#8217;s what stands out for each audience.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Kudos to release lead Aaron Jorbin and his team for pushing this release over the finish line and getting it into hands of WordPress users quickly. </p>\n\n\n\n<h2 class=\"wp-block-heading\">The most important fixes for end users</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Registration page spam is shut down (<a href=\"https://core.trac.wordpress.org/ticket/63085\">#63085</a>).</strong> The account registration page could be abused to send &#8220;Login details&#8221; spam emails from your site. This is arguably the most impactful fix in the release for anyone running a site with open registration — it protects both your users&#8217; inboxes and your domain&#8217;s email reputation.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>The 7.0 admin reskin gets its rough edges sanded off.</strong> WordPress 7.0&#8217;s refreshed admin design shipped with a handful of visual glitches that this release cleans up:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Form elements are now standardized in the mobile viewport (<a href=\"https://core.trac.wordpress.org/ticket/64999\">#64999</a>)</li>\n\n\n\n<li>The image editor&#8217;s scale and crop inputs no longer mismatch in size, and the info icon uses the new color scheme (<a href=\"https://core.trac.wordpress.org/ticket/64937\">#64937</a>, <a href=\"https://core.trac.wordpress.org/ticket/65428\">#65428</a>)</li>\n\n\n\n<li>The publish settings panel no longer crowds its primary action buttons together (<a href=\"https://core.trac.wordpress.org/ticket/65286\">#65286</a>)</li>\n\n\n\n<li>The Media Library&#8217;s loading spinner is properly aligned in the modal filter toolbar, and the search bar no longer jumps position after a search (<a href=\"https://core.trac.wordpress.org/ticket/65275\">#65275</a>, <a href=\"https://core.trac.wordpress.org/ticket/65296\">#65296</a>)</li>\n\n\n\n<li>A &#8220;black flash&#8221; that briefly appeared on wp-admin pages before the interface finished loading is gone (Gutenberg <a href=\"https://github.com/WordPress/gutenberg/pull/78493\">#78493</a>)</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Emoji behave correctly again.</strong> Two related fixes: the emoji detection script is once more printed in the admin (<a href=\"https://core.trac.wordpress.org/ticket/65310\">#65310</a>), and certain characters are no longer incorrectly replaced by Twemoji images (<a href=\"https://core.trac.wordpress.org/ticket/64318\">#64318</a>).</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Accessibility improvements to the new revisions experience.</strong> The Visual History / Revisions feature introduced in 7.0 receives several accessibility fixes: focus now moves to the revisions slider when entering revisions mode, and changed blocks are marked with a CSS outline as a secondary, non-color indicator — important for users with low vision or color blindness (<a href=\"https://core.trac.wordpress.org/ticket/65122\">#65122</a>, Gutenberg <a href=\"https://github.com/WordPress/gutenberg/pull/77530\">#77530</a>, <a href=\"https://github.com/WordPress/gutenberg/pull/78393\">#78393</a>, <a href=\"https://github.com/WordPress/gutenberg/pull/79691\">#79691</a>).</p>\n\n\n\n<h2 class=\"wp-block-heading\">The most important fixes for developers</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><code>wp_kses()</code> no longer corrupts valid CSS (<a href=\"https://core.trac.wordpress.org/ticket/65270\">#65270</a>).</strong> Since 7.0 RC4, <code>wp_kses()</code> could mangle legitimate <code>background-image: url(…)</code> declarations into a broken <code>style=\")\"</code> attribute. If your theme or plugin outputs inline background images through KSES-filtered content, 7.0.1 restores expected behavior — any workarounds you shipped can now be removed.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><code>global-styles-inline-css</code> can be dequeued again (<a href=\"https://core.trac.wordpress.org/ticket/65336\">#65336</a>).</strong> Since 7.0, developers were unable to remove the global styles inline stylesheet. If your build pipeline or performance optimization strips this and re-serves it another way, that control is back.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>PHP 8.5 compatibility fix in <code>wp_get_attachment_image_src()</code> (<a href=\"https://core.trac.wordpress.org/ticket/64742\">#64742</a>).</strong> An incorrect array access triggered issues under PHP 8.5. If you&#8217;re testing sites on newer PHP versions, this removes one blocker.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>A removed Navigation function returns as a deprecated shim (Gutenberg <a href=\"https://github.com/WordPress/gutenberg/pull/78484\">#78484</a>).</strong> <code>block_core_navigation_submenu_render_submenu_icon()</code> was removed in 7.0, breaking themes and plugins that called it directly. It&#8217;s restored as a deprecated shim — but treat this as your migration notice, not a reprieve. Update any code that references it.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Editor state management fixes reduce false &#8220;unsaved changes&#8221; warnings.</strong> Two Gutenberg fixes matter here: </p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>controlled/mode block changes are now marked non-persistent (<a href=\"https://github.com/WordPress/gutenberg/pull/79350\">#79350</a>), and </li>\n\n\n\n<li>related navigation entities are no longer dirtied during passive renders (<a href=\"https://github.com/WordPress/gutenberg/pull/79000\">#79000</a>). </li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Together these should mean fewer spurious dirty states and a cleaner undo history — a quality-of-life improvement if you build with template parts and navigation blocks.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Block Visibility: &#8220;hide everywhere&#8221; keeps working after a block opts out of visibility support (<a href=\"https://core.trac.wordpress.org/ticket/65389\">#65389</a>).</strong> If you register blocks that disable visibility support, previously hidden instances now stay hidden as expected.</p>\n\n\n\n<h2 class=\"wp-block-heading\">How to update</h2>\n\n\n\n<p class=\"wp-block-paragraph\">You can update directly from <strong>Dashboard → Updates</strong> in your site&#8217;s admin, run <code>wp core update</code> with WP-CLI, or download WordPress 7.0.1 from WordPress.org and install it manually. Sites that support automatic background updates for minor releases will begin updating on their own shortly.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The full ticket list is available in the<a href=\"https://make.wordpress.org/core/2026/07/01/wordpress-7-0-1-rc1-is-now-available/\"> release candidate announcement</a>, Trac report 4, and the 7.0.x editor tasks board on GitHub.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What&#8217;s next: WordPress 7.1</h2>\n\n\n\n<p class=\"wp-block-paragraph\">With 7.0.1 out the door, attention turns to the next major release: WordPress 7.1 is scheduled for August 19, 2026. To see what&#8217;s planned for the release, check out the <a href=\"https://make.wordpress.org/core/2026/06/19/roadmap-to-7-1/\">Roadmap to 7.1</a> on the Make WordPress Core blog.</p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 10 Jul 2026 09:34:45 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:18:\"Birgit Pauli-Haack\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:3;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:55:\"WordPress.org blog: WordPress 7.0.1 Maintenance Release\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=21005\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://wordpress.org/news/2026/07/wordpress-7-0-1-maintenance-release/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:8685:\"<p class=\"wp-block-paragraph\"><strong>WordPress 7.0.1 is now available!</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">This minor release includes fixes for 31 bugs <a href=\"https://core.trac.wordpress.org/query?resolution=fixed&amp;milestone=7.0.1&amp;group=component&amp;col=id&amp;col=summary&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=status&amp;col=priority&amp;order=priority\">throughout Core</a> and the <a href=\"https://core.trac.wordpress.org/changeset/62610\">Block Editor</a>, addressing issues affecting multiple areas of WordPress including the block editor, admin ui, and media. For a full list of bug fixes, please refer to the <a href=\"https://make.wordpress.org/core/2026/07/01/wordpress-7-0-1-rc1-is-now-available/\">release candidate announcement.</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0.1 is a short-cycle maintenance release. The next major version of WordPress will be 7.1; it is scheduled for release on 19 August 2026 at <a href=\"https://us.wordcamp.org/2026/\">WordCamp US</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you have sites that support automatic background updates, the update process will begin automatically.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You can <a href=\"https://wordpress.org/wordpress-7.0.1.zip\">download WordPress 7.0.1 from WordPress.org</a>, or visit your WordPress Dashboard, click “Updates”, and then click “Update Now”. For more information on this release, please <a href=\"https://wordpress.org/support/wordpress-version/version-7-0-1\">visit the HelpHub site</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Thank you to these WordPress contributors</h2>\n\n\n\n<p class=\"wp-block-paragraph\">This release was led by <a href=\"https://profiles.wordpress.org/jorbin/\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/masteradhoc/\">Brian Haas</a>, <a href=\"https://profiles.wordpress.org/cbravobernal/\">Carlos Bravo</a> and <a href=\"https://profiles.wordpress.org/estelaris/\">Estela Rueda</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress 7.0.1 would not have been possible without the contributions of the following people. Their asynchronous coordination to deliver maintenance fixes into a stable release is a testament to the power and capability of the WordPress community.</p>\n\n\n\n<p class=\"is-style-wporg-props-long wp-block-paragraph\"><a href=\"https://profiles.wordpress.org/jorbin\">Aaron Jorbin</a>, <a href=\"https://profiles.wordpress.org/abduremon\">Abdur Rahman Emon</a>, <a href=\"https://profiles.wordpress.org/abhishekfdd\">Abhishek Kumar</a>, <a href=\"https://profiles.wordpress.org/adamsilverstein\">Adam Silverstein</a>, <a href=\"https://profiles.wordpress.org/zieladam\">Adam Zieliński</a>, <a href=\"https://profiles.wordpress.org/iamadisingh\">Aditya Singh</a>, <a href=\"https://profiles.wordpress.org/wildworks\">Aki Hamano</a>, <a href=\"https://profiles.wordpress.org/afercia\">Andrea Fercia</a>, <a href=\"https://profiles.wordpress.org/andraganescu\">Andrei Draganescu</a>, <a href=\"https://profiles.wordpress.org/andrewserong\">Andrew Serong</a>, <a href=\"https://profiles.wordpress.org/annezazu\">annezazu</a>, <a href=\"https://profiles.wordpress.org/scruffian\">Ben Dwyer</a>, <a href=\"https://profiles.wordpress.org/bacoords\">Brian Coords</a>, <a href=\"https://profiles.wordpress.org/masteradhoc\">Brian Haas</a>, <a href=\"https://profiles.wordpress.org/cbravobernal\">Carlos Bravo</a>, <a href=\"https://profiles.wordpress.org/cogdesign\">cogdesign</a>, <a href=\"https://profiles.wordpress.org/danluu\">Dan Luu</a>, <a href=\"https://profiles.wordpress.org/talldanwp\">Daniel Richards</a>, <a href=\"https://profiles.wordpress.org/darshitrajyaguru97\">Darshit Rajyaguru</a>, <a href=\"https://profiles.wordpress.org/davidbaumwald\">David Baumwald</a>, <a href=\"https://profiles.wordpress.org/dmsnell\">Dennis Snell</a>, <a href=\"https://profiles.wordpress.org/dhruvang21\">Dhruvang21</a>, <a href=\"https://profiles.wordpress.org/ellatrix\">Ella Van Durpe</a>, <a href=\"https://profiles.wordpress.org/r1k0\">Erick Wambua</a>, <a href=\"https://profiles.wordpress.org/ecairol\">Esteban</a>, <a href=\"https://profiles.wordpress.org/estelaris\">Estela Rueda</a>, <a href=\"https://profiles.wordpress.org/mamaduka\">George Mamadashvili</a>, <a href=\"https://profiles.wordpress.org/gziolo\">Greg Ziółkowski</a>, <a href=\"https://profiles.wordpress.org/abcd95\">Himanshu Pathak</a>, <a href=\"https://profiles.wordpress.org/hbhalodia\">Hit Bhalodia</a>, <a href=\"https://profiles.wordpress.org/huzaifaalmesbah\">Huzaifa Al Mesbah</a>, <a href=\"https://profiles.wordpress.org/iflairwebtechnologies\">iflairwebtechnologies</a>, <a href=\"https://profiles.wordpress.org/jamesbregenzer\">James</a>, <a href=\"https://profiles.wordpress.org/jsnajdr\">Jarda Snajdr</a>, <a href=\"https://profiles.wordpress.org/audrasjb\">Jb Audras</a>, <a href=\"https://profiles.wordpress.org/joedolson\">Joe Dolson</a>, <a href=\"https://profiles.wordpress.org/joen\">Joen Asmussen</a>, <a href=\"https://profiles.wordpress.org/jonsurrell\">Jon Surrell</a>, <a href=\"https://profiles.wordpress.org/desrosj\">Jonathan Desrosiers</a>, <a href=\"https://profiles.wordpress.org/karthikeya01\">Karthikeya Bethu</a>, <a href=\"https://profiles.wordpress.org/khokansardar\">Khokan Sardar</a>, <a href=\"https://profiles.wordpress.org/rlucian\">Lucian R.</a>, <a href=\"https://profiles.wordpress.org/luismulinari\">luismulinari</a>, <a href=\"https://profiles.wordpress.org/dervishov\">Mahammad Darvishov</a>, <a href=\"https://profiles.wordpress.org/manhar\">Manhar Barot</a>, <a href=\"https://profiles.wordpress.org/mciampini\">Marco Ciampini</a>, <a href=\"https://profiles.wordpress.org/tyxla\">Marin Atanasov</a>, <a href=\"https://profiles.wordpress.org/muryam\">Maryam Sultana</a>, <a href=\"https://profiles.wordpress.org/masum52\">Masum</a>, <a href=\"https://profiles.wordpress.org/mcsf\">Miguel Fonseca</a>, <a href=\"https://profiles.wordpress.org/369work\">Miroku</a>, <a href=\"https://profiles.wordpress.org/mohamedahamed\">Mohammed Noumaan Ahamed</a>, <a href=\"https://profiles.wordpress.org/mukesh27\">Mukesh Panchal</a>, <a href=\"https://profiles.wordpress.org/mustafabharmal\">Mustafa Bharmal</a>, <a href=\"https://profiles.wordpress.org/ntsekouras\">Nik Tsekouras</a>, <a href=\"https://profiles.wordpress.org/noruzzaman\">Noruzzaman</a>, <a href=\"https://profiles.wordpress.org/ozgursar\">Ozgur Sar</a>, <a href=\"https://profiles.wordpress.org/peterwilsoncc\">Peter Wilson</a>, <a href=\"https://profiles.wordpress.org/presskopp\">Presskopp</a>, <a href=\"https://profiles.wordpress.org/ekla\">Rahul Kumar</a>, <a href=\"https://profiles.wordpress.org/ramonopoly\">ramonopoly</a>, <a href=\"https://profiles.wordpress.org/youknowriad\">Riad Benguella</a>, <a href=\"https://profiles.wordpress.org/rishabhwp\">Rishabh Gupta</a>, <a href=\"https://profiles.wordpress.org/roshniahuja14\">Roshni Ahuja</a>, <a href=\"https://profiles.wordpress.org/sainathpoojary\">Sainath Poojary</a>, <a href=\"https://profiles.wordpress.org/sakshamsharma5\">Saksham Sharma</a>, <a href=\"https://profiles.wordpress.org/andrewssanya\">SAndrew</a>, <a href=\"https://profiles.wordpress.org/coffee2code\">Scott Reilly</a>, <a href=\"https://profiles.wordpress.org/sergeybiryukov\">Sergey Biryukov</a>, <a href=\"https://profiles.wordpress.org/siliconforks\">siliconforks</a>, <a href=\"https://profiles.wordpress.org/sabernhardt\">Stephen Bernhardt</a>, <a href=\"https://profiles.wordpress.org/swanandm\">Swanand M</a>, <a href=\"https://profiles.wordpress.org/inc2734\">Takashi Kitajima</a>, <a href=\"https://profiles.wordpress.org/edent\">Terence Eden</a>, <a href=\"https://profiles.wordpress.org/threadi\">threadi</a>, <a href=\"https://profiles.wordpress.org/tusharaddweb\">Tushar Patel</a>, <a href=\"https://profiles.wordpress.org/umesh.nevase\">Umesh Nevase</a>, <a href=\"https://profiles.wordpress.org/webmandesign\">WebMan Design | Oliver Juhas</a>, <a href=\"https://profiles.wordpress.org/westonruter\">Weston Ruter</a>, <a href=\"https://profiles.wordpress.org/yogeshbhutkar\">Yogesh Bhutkar</a>, <a href=\"https://profiles.wordpress.org/yusufmudagal\">Yusuf Mudagal</a> </p>\n\n\n\n<h2 class=\"wp-block-heading\">How to contribute</h2>\n\n\n\n<p class=\"wp-block-paragraph\">To get involved in WordPress core development, head over to Trac, <a href=\"https://core.trac.wordpress.org/report/6\">choose a ticket</a>, and join the conversation in the <a href=\"https://wordpress.slack.com/archives/C02RQBWTW\">#core</a> channel. Need help? Check out the <a href=\"https://make.wordpress.org/core/handbook/\">Core Contributor Handbook</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Props to </em><a class=\"mention\" href=\"https://profiles.wordpress.org/jorbin/\"><span class=\"mentions-prefix\">@</span>jorbin</a><em> for proofreading.</em></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Jul 2026 17:33:42 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Estela Rueda\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:4;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"Open Channels FM: The Paradox of Empowerment in a Disruptive Era\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2556703\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"https://openchannels.fm/the-paradox-of-empowerment-in-a-disruptive-era/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:158:\"Tech feels wild and unpredictable, yet super empowering. Success now hinges on broad awareness and curiosity, not just deep specialization. Embrace the chaos.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Jul 2026 15:24:38 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:55:\"Jonathan Desrosiers: 13 Years Contributing to WordPress\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:39:\"https://jonathandesrosiers.com/?p=12208\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://jonathandesrosiers.com/2026/07/13-years-contributing-to-wordpress/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:13569:\"<p class=\"wp-block-paragraph\">Thirteen years ago today, I received <a href=\"https://core.trac.wordpress.org/changeset/24588\">my very first props for contributing to WordPress Core</a>. If my WordPress contribution journey were a person, it would now be a teenager. It&#8217;s pretty wild to think about, but I&#8217;ve now been contributing to the WordPress project in some way for a third of my life!</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-what-is-a-prop\">What is a &#8220;prop&#8221;?</h2>\n\n\n\n<p class=\"wp-block-paragraph\">In the WordPress open source project, community participants receive credit for contributing to a given change or deliverable by receiving “props.”</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Props should be given to all those who contributed to the final commit, whether through patches, refreshed patches, code suggested otherwise, design, writing, user testing, or other significant investments of time and effort. Usernames are parsed for the credits list and WordPress.org profiles.</p>\n\n\n\n<p class=\"is-style-text-subtitle is-style-text-subtitle--1 wp-block-paragraph\"><a href=\"https://make.wordpress.org/core/handbook/best-practices/commit-messages/#props\">WordPress Core Handbook</a></p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">The names of all the contributors who helped make a specific release possible are collected in the weeks leading up and added to the Credits API, which powers the Credits page in the WordPress dashboard.</p>\n\n\n\n<p class=\"wp-block-paragraph\">To date, I have been listed on the Credits page for 24 consecutive releases starting with 4.7, and 29 of the 35 releases overall since my first credited contribution in <a href=\"https://wordpress.org/news/2013/08/oscar/\">WordPress 3.6 “Oscar”,</a> alongside 224 other contributors.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Every year is a bit different than the last, but I can confidently say that this past year has been significantly different. What it means to develop software or contribute to open source is changing rapidly with advanced AI innovations seemingly every day combined with these tools being accessible to more people than ever before. But throughout all this, one truth holds strong: open source software is more important than ever.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-looking-back\">Looking Back</h2>\n\n\n\n<p class=\"wp-block-paragraph\">It seemed only fitting for me to instruct AI to analyze my contribution activity over the last 365 days to try and find anything interesting!</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"h-prompt\">Prompt</h3>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Today is the 13th Anniversary of my first credited contribution to the WordPress project. I try to write a blog post each year to mark the occasion.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I’m looking for ideas for this years edition. Please go and read all of my past posts (accessible here at this category feed https://jonathandesrosiers.com/category/contributing-anniversaries/feed) and give me 10-12 ideas for what to focus on this year. You can also look through the other content on my site for other ideas.</p>\n\n\n\n<p class=\"wp-block-paragraph\">After you do that, I want you to look at the git history for the <code>wordpress-develop</code> and <code>gutenberg</code> repositories between July 8, 2025 and yesterday (July 7, 2026). I want you to parse the logs to summarize my activity and find some particular ways to analyze the data that are interesting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Be creative! These posts are the most fun when I am able to find some unique insight into a year&#8217;s worth of contributions.</p>\n</blockquote>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"h-results\">Results</h3>\n\n\n\n<h4 class=\"wp-block-heading\" id=\"h-your-year-13-in-numbers-jul-8-2025-jul-7-2026\">Your year 13 in numbers (Jul 8 2025 → Jul 7 2026)</h4>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Metric</th><th>Value</th></tr></thead><tbody><tr><td>Core commits authored &amp; committed</td><td><strong>119</strong> (~7% of all 1,707 core commits this cycle)</td></tr><tr><td>Additional commits crediting you (props received)</td><td><strong>97</strong> → ~<strong>216</strong> credited touch points in core alone</td></tr><tr><td>Lines changed</td><td><strong>+41,746 / −21,940</strong> across 656 file-changes</td></tr><tr><td>Unique Trac tickets</td><td><strong>69</strong></td></tr><tr><td>Gutenberg PRs authored</td><td><strong>24</strong> (+108 co-authored/credited)</td></tr><tr><td>Reverts you committed</td><td>6</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>The headline:</strong> <strong>80 of your 119 core commits (67%) are &#8220;Build/Test Tools.&#8221;</strong> Add Tests + General and it&#8217;s ~80%. You spent year 13 as the <strong>plumber of WordPress</strong> — CI, build pipeline, dependency stewardship, release infrastructure.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-the-most-interesting-angles-the-data-surfaced\">The most interesting angles the data surfaced</h2>\n\n\n\n<ol class=\"wp-block-list\">\n<li class=\"\"><strong>The nocturnal committer.</strong> ~50 of your commits land between <strong>midnight and 4am</strong>. Tuesday (37) and Thursday (31) are your peak days; Saturday is nearly dead (3).</li>\n\n\n\n<li class=\"\"><strong>The month that didn&#8217;t exist.</strong> <strong>January 2026: zero commits.</strong> March 2026: <strong>40</strong>. Your cadence is a heartbeat synced to the 6.9 and 7.0 release cycles, not the calendar.</li>\n\n\n\n<li class=\"\"><strong>The June 30th ritual.</strong> You bumped Gutenberg&#8217;s pinned hash <strong>seven times in a single day</strong> (v22.8.0 → v23.4.0) — a whole quarter of catching-up compressed into one sitting.</li>\n\n\n\n<li class=\"\"><strong>Supply-chain quiet work.</strong> Pinning full-length action SHAs, replacing abandoned third-party actions, migrating release logic to a GitHub App, ca-bundle updates — you spent the year hardening the software supply chain nobody thanks you for.</li>\n\n\n\n<li class=\"\"><strong>Keeping the ancient libraries breathing.</strong> lodash, underscore, backbone, getID3, Twemoji — you&#8217;re the caretaker of WordPress&#8217;s legacy vendored code.</li>\n\n\n\n<li class=\"\"><strong>Future-proofing the matrix.</strong> MySQL 9.5/9.6/9.7, MariaDB 12.1, PHP 8.5 (HEIF/HEIC) — you test tomorrow&#8217;s platforms today.</li>\n\n\n\n<li class=\"\"><strong>A first, quietly historic commit:</strong> <em>&#8220;Include example for disclosing AI usage&#8221;</em> — you helped write core&#8217;s early AI-disclosure norms.</li>\n</ol>\n\n\n\n<h4 class=\"wp-block-heading\" id=\"h-10-12-ideas-for-the-year-13-post\">10–12 ideas for the year-13 post</h4>\n\n\n\n<ol class=\"wp-block-list\">\n<li class=\"\"><strong>&#8220;The Plumber&#8217;s Year: 67% of My Commits Were Infrastructure.&#8221;</strong> Own the unglamorous. A love letter to build/test/CI work — the contributions that never show up in a release announcement but without which nothing ships. This is your strongest, most authentic angle.</li>\n\n\n\n<li class=\"\"><strong>&#8220;Confessions of a Nocturnal Committer.&#8221;</strong> Fun, human, data-driven: your midnight-to-4am commit cluster, Tuesday/Thursday peaks, the dead January. Chart your year as a heartbeat and reflect on what it says about maintainer rhythms (and sustainability/burnout).</li>\n\n\n\n<li class=\"\"><strong>&#8220;216 Times.&#8221;</strong> Companion to your 2024 props post, flipped: this year you <em>received</em> credit ~216 times in core (119 committed + 97 propped). Explore the two halves of a committer&#8217;s fingerprint — the work you land yourself vs. the work you shepherd for others.</li>\n\n\n\n<li class=\"\"><strong>&#8220;The Boring Commits That Keep 40% of the Web Safe.&#8221;</strong> The supply-chain security angle: pinned SHAs, abandoned-action replacement, the GitHub App migration, ca-bundle. Frame maintenance-as-security — timely and underappreciated.</li>\n\n\n\n<li class=\"\"><strong>&#8220;I Test the Future So You Don&#8217;t Break in It.&#8221;</strong> MySQL 9.7, MariaDB 12.1, PHP 8.5 — a piece on being the person who runs tomorrow&#8217;s platforms against today&#8217;s code, and why the test matrix is a form of care.</li>\n\n\n\n<li class=\"\"><strong>&#8220;The Commit I&#8217;m Proudest Of Was One Line About AI.&#8221;</strong> Use <em>&#8220;Include example for disclosing AI usage&#8221;</em> as a springboard into how WordPress (and you) navigated AI&#8217;s arrival in the contribution workflow in 2025–26. Very of-the-moment.</li>\n\n\n\n<li class=\"\"><strong>&#8220;Anatomy of a Revert.&#8221;</strong> Six times this year you reverted your own or others&#8217; work. A candid, senior-contributor essay on why reverting is a feature not a failure — iteration, humility, and trunk stability.</li>\n\n\n\n<li class=\"\"><strong>&#8220;A Year in Dependencies.&#8221;</strong> The stewardship story — lodash/underscore/backbone/getID3/Twemoji. What it means to be the caretaker of code written a decade ago that you can&#8217;t just delete. Legacy as responsibility.</li>\n\n\n\n<li class=\"\"><strong>&#8220;Who I Built With.&#8221;</strong> Refresh your collaborator lens for year 13: westonruter (24), jorbin (22), johnbillion (15), peterwilsoncc (14), wildworks (13)… Name the people behind the props lines and tell a story or two about the work you shared.</li>\n\n\n\n<li class=\"\"><strong>&#8220;The Shape of a Release Cycle, Drawn in Commits.&#8221;</strong> Overlay your monthly commit counts on the 6.9 and 7.0 timelines — the March spike, the December bundled-themes push, the quiet stretches. Show readers what a maintainer&#8217;s year <em>looks like</em> mapped to what shipped.</li>\n\n\n\n<li class=\"\"><strong>&#8220;Same Job, New Tools: Automating Myself Out of the Loop.&#8221;</strong> Your Gutenberg PRs are almost all release automation — GitHub App auth, GHCR publishing, reproducible builds, Dependabot. A reflective piece on spending your labor building the machine that does the labor, and what that means for the next generation of contributors.</li>\n</ol>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\"></blockquote>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">I haven&#8217;t validated any of these numbers, but they do seem relatively accurate at first glance. I had ChatGPT create an embroidered patch that reflects the summary above.</p>\n\n\n\n<figure class=\"wp-block-image size-large is-resized wp-lightbox-container\"><img alt=\"\" class=\"wp-image-12221 not-transparent\" height=\"1024\" src=\"https://jonathandesrosiers.com/wp-content/uploads/2026/07/plumber-of-wordpress-1024x1024.jpg\" width=\"1024\" /><button class=\"lightbox-trigger\" type=\"button\">\n			<svg fill=\"none\" height=\"12\" viewBox=\"0 0 12 12\" width=\"12\" xmlns=\"http://www.w3.org/2000/svg\">\n				<path d=\"M2 0a2 2 0 0 0-2 2v2h1.5V2a.5.5 0 0 1 .5-.5h2V0H2Zm2 10.5H2a.5.5 0 0 1-.5-.5V8H0v2a2 2 0 0 0 2 2h2v-1.5ZM8 12v-1.5h2a.5.5 0 0 0 .5-.5V8H12v2a2 2 0 0 1-2 2H8Zm2-12a2 2 0 0 1 2 2v2h-1.5V2a.5.5 0 0 0-.5-.5H8V0h2Z\" fill=\"#fff\">\n			</svg>\n		</button></figure>\n\n\n\n<p class=\"wp-block-paragraph\">And some of those writing suggestions are pretty good ideas! I&#8217;m out of time for today, so I&#8217;ll file these in the backlog for another day. But here&#8217;s to another year of helping the world find their voice to share their stories using WordPress. <img alt=\"🍻\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f37b.png\" style=\"height: 1em;\" /></p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-past-milestones\">Past Milestones</h2>\n\n\n\n<p class=\"wp-block-paragraph\">&#8220;Props&#8221; Anniversaries: <a href=\"https://jonathandesrosiers.com/2023/07/10-years-of-contributing-to-wordpress/\">Ten</a>, <a href=\"https://jonathandesrosiers.com/2024/07/11-years-contributing-to-wordpress/\">Eleven</a>, <a href=\"https://jonathandesrosiers.com/2025/07/12-years-contributing-to-wordpress/\">Twelve</a> (<a href=\"https://jonathandesrosiers.com/category/contributing-anniversaries/\">archive</a>).</p>\n\n\n\n<p class=\"wp-block-paragraph\">Commit-iversaries: <a href=\"https://jonathandesrosiers.com/2020/11/two-years-my-wordpress-commit-iversary/\">Two</a>, <a href=\"https://jonathandesrosiers.com/2023/11/five-years-my-wordpress-commit-iversary/\">Five</a>, <a href=\"https://jonathandesrosiers.com/2024/11/six-years-a-committer-my-wordpress-commit-iversary/\">Six</a>, <a href=\"https://jonathandesrosiers.com/2025/11/seven-years-a-committer-my-wordpress-commit-iversary/\">Seven</a> (<a href=\"https://jonathandesrosiers.com/category/commit-iversaries/\">archive</a>).</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"has-text-align-right has-small-font-size wp-block-paragraph\"><em>Featured image credit: <a href=\"https://creativecommons.org/publicdomain/zero/1.0/\">CC0</a> licensed <a href=\"https://wordpress.org/photos/photo/72361fea8c/\">photo</a> by <a href=\"https://wordpress.org/photos/author/westguard/\">Mark Westguard</a> from the <a href=\"https://wordpress.org/photos/\">WordPress Photo Directory</a>.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n<p>The post <a href=\"https://jonathandesrosiers.com/2026/07/13-years-contributing-to-wordpress/\">13 Years Contributing to WordPress</a> appeared first on <a href=\"https://jonathandesrosiers.com\">Jonathan Desrosiers</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 09 Jul 2026 03:39:36 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:19:\"Jonathan Desrosiers\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:25:\"Matt: Code for the People\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153500\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://ma.tt/2026/07/people-code/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3787:\"<figure class=\"wp-block-image size-full\"><a href=\"https://codeforthepeople.com/\"><img alt=\"\" class=\"wp-image-153503\" height=\"326\" src=\"https://i0.wp.com/ma.tt/files/2026/07/cftp-matt.jpeg?resize=604%2C326&#038;quality=89&#038;ssl=1\" width=\"604\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Lights! Camera! Action!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Todd Spangler at Variety writes: <a href=\"https://variety.com/2026/digital/news/automattic-code-for-the-people-1236802508/\">Automattic’s ‘Code for the People’ Documentary Is a Rallying Cry for Users to Fight for the Open Internet</a>, from the NYC premiere last week.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;m looking forward to the <a href=\"https://luma.com/r8wbww10\">San Francisco premiere of the documentary</a>, and then tomorrow everyone <a href=\"https://codeforthepeople.com/\">can stream it for free on codeforthepeople.com</a>! Appearances by <a href=\"https://nomad.blog/\">Anne McCarthy</a>, <a href=\"https://beau.blog/\">Beau Lebens</a>, <a href=\"https://eric.blog/\">Eric Binnion</a>, <a href=\"https://iandanielstewart.com/\">Ian Stewart</a>, <a href=\"https://marjorie.blog\">Marjorie Asturias</a>, <a href=\"https://mary.blog/\">Mary Hubbard</a>, <a href=\"https://matiasventura.com/\">Matías Ventura</a>, Matthew Miller, <a href=\"https://paolo.blog/\">Paolo Belcastro</a>, and <a href=\"https://paulmaiorana.com/\">Paul Maiorana</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>We need to tell the story of Open Source in as many ways and places as possible. It&#8217;s never been more critical. </strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Film is new to us, and it&#8217;s funny how quickly things change: There&#8217;s a segment with a few &#8220;OpenAI not open&#8221; sound bites, but to their credit, they <a href=\"https://openai.com/open-models/\">have been releasing open-weight models (Safeguard is particularly interesting)</a>. That said, the <a href=\"https://artificialanalysis.ai/leaderboards/models?weights=open\">top open-weight models are all from China</a>, save for <a href=\"https://www.nvidia.com/en-us/ai-data-science/foundation-models/nemotron/\">Nvidia&#8217;s Nemotron</a>, in ~12th place. </p>\n\n\n\n<p class=\"wp-block-paragraph\">When I went to the first WordCamps <a href=\"https://ma.tt/2008/09/first-day-in-beijing/\">in Beijing</a> and <a href=\"https://ma.tt/2008/09/shanghai-wordcamp/\">Shanghai</a> in 2009, it was a very different time. They were the biggest in the world at the time! I don&#8217;t think you could <a href=\"https://ma.tt/2008/09/first-day-in-beijing/#jp-carousel-7712\">take photos in Tiananmen Square as freely as I did then</a>; now to visit I think you need an appointment, ID checks, and security checks. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Even during WordCamp, it felt like the freedom of Open Source was in high demand, but it also created a lot of fear. I found out later that one of the student volunteers who helped their professor organize everything had been taken in for hours of questioning following the event.</p>\n\n\n\n<p class=\"wp-block-paragraph\">On that trip, I saw how fine-grained the Great Firewall could be when individual posts (IIRC, about bad milk from a factory harming babies) wouldn&#8217;t load, but the rest of the site would.  WordPress.com had been totally blocked, <a href=\"https://web.archive.org/web/20090601162213/http://www.google.com/hostednews/afp/article/ALeqM5igVn4hcj6ZNWlawSvzLvgEMkZmkQ\">taking about a quarter of our traffic at the time</a>, but behind the Firewall, Open Source continued to thrive and grow, and now the frontier open models are being driven by China in a way I never would have predicted!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Once you&#8217;ve had a taste of freedom, it&#8217;s hard to go back.</strong></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 08 Jul 2026 23:16:07 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:123:\"WPTavern: #224 – David Snead on Building Trust and Collaboration in the Hosting Industry With the Secure Hosting Alliance\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=206201\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:137:\"https://wptavern.com/podcast/224-david-snead-on-building-trust-and-collaboration-in-the-hosting-industry-with-the-secure-hosting-alliance\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:37674:\"<details>Transcript<div>\n<p class=\"wp-block-paragraph\">[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Jukebox is a podcast which is dedicated to all things WordPress. The people, the events, the plugins, the blocks, the themes, and in this case, building trust and collaboration in the hosting industry with the Secure Hosting Alliance.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you, and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox, and use the form there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So on the podcast today, we have David Snead. David has been involved in the hosting industry since 1999, starting out as legal counsel for one of the earliest shared hosting companies, and going on to work with over 50 others. He helped found the i2Coalition, serve as in-house counsel for cPanel and WebPros, and now leads the Secure Hosting Alliance.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re listening to this podcast, I&#8217;m sure that many of you will have worked closely with hosting companies. Perhaps you run an agency, or business, that depends on the reliability, ethics, and security of hosting providers. David is here to talk about cross-industry collaboration in the hosting world, specifically around improving security, professionalism, and communication between hosts.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The conversation focused on why, and how, the Internet Infrastructure Forum, or IIF, is building a framework for real-time intelligence sharing and abuse reporting, aiming to help the entire ecosystem detect and prevent attacks faster than adversaries can adapt.</p>\n\n\n\n<p class=\"wp-block-paragraph\">David talks about the challenges hosting companies face, especially smaller ones, in keeping up with security, and how this evolving project hopes to ease this by sharing actionable, non-proprietary abuse information across registrars, hosting providers, DNS services, and more.</p>\n\n\n\n<p class=\"wp-block-paragraph\">He discusses the growth of both the Secure Hosting Alliance and the IIF, the business case for collaboration, and the nuances of legal and technical information sharing across borders.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re in hosting, run a web agency, or just want to know how the backbone of the web is working to stay more secure and connected, this episode is for you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so, without further delay, I bring you David Snead.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I am joined on the podcast by David Snead. Hello David.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:20] <strong>David Snead:</strong> Hello.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:21] <strong>Nathan Wrigley:</strong> Very nice to have you with us. David&#8217;s got a really interesting background, and a really interesting, I&#8217;m going to use the word project. I don&#8217;t know if that&#8217;s the right word. It feels like it&#8217;s got more solidity and it&#8217;s got a lot more history than that. It&#8217;s something which is, I think going, but we&#8217;ll find out a little bit more about it. It&#8217;s all about the hosting industry and trying to get hosts to, I guess communicate with each other in ways going forwards.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:44] <strong>David Snead:</strong> That is a part of it. There are really two goals and one is to level up the ethics and professionalism in the hosting industry. And the second is to facilitate more comradery and interaction among hosts. Something that folks felt occurred in the early 2000s, and with all the consolidation that occurred went away. And so that&#8217;s something that we&#8217;re also trying to facilitate.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:04:16] <strong>Nathan Wrigley:</strong> Okay. So given that we&#8217;re going to be talking about hosting, I guess it&#8217;s a good idea to paint your credentials and find out a little bit more about you. So a short opportunity to just tell us a little about you and your background in WordPress and hosting specifically, I suppose.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:04:29] <strong>David Snead:</strong> Sure. So I have been working in the hosting industry since 1999. As I often say, I was working in the hosting industry when hosting was cool. It is not so cool anymore. In fact most people don&#8217;t really pay attention to it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You know, and I started as a lawyer for a hosting company, and I was in-house counsel for a company that actually owned a hosting company and was one of the earliest hosting companies that specialised in shared hosting. And so I was their general counsel. And for some reason it stuck, and I&#8217;ve just kind of turned it into a career.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So after that I had a private practise as a lawyer and I worked with probably 50 different hosting companies, mostly writing policies that nobody ever reads, which makes me super fun at parties.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And then from there, my friend Christian Dawson and I formed the i2Coalition as a response to some legislation in the US that would&#8217;ve been kind of the death nail for internet providers. So we started the i2Coalition. I then went in-house for cPanel and worked at cPanel and WebPros for 10 years, and then started the Secure Hosting Alliance.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:05:52] <strong>Nathan Wrigley:</strong> Okay. So you&#8217;ve got all all the history. That&#8217;s pretty good. You know, if we&#8217;re going to talk about hosting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:05:57] <strong>David Snead:</strong> All the hosting history in one person. That&#8217;s kind of a very scary idea, no?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:02] <strong>Nathan Wrigley:</strong> But that&#8217;s excellent. So do you still offer counsel? Is that still, so you haven&#8217;t sort of sidestepped and do half of the week on a sort of more technical basis? It&#8217;s still the legal side that you&#8217;re involved in.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:13] <strong>David Snead:</strong> I do. Right now I&#8217;m doing mostly M&amp;A work for, it&#8217;s weird. So I don&#8217;t know if anybody has ever said this to you before, but web hosting is kind of like the Hotel California. It&#8217;s like, once you start in the web hosting industry, you never leave. And so I have all these clients from 15 years ago who are now running like little baby hosts, and they&#8217;re talking to bigger hosts and they want to get acquired. So I&#8217;m doing some of that now. I am not writing any of the policies that nobody ever reads because that was just, I did that for too long.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:51] <strong>Nathan Wrigley:</strong> There were too many moments parties.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:53] <strong>David Snead:</strong> Yes, exactly. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:55] <strong>Nathan Wrigley:</strong> Okay, so I&#8217;m going to read into the record the title and the blurb that went with the presentation that you are doing or done.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:07:02] <strong>David Snead:</strong> I did it yesterday.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:07:03] <strong>Nathan Wrigley:</strong> Okay, we&#8217;ll get into that in a moment. So the title is coordinating the fight, cross industry collaboration, and the blurb goes as follows. WordPress hosting threats cross company lines. When one provider falls victim, the entire ecosystem suffers. This session explores how the Internet Infrastructure Forum, or IFF, enables hosting providers, registrars and registries to coordinate abuse response through real time intelligence sharing. Learn how operational collaboration helps responsible operators detect and stop attacks faster than adversaries can adapt. And why working together produces results no single provider could achieve alone.</p>\n\n\n\n<p class=\"wp-block-paragraph\">When I read that, immediately was, yeah, that&#8217;s a really sensible idea. Why are we separately, as hosting companies, I say we, I mean the hosting companies. Why are they all trying to do the same work over and over again, separately? When presumably this aspect of the work, the security bit is something they all have in common.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:08:05] <strong>David Snead:</strong> Right? So that&#8217;s the fundamental question, right? So the IIF is a voluntary organisation that is made up of everyone in the infrastructure stack. So from registrars, registries, DNS providers, hosting providers, cloud providers, everyone in the stack. So it is facilitated by the Internet and Jurisdiction Foundation. They&#8217;re based in Paris, and they&#8217;re the actually the secretariat for it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And what it&#8217;s designed to do is create a common way for everyone who&#8217;s in the infrastructure stack to share information about abuse and abuse issues. And it&#8217;s one of the fundamental problems that you referred to is everybody is operating in a silo, right? And that&#8217;s mostly because that&#8217;s the way the internet is architected, right?</p>\n\n\n\n<p class=\"wp-block-paragraph\">So the internet is architected, so it&#8217;s distributed, right? Registrars and registries basically do their own thing with domain names. They might have a small hosting component or maybe a cloud component, but by and large, all they do is domain names.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Hosting providers probably resell domain names, but they&#8217;re not part of that industry. And so how do they all coordinate? And that&#8217;s what the IIF is trying to facilitate, is more information sharing among the participants.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:09:39] <strong>Nathan Wrigley:</strong> Well I imagine some of the hosting companies are probably fairly good. You know, they&#8217;ve got a giant customer base. Let&#8217;s imagine hosting company X over there, they&#8217;ve got millions of customers. They&#8217;ve got a huge budget that they can put over to, let&#8217;s say, security things. Well that&#8217;s all well and good, brilliant. But then there are other companies who are much scrappier. You know, they maybe have only a few thousand customers. And so their budget for the exact same work is going to be reduced.</p>\n\n\n\n<p class=\"wp-block-paragraph\">How will this work? Is it going to be like a subscription service basically? Will you have a membership, which is in some way equal to the number of clients that you&#8217;ve got? Will there be some expectation that, okay, we&#8217;ll look at your revenue, your membership will be equivalent to a percentage of your revenue? How will that all work?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:10:20] <strong>David Snead:</strong> We don&#8217;t know. This is a very early stage project. Right now we are in a prototype phase where we have just figured out what information folks should submit to the secretariat.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So the way it works is, you submit the information that you collect for a particular abuse issue to the secretariat, who then enriches it with all the other information that&#8217;s been submitted and sends it to the right person.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So a great example is, let&#8217;s say a registrar reported a phishing domain. They turn off the phishing domain and they have maybe a timestamp, an IP address where it was submitted from. They submit that to the secretariat, who then finds the hosting company who is providing the services for the hosting and says, this came in about this particular site. Can you take action on that? So that&#8217;s the way it works.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Right now it&#8217;s very early stage. It&#8217;s in the first phase of a test, and we&#8217;re going to look at whether the way we&#8217;ve architected it, or the way the group has architected it, actually makes sense.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:11:39] <strong>Nathan Wrigley:</strong> Is this going to be then a sort of slow on ramp whereby you bring a few companies in at the beginning, hopefully. And then one or two more and iron out the wrinkles, and then some more and some more? Because I imagine, if you just threw the switch, everybody&#8217;s in, a lot could go wrong at that point. And I&#8217;m guessing there&#8217;s going to be more of a slow on ramp.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:12:00] <strong>David Snead:</strong> So you&#8217;ve pointed out my particular frustration with the IIF, and the reason that the secretariat is moving slowly, right? So fortunately, or unfortunately, based on my cultural background, I&#8217;m just sitting here going, this needs to move faster. We need to have everybody involved, we need to have all the hosts involved, we need to have all the registrars and registries. And other folks who are a little bit more skilled in this type of work say, no, we need to figure out what we&#8217;re doing and that requires a small number of people.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The phase that we&#8217;re in right now is looking for more folks who are interested in sitting at the table and being part of the discussion. Particularly in the hosting industry and in the web design and marketing industry. Those are folks who don&#8217;t generally participate in these kind of industry led collaboration exercises. And that&#8217;s the reason that I&#8217;m at WordCamp, is to talk to web designers, marketing agencies about why they should participate in something like this.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:13] <strong>Nathan Wrigley:</strong> So this really isn&#8217;t bound in any way to WordPress, is it? It just so happens that WordPress has a significant chunk of the internet, so this is a good place to start. But if you happen to be a, I don&#8217;t know, Drupal user, or you&#8217;re just into writing PHP code or whatever it may be, this is still applicable. There&#8217;s no real WordPress layer to this. This is just a good place for you to come because, well, there&#8217;s probably, what, 30 hosts, 100 yards away from us out there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:37] <strong>David Snead:</strong> I know. And I haven&#8217;t seen all of them yet.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:39] <strong>Nathan Wrigley:</strong> Yeah, there&#8217;s work to do. But agnostic to any platform, basically.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:42] <strong>David Snead:</strong> It is completely platform agnostic, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:43] <strong>Nathan Wrigley:</strong> Okay. Okay, that&#8217;s interesting. But WordPress is a, is certainly a good place to start.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Now, I&#8217;m imagining, if I was a hosting company and I was the chief executive, I definitely have some questions for you in terms of, okay, we&#8217;re going to share our valuable intel with you, what are you going to do with that? How can we trust you? How do we know that the sharing is going to be done effectively and what have you?</p>\n\n\n\n<p class=\"wp-block-paragraph\">So I guess really what I&#8217;m getting to is, what is the assurances or checks and balances that you, in the end, will hope to offer the host? That you can assure them that, look, if you hand us this body of work, you don&#8217;t need to think about it again. You can trust us to do it honourably, effectively, collaboratively. You get where going.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:14:26] <strong>David Snead:</strong> Yeah, yeah. And I suspect that you wanted to be a lawyer at some time, because that&#8217;s one of the issues that we&#8217;re facing. Information that can be shared freely, as an example, in the United States, might not be capable of being shared so freely in the European Union, or in Brazil, or in India or someplace like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So one of the things that&#8217;s being done, not by me, but by another group, another working group that&#8217;s part of this, is analysing the legal issues around information sharing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The information that&#8217;s being shared, to answer the proprietary and confidentiality question, is not proprietary or confidential information. So it&#8217;s things like timestamps, domain names, IP addresses for the initial abuse submission. Things like that that really don&#8217;t indicate some sort of company confidential information. And it&#8217;s further abstracted into xarf, which is a language that&#8217;s used for abuse reporting, that we all can share. And so I think that the only thing that would be of concern is whether that information is personal information that&#8217;s subject to jurisdictional restrictions around the world.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:15:48] <strong>Nathan Wrigley:</strong> Would the idea be that this organisation would do the remedial work? So is there any notion that, let&#8217;s say for example, some sort of security problem was discovered by hosting company A over there, and they share that intel with you. Maybe the question is kind of asking, will you then appoint people to figure out what the patch is for that? Or is your idea just to, oh, red flag, we&#8217;ve got this problem, now you all know about it. Is it just information sharing as opposed to fixes?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:16:17] <strong>David Snead:</strong> Yeah, it&#8217;s the latter. So the thing that we&#8217;re solving for right now, so there&#8217;s just one issue that, one abuse issue, that we&#8217;re testing out and it&#8217;s issues related to fake shops. And so the fake shop issue is the test abuse issue for the project, and where folks are sharing information. It&#8217;s a particular problem right now with credentials harvesting. And so that&#8217;s what we&#8217;re trying to look at.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:16:43] <strong>Nathan Wrigley:</strong> And how has the conversations that you&#8217;ve had thus far, how have they gone? Has this been warmly received or are you facing a little bit of pushback?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:16:50] <strong>David Snead:</strong> So, look, I&#8217;ll be very direct with you. If something isn&#8217;t just an immediate threat to them, it&#8217;s very difficult to conceptualise why you should participate. And I am pretty used to answering that question simply based on the political work that I do with the i2Coalition. But once you talk about, so let&#8217;s use fake shops as an example. Fake shops, and you&#8217;re providing services to fake shops, actually has an impact on your bottom line.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So if you are providing, let&#8217;s say, payment processing to an entity that is running a fake shop, it very easily can make your credit card processing charges higher. It ends up eating bandwidth. It will tax your abuse resources.</p>\n\n\n\n<p class=\"wp-block-paragraph\">One of the things that you referred to initially is, you know, larger hosts have a lot of money. I wouldn&#8217;t say they have a lot of money, but they have more bandwidth to handle a vast fire hose of abuse issues. Most smaller hosting companies might only get five or six abuse issues in a month. But if you have a fake shop, that&#8217;s going to generate a huge amount of abuse, and it&#8217;s taking away resources that you can use to actually grow your business. So that argument actually is relatively persuasive in getting folks to pay attention.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I find that the business argument around abuse is a much more compelling discussion than kind of moral persuasion. I don&#8217;t think moral persuasion works in the context of a community that is trying very hard just to keep their heads above water.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:18:42] <strong>Nathan Wrigley:</strong> It feels to me from what you&#8217;ve just said, and I could be reading too much between the lines, but it feels to me as if a good target audience would be smaller hosts to begin with, simply because they&#8217;re probably going to be more receptive because they have less bandwidth themselves. And so would welcome anything that can make the burden of sharing this information easier. So 10 of the small hosts combined is, well, it&#8217;s much bigger than each of them individually would be, whereas I suppose you&#8217;ll have to get a critical mass of them on board until maybe some of the bigger hosts start to look at you with favourable eyes, let&#8217;s say that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:19:15] <strong>David Snead:</strong> Well, so we have some pretty large hosting companies who are participating. So as an example, both GoDaddy and Newfold are participating. But we also have smaller hosts. But I agree with you, the information that&#8217;s being provided, particularly since it is actionable, realistic information that can be adapted for bespoke systems, is invaluable, right?</p>\n\n\n\n<p class=\"wp-block-paragraph\">So if you only get five or six abuse complaints and you get an abuse complaint, and you can go to the secretariat and say, we got a complaint about this domain, and the secretariat says, here&#8217;s what the registrar did. Here&#8217;s what Cloudflare did. Here&#8217;s the information they provided us. And you can use that to make a decision on how to address that problem. It saved you hours and hours and hours of research time.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:09] <strong>Nathan Wrigley:</strong> Technically speaking, what would the conduit of information both toward you and away from you look like? So if I&#8217;m hosting company X, how are you imagining that I will supply you with that information? But also, if I&#8217;m just looking for information from you on a daily, weekly basis, whatever it may be, how do I receive that? Is this like a, I don&#8217;t know, a website or an API or?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:33] <strong>David Snead:</strong> It&#8217;s an API. So it&#8217;s a file. It&#8217;s just a general file download.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:37] <strong>Nathan Wrigley:</strong> Right, okay. So it&#8217;s readily available 24/7?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:40] <strong>David Snead:</strong> Right. That&#8217;s the goal. Right now it&#8217;s not, but the goal is to kind of figure out a way to make something like that possible.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:47] <strong>Nathan Wrigley:</strong> Yeah, okay. I also suppose that the hosting companies, whilst this is good for their business if they can minimise costs and hand a lot of this work over to you, there&#8217;s a part of them which would also probably like to put some sort of badge on their website to say, this is what we&#8217;re doing. We&#8217;re part of this alliance, for want of a better word. Is that something that you are looking to develop as well, you know, some sort of credentialing system to demonstrate that you&#8217;re in this?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:21:12] <strong>David Snead:</strong> So that&#8217;s not something that the IIF is working on. It&#8217;s something that the Secure Hosting Alliance does. The Secure Hosting Alliance has a trust seal that we give to hosts who fulfil our Trust Seal Certification provisions. But that&#8217;s not something that the IIF does.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Talking about like why, other than business reasons, folks should participate in this, one of the things that is going on that I would suggest that most hosts know about, is there&#8217;s a little bit of a moral panic going on in the world about what contents you have. And regulation is actually a very real thing for the hosting industry, who has not ever been regulated. This is the time where you can say, hey, this is what we&#8217;re doing, right? We&#8217;re dealing with issues. This way a trust seal is the same thing, right? It&#8217;s something that you can say, we are actually taking steps to make the internet a better place.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:18] <strong>Nathan Wrigley:</strong> I think if you are a general agency owner or, I don&#8217;t know, just a freelancer, hosting is one of those things that you, once you&#8217;ve done it once, you&#8217;re in it for the long haul until something goes wrong. But you&#8217;re also browsing around for any tiny indication of why is this host slightly different? You know, what is it that they&#8217;re doing that, I don&#8217;t know, is faster? What is it that they&#8217;re doing that&#8217;s more secure? So it feels to me if you had a credentialing system and I began to hear about it and see it pop up again and again, it would be one of the metrics which I would weigh up when looking at hosting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:51] <strong>David Snead:</strong> I would think so. One of the things that a trust seal does is it indicates that there&#8217;s been some vetting of the host. That someone has determined the things that are important to the hosting industry and are important to the web design industry. The agency industry are also important to the host.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Great example of that is one of the provisions of the Secure Hosting Alliances&#8217; Trust Seal Certification is that a contract is presented to the customer before they sign up, which is super customer friendly.</p>\n\n\n\n<p class=\"wp-block-paragraph\">One of the things as a lawyer that you hear about all the time when people are dissatisfied with their services is, yeah, well, I never saw that contract. Or it was just a hyperlink in an email that I got. That&#8217;s one of the differentiators for a Trust Seal certified host is that the contract is actually presented to them, to the customer beforehand.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:23:57] <strong>Nathan Wrigley:</strong> So in terms of the WordPress crowd, is this a thing that you are pitching only to hosts? Like when you step out of here, are you trying to have conversations only with hosts? Or is there some bit of the WordPress community, the freelance, the agency owners? Are you trying to communicate with them just to scope out what they need?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:15] <strong>David Snead:</strong> So for both the Secure Hosting Alliance and for the IIF, it is that. I really enjoy talking to agencies and developers about whether this is important to them, or why it might be important to them.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:31] <strong>Nathan Wrigley:</strong> In terms of how long this project&#8217;s been going, I&#8217;ve only heard of it because of your participation here, but I don&#8217;t know if you&#8217;ve been banging this gong for a decade or, I mean you&#8217;ve been in the industry for long enough to have been banging it for decades. Is this a new initiative or is this something which has a long and storied history?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:49] <strong>David Snead:</strong> So the Secure Hosting Alliance has only been active for a year, a little bit over a year. I&#8217;ve been talking about abuse for a long time, but the Secure Hosting Alliance has only been around for a year.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:01] <strong>Nathan Wrigley:</strong> And have you, in that year, got any intuitions that you&#8217;ll be here for another year? Is it basically going in the right direction?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:09] <strong>David Snead:</strong> It is going in the right direction. So we started out with two or three charter members. We now have 25 hosting members. We have three security vendors who are members as well. We have, I think, 17 Trust Seal Certified members, and we&#8217;re launching in 2027 a trust seal for security vendors who provide services to hosting companies.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:40] <strong>Nathan Wrigley:</strong> I know that several owners of hosting companies listen to this podcast. They may very well be the people that you&#8217;ve spoken to already, but if they are not, and they are people who would like to investigate this further, I suppose the thing that&#8217;s going to be in their head is, okay, Nathan and David, you&#8217;ve explained what I&#8217;ll get out of it, what do I need to put into it? So is this an annual financial commitment? How does it all work from that point of view?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:02] <strong>David Snead:</strong> Yeah, so you become a member of the i2Coalition. And so the Secure Hosting Alliance is a working group of the i2Coalition. So you would be a general member and you would participate in the Secure Hosting Alliances&#8217; working groups. You also have the ability to participate in the i2Coalition as a whole, which is a much larger trade association that represents almost everyone in the internet infrastructure vertical. Mostly doing policy work, primarily in the US and the EU. Although there&#8217;s, we&#8217;re doing some work in India right now as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:40] <strong>Nathan Wrigley:</strong> And does membership allow you to steer the future of the project? I know that lots of chefs in the kitchen results in terrible food, but that, I fear, is something that could happen. You&#8217;ve got 87 members, 260 members. And then the 260 members all start to bicker and, you know, we want this, no. You see how it goes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:59] <strong>David Snead:</strong> I do.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:59] <strong>Nathan Wrigley:</strong> What&#8217;s the position there? You know, is there sort of gated levels of membership? How are you organising all of that?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:27:04] <strong>David Snead:</strong> There are not. The membership is based on self-reported revenue. The membership is not horrifically expensive from my perspective. And I think that that, most of our members would say that it is, it&#8217;s actually relatively affordable, particularly for the small to medium sized hosts. And registrars or design agencies, anyone who&#8217;s participating.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The question about, who&#8217;s running the show, comes up quite a bit. We haven&#8217;t really faced that issue, particularly in the Secure Hosting Alliance. Folks seem to get along. But the organisation runs on the idea of rough consensus. And so decisions end up not being controlled by one member or not. Some of the i2Coalition has some very large companies who everybody knows about, who get along with startups, and folks against whom they compete directly. And policies still get made. The organisation still moves forward.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:11] <strong>Nathan Wrigley:</strong> Yeah, I guess you&#8217;re in a space where, obviously all of these hosting companies commercially are vying for everybody else&#8217;s business. But in this particular situation, that is not the case. Nobody&#8217;s vying for their websites to be less secure. They all want the same level of security. So at least in that sense, you would hope that consensus could be maintained even if, commercially, the two companies that are in the room, the 10 companies that are in the room might be commercially at loggerheads with each other. At least on this they could agree. That would be the hope, I suppose, anyway.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:47] <strong>David Snead:</strong> It seems to be, not only the hope, but the actual way that things work. You ask about how compromise is reached. What comes to mind is I have a much different concept of privacy than, particularly when I was at WebPros, than other folks in the i2Coalition had. And another company just called me up and we worked through our disagreements about how privacy should be handled within the i2Coalition and were able to move forward.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The industry I&#8217;ve found to be hugely collaborative, particularly the hosting industry. Everybody knows what their competitor is doing. But when it comes to addressing an issue like, how are we going to deal with abuse as a community? Folks come together. CEOs of hosting companies while they compete tend to be relatively good friends.</p>\n\n\n\n<p class=\"wp-block-paragraph\">As I said at the very beginning, it really is like the Hotel California, right? You come in as a CEO of a hosting company, you grow it and you sell it to another company. All of a sudden you&#8217;re at the bottom again with a server in your grandma&#8217;s basement, you know, trying to start again.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:30:08] <strong>Nathan Wrigley:</strong> It&#8217;s a really curious effort. I suppose really at the bottom of this entire podcast is your endeavour to be heard and to reach out and get some conversations going. So with that in mind, where do people find the information about this? So maybe there&#8217;s a website that we could mention. But also, is there a specific place where you hang out? Is there a place where you would like to be contacted most?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:30:33] <strong>David Snead:</strong> Sure. So our website is hostingsecurity.net. I&#8217;m not too afraid of getting too much spam. So folks can email me at snead@i2coalition.com And the two is the numeral two. So it&#8217;s snead@i2coalition.com. And I&#8217;m happy to answer questions.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In terms of hanging out, I am at most industry conferences in the hosting industry. In the WordPress industry, I&#8217;ll be at WordCamp US. We also participate very heavily in ICANN. So there is an i2Coalition member at every single ICANN meeting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:31:12] <strong>Nathan Wrigley:</strong> So if you go to wptavern.com and you search for the episode with David Snead, S-N-E-A-D, you&#8217;ll be able to find those details. I&#8217;ll put everything into the show notes. So anything that I missed? Was there a particular focus that we didn&#8217;t touch?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:31:26] <strong>David Snead:</strong> No, this is actually one of the most thorough podcasts I&#8217;ve been on recently.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:31:31] <strong>Nathan Wrigley:</strong> That&#8217;s love to hear it. Well, David Snead, thank you very much for joining me today.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:31:35] <strong>David Snead:</strong> Glad to be here. Thanks for having me.</p>\n</div></details>\n\n\n\n<p class=\"wp-block-paragraph\">On the podcast today we have David Snead.</p>\n\n\n\n<p class=\"wp-block-paragraph\">David has been involved in the hosting industry since 1999, starting out as legal counsel for one of the earliest shared hosting companies and going on to work with over 50 others. He helped found the i2Coalition, serve as in-house counsel for cPanel and WebPros, and now leads the Secure Hosting Alliance.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you’re listening to this podcast, I’m sure that many of you will have worked closely with hosting companies. Perhaps you run an agency or business that depends on the reliability, ethics, and security of hosting providers. David is here to talk about cross-industry collaboration in the hosting world, specifically around improving security, professionalism, and communication between hosts.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The conversation focused on why and how the Internet Infrastructure Forum (IIF) is building a framework for real-time intelligence sharing and abuse reporting, aiming to help the entire ecosystem detect and prevent attacks faster than adversaries can adapt.</p>\n\n\n\n<p class=\"wp-block-paragraph\">David talks about the challenges hosting companies face, especially smaller ones, in keeping up with security, and how this evolving project hopes to ease this by sharing actionable, non-proprietary abuse information across registrars, hosting providers, DNS services, and more. He discusses the growth of both the Secure Hosting Alliance and the IIF, the business case for collaboration, and the nuances of legal and technical information sharing across borders.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you’re in hosting, run a web agency, or just want to know how the backbone of the web is working to stay more secure and connected, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://i2coalition.com\">i2coalition website</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://hostingsecurity.net\">Secure Hosting Alliance website</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 08 Jul 2026 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:118:\"HeroPress: “Listen… the birds are already singing” – “Послухай… пташки заспівали”\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://heropress.com/?post_type=heropress-essays&p=8704\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:146:\"https://heropress.com/essays/listen-the-birds-are-already-singing/#utm_source=rss&utm_medium=rss&utm_campaign=listen-the-birds-are-already-singing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:37329:\"<img alt=\"Pull Quote: WordCamp Europe has become one of the few places where [Ukranians] can reassemble in person. WordCamp Europe став одним із небагатьох місць, де [українці] можуть знову зібратися разом наживо.\" class=\"attachment-large size-large wp-post-image\" height=\"512\" src=\"https://heropress.com/wp-content/uploads/3026/07/volodymyr_banner.webp\" width=\"1024\" /><p class=\"wp-block-paragraph\"><a href=\"https://heropress.com/feed/#ukranian\">Це есе також доступно українською</a>.</p>\n\n\n\n<figure class=\"wp-block-audio\"><audio controls=\"controls\" src=\"https://heropress.com/wp-content/uploads/3026/07/volodomyr_english_recording.mp3\"></audio><figcaption class=\"wp-element-caption\">Listen to Volodymyr read his own story aloud.</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">&#8220;Listen&#8230; the birds are already singing,&#8221; said Danylo — a Ukrainian I&#8217;d met at a previous WordCamp — as we were wrapping up the last hour of the WCEU afterparty in Krakow. &#8220;It&#8217;s time for us to go.&#8221; He started singing &#8220;Hei! Hei! Hei, sokoly! Omynaite hory, lisy, doly.&#8221; I started singing with him. The Polish guys next to us continued singing in Polish &#8220;Dzwoń, dzwoń, dzwoń dzwoneczku, Mój stepowy skowroneczku.&#8221; Some people behind us joined the choir. That was &#8220;Hey Sokoly&#8221; — a Ukrainian-Polish folk song — carrying us out of Bastion III, a 19th-century Austrian fortress on the edge of Krakow&#8217;s Old Town, as the night turned to morning.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But to explain how I ended up there, I need to go back to where it all began.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://heropress.com/wp-content/uploads/3026/07/krakow_castle2.webp\"><img alt=\"Krakow Castle in morning light\" class=\"wp-image-8713\" height=\"1606\" src=\"https://heropress.com/wp-content/uploads/3026/07/krakow_castle2.webp\" width=\"1402\" /></a><figcaption class=\"wp-element-caption\">The view of the Krakow castle, taken on the morning after the after-party, around the time when birds were singing. Photo by Volodymyr Melnychenko.</figcaption></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-mykolaiv\">Mykolaiv</h2>\n\n\n\n<p class=\"wp-block-paragraph\">It all started in Mykolaiv, the city of shipbuilders and brides, where I spent my childhood. I graduated from two universities I had been attending simultaneously and started looking for a job during a gap year. I planned to find work to earn some money for further education while preparing for the entrance exams to one of the Finnish universities. Mykolaiv didn&#8217;t provide good opportunities for graduates unless you had very good connections, but I managed to find a job at an &#8220;IT&#8221; company. In 2011, the term &#8220;IT&#8221; didn&#8217;t mean much to me, but they required English, which was my major, so I thought — why not. The work wasn&#8217;t particularly difficult: I had to pretend to be &#8220;Bob&#8221; from the United States, helping customers who had purchased physical products by tracking their orders and walking them through setup instructions. I was fired after a month and a half. Maybe I underperformed, or maybe somebody just didn&#8217;t like me — either way, it&#8217;s water under the bridge.<br /><br />The first job I&#8217;d gotten entirely on my own, the first paycheck that proved I could be independent, and the first time being fired — all of it hit me at once. The last part was devastating, made worse by comments like &#8220;it was too good to be true,&#8221; &#8220;we told you they&#8217;d trick you,&#8221; and &#8220;look at so-and-so, doing such-and-such and earning properly.&#8221; It was hard to sit with feeling like a failure. But somewhere in that difficulty, I got tougher — and more determined to prove everyone wrong.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-templatemonster\">TemplateMonster</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The first job was a failure, but it gave me one clear answer: I needed to stay in IT. The next job was TemplateMonster.com — well known in certain circles. It was the complete opposite of what I&#8217;d experienced before. In 2012 they were selling templates for the most popular CMS platforms of the time: WordPress, Joomla, Drupal, and various e-commerce solutions. The onboarding alone took two months, which tells you something about how seriously they took their people — staff rarely left, and when they did, it was for personal reasons, not because they were pushed out.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><br />My job was to help customers with their templates: installation, editing, customization. Difficult, but genuinely interesting — I liked it. This was the first time I encountered WordPress. I worked six nights a week, and Sundays were the strangest — your day off, but your body had adjusted to night shifts and refused to cooperate. None of that bothered me much. Being able to build sites and make things look exactly right was addictive. I overworked, learned constantly, pestered developers with questions, all just to quench my thirst for knowledge. It ended quickly: I got accepted into three master&#8217;s programs in Finland, chose one, and left for Central Finland.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-helsinki\">Helsinki</h2>\n\n\n\n<figure class=\"wp-block-image alignright size-large is-resized\"><a href=\"https://heropress.com/wp-content/uploads/3026/07/image3.webp\"><img alt=\"Closeup of a glass of orange juice with croissants next to it, and a projection screen in the background.\" class=\"wp-image-8715\" height=\"1024\" src=\"https://heropress.com/wp-content/uploads/3026/07/image3-1024x1024.webp\" style=\"width: 400px;\" width=\"1024\" /></a><figcaption class=\"wp-element-caption\">Morning “Weekly” at booncon PIXELS, my first workplace in Helsinki. Photo by Volodymyr Melnychenko.</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Studying in Finland was genuinely different from anything I&#8217;d known in Ukraine — in the best possible way. Once the mandatory courses were done, I started looking for work. It was harder than I expected: a year of passive searching, then six months of applying every day. Eventually, I landed at a Helsinki-based agency building WordPress websites — which is still what I do today. A friendly team, around ten people — I&#8217;m still close with many of them. We built sites of varying complexity during the day and spent evenings playing board games, swapping stories, and throwing the occasional party.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That&#8217;s also where I attended my first WordPress event: WordCamp Helsinki 2017, a two-day conference. It didn&#8217;t blow me away, but it opened something. When you work in a small agency, you live inside your own bubble — and then suddenly a whole other world appears. You see the other side of WordPress: the community, the people pushing it forward, the people wrestling with the same problems you are and finding creative ways through.<br /><br />That first local WordCamp was enough to make us want to go further. In 2019 the team went to Berlin for WCEU — my first trip abroad outside of the Finland-Ukraine route I knew well. We spent a few days exploring the city and attending the event. WordCamp Europe is a different scale entirely: thousands of attendees, hundreds of volunteers making it happen. Standing in that crowd, I knew I wanted to be part of it — not just as a visitor. And then corona happened.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-porto\">Porto</h2>\n\n\n\n<figure class=\"wp-block-image alignright size-large is-resized\"><a href=\"https://heropress.com/wp-content/uploads/3026/07/image1.webp\"><img alt=\"Volodymyr leaning on a handrail with Krakow in the background.\" class=\"wp-image-8718\" height=\"1024\" src=\"https://heropress.com/wp-content/uploads/3026/07/image1-768x1024.webp\" style=\"width: 400px;\" width=\"768\" /></a><figcaption class=\"wp-element-caption\">Me, standing on the roof the Super Bock Arena, where the WCEU 2022 took place. Photo by Oleksandr Misyats.</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">WCEU 2020 and 2021 were online, and I felt they were missing the whole point — thousands of people in one place, feeding off each other&#8217;s energy. So when Porto was announced for 2022, I started packing. This time, I joined as a volunteer, to see WordCamp from the inside. It was the right call. It was also a difficult time for Ukrainians — the full-scale invasion was by then well into its second year, and everyone was finding their own way to cope. For me, this event became a source of strength. I connected with the Ukrainian community, had real conversations with speakers, and came away feeling like I&#8217;d experienced what WCEU is actually for.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><br />That trip also clarified something I&#8217;d been circling around for a while. I&#8217;ve always loved traveling, but there was a barrier that had nothing to do with visas or money — though those were factors too. It was a justification problem. Coming from a culture where time should be spent purposefully, traveling for its own sake felt hard to defend. A work conference, though? Completely justifiable. Nobody asks how much fun you had. I&#8217;ve been to Germany, Portugal, Italy, Switzerland, and Poland this way. Spain is next.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Attending WordCamps is one thing. Building a similar event is another.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-wp-suomi\">WP Suomi</h2>\n\n\n\n<p class=\"wp-block-paragraph\">In 2025 I became the lead organizer of <a href=\"https://wpsuomi.fi/\">WP Suomi</a> — the first independent Finnish WordPress event, held in Helsinki. The months before October 10th were intensive in ways I hadn&#8217;t anticipated: budgets, logistics, gifts, merch, catering, venue coordination, a hundred small details that needed to be right simultaneously. I remember waking up at midnight worrying that I hadn&#8217;t ordered something in time and it wouldn&#8217;t arrive before the event. Most of the work that goes into an event like this is invisible to the people attending. They see the schedule, the food, the afterparty. They don&#8217;t see the half a year of pieces being polished before the puzzle comes together.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://heropress.com/wp-content/uploads/3026/07/image5.webp\"><img alt=\"Banner for WP Suomi\" class=\"wp-image-8721\" height=\"576\" src=\"https://heropress.com/wp-content/uploads/3026/07/image5-1024x576.webp\" width=\"1024\" /></a><figcaption class=\"wp-element-caption\">WP Suomi hall screen graphics. Graphics by Sergei Shchegrinets.</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">On the day of the event, there was nothing left to worry about. Whatever needed doing had been done — if something had been missed in the preparation, it would show up now and there would be little we could do about it. So why worry? The time for that was the preparation, not the day itself. The team — experienced, reliable, no hand-holding required — knew exactly what they were there for.<br /><br />Around 300 people attended WP Suomi. Forty filled out our feedback form afterward, giving an overall score of 4.47 out of 5. But the number mattered less than what people wrote: networking, atmosphere, meeting old friends and new ones, a community that welcomes everyone openly. Reading that, I recognized the same feeling I&#8217;d had at WordCamp Helsinki 2017 — something new, interesting, and full of possibility.<br /><br />Organizing WP Suomi gave me a clearer understanding of what goes into making these events happen. Having been a volunteer at WCEU and then a lead organizer at WP Suomi, I arrived in Krakow with a slightly different perspective — a better sense of what the people around me were going through. This year I&#8217;m back on the WP Suomi organizing team as speakers coordinator — a different role, another angle.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://heropress.com/wp-content/uploads/3026/07/image2.webp\"><img alt=\"Milania Cap near a presentation podium.\" class=\"wp-image-8723\" height=\"683\" src=\"https://heropress.com/wp-content/uploads/3026/07/image2-1024x683.webp\" width=\"1024\" /></a><figcaption class=\"wp-element-caption\">Milana Cap is ready to show some magic with HTML API. She is one of two people who convinced Vladimir to become the lead organizer of WP Suomi ‘25. Photo by Asanka Hettiarachchi.</figcaption></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-krakow\">Krakow</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordCamps have changed for me over the years — less about the sessions on stage, more about what happens between them. As an organizer, you miss most of the talks anyway, pulled in ten directions at once. But real life happens in the corridors, and at the parties in the evenings. </p>\n\n\n\n<p class=\"wp-block-paragraph\">This matters especially for the Ukrainian community. The war has scattered us across Europe — different countries, different companies, different lives. WordCamp Europe has become one of the few places where we reassemble in person: to share what the year brought, to meet people we only knew online, to see the community still growing despite everything. Many couldn&#8217;t make it to Krakow, some would not be able to visit these events anymore. For those of us who could, the room carried extra weight. </p>\n\n\n\n<p class=\"wp-block-paragraph\">That&#8217;s what Danylo and I were singing about at dawn outside Bastion III, even if neither of us said it out loud. I hope to do that someday in the afterparties in Helsinki and Kyiv — whenever that becomes possible again.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://heropress.com/wp-content/uploads/3026/07/image4.webp\"><img alt=\"Ukrainian team at WordCamp Torino 2024.\" class=\"wp-image-8725\" height=\"684\" src=\"https://heropress.com/wp-content/uploads/3026/07/image4-1024x684.webp\" width=\"1024\" /></a><figcaption class=\"wp-element-caption\">Ukrainian team at WordCamp Torino 2024. More and more Ukrainians visit this event every year despite the war. Photo by Maksym Kaharlytskyi. </figcaption></figure>\n\n\n\n<div class=\"wp-block-group has-background is-vertical is-nowrap is-layout-flex wp-container-core-group-is-layout-ff19e26b wp-block-group-is-layout-flex\" id=\"desktop\">\n<h2 class=\"kt-adv-heading8704_097876-99 wp-block-kadence-advancedheading\" id=\"work-environment\">Volodymyr&#8217;s Work Environment</h2>\n\n\n\n<p class=\"wp-block-paragraph\">We asked Volodymyr for a view into his development life and this is what he sent!</p>\n\n\n	<div class=\"hotspots-image-container\">\n		<img alt=\"Volodymyr’s Desk\" class=\"hotspots-image skip-lazy\" height=\"1890\" src=\"https://heropress.com/wp-content/uploads/2026/07/img_5363.webp\" width=\"2560\" />\n	</div>\n\n\n\n\n<p class=\"has--font-size wp-block-paragraph\">HeroPress would like to thank <a href=\"https://wpdrawattention.com/\">Draw Attention</a> for their donation of the plugin to make this interactive image!</p>\n</div>\n\n\n\n<h1 class=\"wp-block-heading\" id=\"ukranian\">“Послухай… пташки заспівали”</h1>\n\n\n\n<figure class=\"wp-block-audio\"><audio controls=\"controls\" src=\"https://heropress.com/wp-content/uploads/3026/07/volodomyr_ukrainian_recording.mp3\"></audio><figcaption class=\"wp-element-caption\">Слухайте власну історію Володимира вголос.</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">«Послухай… пташки заспівали», — сказав Данило, українець, з яким я познайомився на попередньому WordCamp — ми якраз протеревенили останню годину afterparty WCEU у Кракові. «Значить нам теж час іти». І тут він від душі почав співати «Гей, гей, гей, соколи, оминайте гори, ліси, доли». Я підхопив пісню разом із ним. Поляки, що ішли поруч продовжили польською: «Dzwoń, dzwoń, dzwoń dzwoneczku, mój stepowy skowroneczku». Хтось позаду теж приєднався до хору. Це була «Гей, соколи» — українсько-польська народна пісня — під акомпанемент якої нас виносив натовп із Бастіону III, австрійської фортеці XIX століття на околиці краківського Старого міста, саме тоді, коли вже ніч переходила у ранок.<br /><br />Щоб пояснити, як я там опинився, доведеться повернутися до самого початку цієї історії.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://heropress.com/wp-content/uploads/2026/07/krakow_castle2.webp\"><img alt=\"\" class=\"wp-image-8748\" height=\"1024\" src=\"https://heropress.com/wp-content/uploads/2026/07/krakow_castle2-894x1024.webp\" width=\"894\" /></a><figcaption class=\"wp-element-caption\">Вид на Краківський замок, фото зроблене зранку після вечірки, приблизно в той час коли “вже заспівали пташки”. Фото зроблене Володимиром Мельниченко. </figcaption></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-миколаїв\">Миколаїв</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Ця історія бере свій початок у Миколаєві – місті суднобудівельників і наречених, де я виріс. Здобув освіту у двох університетах, де навчався одночасно і почав шукати роботу під час року перерви перед продовженням навчання. Я планував знайти собі роботу, щоб заробити грошенят для продовження навчання, готуючись до вступу в один із фінських університетів. У Миколаєві було важко знайти якісь серйозні перспективи для випускника, хіба що в тебе є зв&#8217;язки, але я примудрився знайти роботу в &#8220;IT&#8221; компанії. У 2011 термін &#8220;АйТі” нічого мені не говорив, але там потрібна була англійська, яка була моїм основним предметом в університеті, тому я подумав, а чом би й ні? Робота не була важкою: треба було казати, що я “Боб” із США і допомагати клієнтам, які купували фізичні продукти, відслідковувати їх замовлення і давати інструкції, як використовувати оте, що вони поназамовляли. Мене звільнили через півтора місяці. Можливо, я щось не так робив, можливо, просто не вдався обличчям — у будь-якому випадку, що було, то загуло.  </p>\n\n\n\n<p class=\"wp-block-paragraph\"><br />На цю роботу я влаштувався самостійно, без будь-якої підтримки, перша заробітна плата була символом моєї незалежності, і перше звільнення — це був бурхливий вир емоцій. Але остання частина просто вибила землю з-під моїх ніг, гірше тільки зробили коментарі на кшталт: “це було занадто добре, щоб бути правдою”, “та ми тобі казали, що там надурять”, і “подивись на нього — він робить те та й се, ще й добре заробляє”. Дуже важко було бути вдома і відчувати себе невдахою. Але це відчуття зробило набагато більше ніж будь-яка ефемерна підтримка — воно мене загартувало і пробудило палке бажання довести, що всі помилялися щодо мене.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-templatemonster-0\">TemplateMonster</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Хоч перша робота виявилась провалом, вона дала мені чітке розуміння, що треба продовжувати шукати роботу в IT. Наступну роботу я знайшов у TemplateMonster.com — добре відому у певних колах. Вона була повною протилежністю моєму минулому досвіду. У 2012 році вони продавали шаблони для більшості популярних CMS-ок того часу: WordPress, Joomla, Drupal, і для різних рішень електронної комерції. Лише ознайомлення з роботою і навчання зайняло два місяці, що промовисто свідчить про те, наскільки серйозно компанія сприймала своїх людей — майже ніколи не звільняли, а якщо люди й ішли з роботи, то з власних причин.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><br />Моїм завданням було допомагати клієнтам із шаблонами, які вони придбали: встановлення, налаштування, редагування. Було доволі складно, але дуже цікаво — мені подобалося. Тоді я вперше познайомився із WordPress. Я працював шість ночей на тиждень, а неділі були найважчими, бо тіло звикало до активності вночі і відмовлялося спати. Хоча такий графік мене не дуже турбував. Можливість створювати будь-які сайти і кастомізувати їх саме під себе — оце було до дідька захопливо. Я багато перепрацьовував, вивчав щось нове, заколупував розробників питаннями, щоб хоч трохи вгамувати жагу до знань. Але усе закінчилося несподівано швидко: я отримав три листи про зарахування на магістратуру у Фінляндії, вибрав один університет і поїхав до Центральної Фінляндії.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-гельсінкі\">Гельсінкі</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Система навчання у Фінляндії побудована зовсім по-іншому — і, на мою думку, на краще. Коли я закінчив основні курси моєї спеціальності, я почав шукати роботу. Завдання було не з легких: рік я шукав пасивно, де-не-де подаючи заявки на роботу, і ще пів року я зайнявся цим активно, відгукуючись на декілька вакансій щодня. Зрештою, доля занесла мене у Гельсінське агентство, що розробляло сайти на WordPress — цим я займаюся і сьогодні. У нас була дуже дружня команда, приблизно з десяти людей, з більшістю з них я досі дружу. Ми будували сайти дуже різного рівня складності, удень, вечорами грали в настолки, ділились історіями зі свого життя і влаштовували грандіозні вечірки.</p>\n\n\n\n<figure class=\"wp-block-image alignright size-large is-resized\"><a href=\"https://heropress.com/wp-content/uploads/2026/07/image3.webp\"><img alt=\"\" class=\"wp-image-8751\" height=\"1024\" src=\"https://heropress.com/wp-content/uploads/2026/07/image3-1024x1024.webp\" style=\"width: 400px;\" width=\"1024\" /></a><figcaption class=\"wp-element-caption\">Вранішній “Weekly” у booncon PIXELS, моєму першому агентстві у Гельсінкі. Фото зроблене Володимиром Мельниченко. </figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">З цією командою я вперше відвідав подію WordPress: WordCamp Helsinki 2017 — дводенну конференцію. Я не був вражений наповал, але вона відкрила мої очі на дещо. Коли ти працюєш у маленькому агентстві, і живеш у своїй бульбашці, а тут неочікувано відкривається цілий всесвіт. Ти бачиш іншу сторону WordPress — спільноту, людей, які рухають увесь проект вперед, людей, які стикаються з тими самими проблемами, які знаходять творчі способи ці проблеми вирішити. </p>\n\n\n\n<p class=\"wp-block-paragraph\"><br />Того першого місцевого WordCamp’у було достатньо, щоб нам захотілося рухатися далі. У 2019 році наша команда поїхала до Берліна на WordCamp Europe — це була моя перша закордонна поїздка за межі звичного для мене маршруту між Фінляндією та Україною. Ми провели кілька днів, досліджуючи місто й відвідуючи конференцію. Масштаб відчувався зовсім по-іншому: тисячі учасників і сотні волонтерів, які усе організовують. Стоячи серед цього натовпу, я зрозумів, що хочу бути частиною цього, і не просто як відвідувач.</p>\n\n\n\n<p class=\"wp-block-paragraph\">А потім почалася пандемія коронавірусу.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-порто\">Порто</h2>\n\n\n\n<figure class=\"wp-block-image alignright size-large is-resized\"><a href=\"https://heropress.com/wp-content/uploads/2026/07/image1.webp\"><img alt=\"\" class=\"wp-image-8754\" height=\"1024\" src=\"https://heropress.com/wp-content/uploads/2026/07/image1-768x1024.webp\" style=\"width: 400px;\" width=\"768\" /></a><figcaption class=\"wp-element-caption\">Я, стою на даху Super Bock Arena, де проводився WCEU 2022. Фото зроблене Олександром Місяц</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">WordCamp Europe 2020 і 2021 років проходили онлайн, і мені здавалося, що вони втратили найголовніше — тисячі людей, зібраних в одному місці, які заряджають одне одного своєю енергією. Тож коли оголосили, що WCEU 2022 відбудеться в Порту, я почав збирати валізу. Цього разу я приєднався до команди волонтерів, щоб побачити WordCamp зсередини. І це було правильне рішення. Для українців це був непростий час — повномасштабне вторгнення вже тривало, і кожен шукав свій спосіб впоратися з новою реальністю. Для мене цей захід став джерелом сили. Я ближче познайомився з українською спільнотою, жваво дискутував зі спікерами й повернувся з відчуттям, що нарешті зрозумів, нашо той WordCamp.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Та поїздка також допомогла мені усвідомити дещо, над чим я давно розмірковував. Я завжди любив подорожувати, але існував бар&#8217;єр, який не мав стосунку ні до віз, ні до грошей — хоча й вони теж відігравали свою роль. Проблема була в тому, як виправдати саму подорож. Я виріс у культурі, де час потрібно витрачати з користю, тому подорожувати просто заради подорожі здавалося чимось, що важко пояснити. А ось робоча конференція — зовсім інша справа. Це цілком виправдана причина. Ніхто не питає, скільки задоволення ти на ній отримав. Саме так я побував у Німеччині, Португалії, Італії, Швейцарії та Польщі. Наступна — Іспанія.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Відвідувати WordCamp — це одне. Створювати подібний захід — зовсім інше.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-wp-suomi-0\">WP Suomi</h2>\n\n\n\n<p class=\"wp-block-paragraph\">У 2025 році я став головним організатором <a href=\"https://wpsuomi.fi/\">WP Suomi</a> — першого незалежного фінського заходу, присвяченого WordPress, що відбувся в Гельсінкі. Місяці, які передували 10 жовтня, виявилися набагато напруженішими, ніж я очікував. Бюджет, логістика, подарунки, мерч, кейтеринг, координація локації — і сотні дрібниць, які мали зійтися в потрібний момент. Пам&#8217;ятаю, як прокидався посеред ночі з думкою, що не встиг замовити щось вчасно і воно не приїде до початку події. Більшість роботи, яка стоїть за такими заходами, залишається непомітною для учасників. Вони бачать програму, їжу, афтепаті. Але не бачать тих пів року, протягом яких окремі деталі поступово складаються в єдину картину.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://heropress.com/wp-content/uploads/2026/07/image5.webp\"><img alt=\"\" class=\"wp-image-8758\" height=\"576\" src=\"https://heropress.com/wp-content/uploads/2026/07/image5-1024x576.webp\" width=\"1024\" /></a><figcaption class=\"wp-element-caption\">Графіка WP Suomi на великому екрані у холі місця проведення. Графіка створена Сергієм Шенгрінцем</figcaption></figure>\n\n\n\n<p class=\"wp-block-paragraph\">WP Suomi відвідали близько 300 людей. Після заходу сорок учасників заповнили форму зворотного зв&#8217;язку, оцінивши його в середньому на 4,47 із 5. Але для мене важливішою була не сама оцінка, а те, що люди писали: нетворкінг, атмосфера, зустрічі зі старими друзями й нові знайомства, спільнота, яка відкрито приймає кожного. Читаючи ці відгуки, я згадав себе і те саме відчуття, яке пережив на WordCamp Helsinki 2017, — це щось нове, захопливе й сповнене можливостей.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><br />Організація WP Suomi допомогла мені значно краще зрозуміти, що стоїть за проведенням таких заходів. Після досвіду волонтера на WCEU, а згодом і головного організатора WP Suomi, я приїхав до Кракова вже з іншим поглядом — набагато краще розуміючи, через що проходять люди, які працюють поруч. Цього року я знову в команді організаторів WP Suomi, але вже в ролі координатора спікерів. Інша відповідальність, інший погляд.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://heropress.com/wp-content/uploads/2026/07/image2.webp\"><img alt=\"\" class=\"wp-image-8760\" height=\"683\" src=\"https://heropress.com/wp-content/uploads/2026/07/image2-1024x683.webp\" width=\"1024\" /></a><figcaption class=\"wp-element-caption\">Milana Cap готова показати магію з HTML API. Вона одна із двох людей, винних у тому, що я став головним організатором WP Suomi ‘25. Фото зроблене Asanka Hettiarachchi.</figcaption></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"h-краків\">Краків</h2>\n\n\n\n<p class=\"wp-block-paragraph\">За ці роки WordCamp для мене змінився. Тепер він менше про доповіді на сцені й більше про те, що відбувається між ними. Як організатор, ти все одно пропускаєш більшість виступів, адже тебе одночасно тягнуть у десять різних боків. Але справжнє життя вирує в коридорах і на вечірках після завершення основних сесій.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Особливо важливо це для української спільноти. Війна розкидала нас по всій Європі — різні країни, різні компанії, різні життя. WordCamp Europe став одним із небагатьох місць, де ми можемо знову зустрітися наживо: поділитися тим, що приніс цей рік, побачитися з людьми, яких досі знали лише онлайн, і переконатися, що наша спільнота продовжує зростати попри все. Багато хто не зміг приїхати до Кракова, на жаль дехто вже ніколи не зможе побувати на цих заходах. Для тих із нас, кому це вдалося, ці зустрічі мають особливе значення.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Саме про це ми з Данилом співали на світанку біля Bastion III, хоча ніхто з нас не сказав цього вголос. Сподіваюся, колись мені ще доведеться робити це на афтепаті в Гельсінкі та Києві — щойно це знову стане можливим.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://heropress.com/wp-content/uploads/2026/07/image4.webp\"><img alt=\"\" class=\"wp-image-8761\" height=\"684\" src=\"https://heropress.com/wp-content/uploads/2026/07/image4-1024x684.webp\" width=\"1024\" /></a><figcaption class=\"wp-element-caption\">Українська команда на WordCamp Europe Torino 2024. Все більше і більше українців приїжджає на цей захід незважаючи на війну. Фото зроблене Максимом Кагарлицьким. </figcaption></figure>\n<p>The post <a href=\"https://heropress.com/essays/listen-the-birds-are-already-singing/\">“Listen&#8230; the birds are already singing” &#8211; “Послухай… пташки заспівали”</a> appeared first on <a href=\"https://heropress.com\">HeroPress</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 08 Jul 2026 05:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:21:\"Volodymyr Melnychenko\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:39:\"BuddyPress: BuddyPress 14.5, 12.7, 11.6\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://buddypress.org/?p=339549\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:60:\"https://buddypress.org/2026/07/buddypress-14-5-0-and-12-7-0/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2951:\"<p class=\"wp-block-paragraph\">BuddyPress <a href=\"https://downloads.wordpress.org/plugin/buddypress.14.5.0.zip\">14.5.0</a>, <a href=\"https://downloads.wordpress.org/plugin/buddypress.12.7.0.zip\">12.7.0</a>, and <a href=\"https://downloads.wordpress.org/plugin/buddypress.11.6.0.zip\">11.6.0 </a>are now available.</p>\n\n\n\n<p class=\"wp-block-paragraph\">These are security and maintenance releases that include two security fixes, along with a number of compatibility improvements, bug fixes, and code modernization updates. We strongly recommend updating your sites as soon as possible.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Highlights</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Two security issues:\n<ul class=\"wp-block-list\">\n<li>Prevent user ID spoofing in the Messages REST API endpoint via improved validation.</li>\n\n\n\n<li>Restrict Component management to Users with the appropriate Capabilities.</li>\n</ul>\n</li>\n\n\n\n<li>Improves compatibility with WordPress 6.9, including support for block style loading optimizations and replacement of deprecated WordPress APIs where appropriate.</li>\n\n\n\n<li>Includes numerous bug fixes across BuddyPress, including BP Nouveau, Groups, Friends, Activity, Administration, and several PHP 8.x compatibility improvements.</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Download</h2>\n\n\n\n<p class=\"wp-block-paragraph\">You can update automatically from your WordPress Dashboard, or download BuddyPress 14.5.0 directly:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://wordpress.org/plugins/buddypress/\">https://wordpress.org/plugins/buddypress/</a></li>\n\n\n\n<li><a href=\"https://buddypress.org/download/\">https://buddypress.org/download/</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">For the complete list of changes included in this release, see the changelog:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://codex.buddypress.org/releases/version-14-5-0/\">https://codex.buddypress.org/releases/version-14-5-0/</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"block-8935e1e5-ef63-42ee-8c08-67fad827159a\">Many thanks to our 14.5.0 contributors </h2>\n\n\n\n<p class=\"wp-block-paragraph\">Thanks to everyone who contributed patches, testing, reviews, bug reports, and responsible security disclosures that helped make this release possible.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Contributors include: emaralive, vapvarun, westonruter, joelkarunungan, nikunj8866, shawfactor, r-a-y, t.schwarz, dcavins, noruzzaman, rollybueno, potcus, pratiklondhe, yatesa01, bhargavbhandari90, amitraj2203, GaryJ., espellcaste, needle, and johnjamesjacoby.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Security issues were responsibly disclosed via the <a href=\"https://hackerone.com/wordpress\">WordPress Bounty Program over at HackerOne</a> and through the <a href=\"https://make.wordpress.org/plugins/\">WordPress Plugins Team.</a> If you were not properly attributed for your contribution here, leave a comment and we&#8217;ll get you added.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Jul 2026 17:57:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"John James Jacoby\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:10;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"Open Channels FM: BackTalk on DevRel, APIs, Digital Freedom\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2556589\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"https://openchannels.fm/backtalk-on-devrel-apis-digital-freedom/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:172:\"Insights into the DevRel role\'s importance, explore endless API possibilities, and consider the balance of digital freedom, cost, and usability in today’s tech landscape.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Jul 2026 13:04:10 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:11;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:13:\"Matt: USA 250\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153462\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:30:\"https://ma.tt/2026/07/usa-250/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:2410:\"<p class=\"wp-block-paragraph\">This auspicious 250th Independence Day, I find myself thinking of what <a href=\"https://om.co/2013/08/13/iamerican/\">Om wrote in iAMerican when he became a US citizen in 2013</a>.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">On a globe, America is a landmass, a country. In an immigrant’s heart it is a belief that future is almost always better. It may not be perfect and it is certainly not equal, but it still is one of a kind — the only place where an absolute stranger with a funny name and a funny accent with no friends or contacts can show up, work hard and actually get to do what he was destined to do. [&#8230;]</p>\n\n\n\n<p class=\"wp-block-paragraph\">In most places in the world, outsiders like me don’t have that chance. That simple truth is what makes America so special. A chance – to be somebody even if you are nobody. America is a state of mind and I have opted-in!</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">I feel lucky to have been born here, and if I hadn&#8217;t been, I think I would have gotten here as fast as I could. I&#8217;m grateful to the public schools that educated me, the <a href=\"https://ma.tt/about/#teachers\">teachers</a> who pushed me, the internet that freed my mind, and the culture of risk and innovation in technology that <a href=\"https://ma.tt/2006/04/a-little-funding/\">invested a million dollars</a> in a 21-year-old dropout kid trying to <a href=\"https://automattic.com/\">build a company</a> around (but not replacing) <a href=\"https://wordpress.org/\">an Open Source project</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">It&#8217;s not unimaginable that these things could have happened someplace else, but it would have been a long shot.</p>\n\n\n\n<p class=\"wp-block-paragraph\">On the lighter side, <a href=\"https://www.youtube.com/watch?v=JYqfVE-fykk\">SNL&#8217;s Washington&#8217;s Dream skit is one of their best ever</a>, <a href=\"https://www.youtube.com/watch?v=Q3RjZY-rSsc\">Google has a pretty funny commercial reimagining the Declaration being written</a>, and <a href=\"https://www.youtube.com/watch?v=ezs9h7Td8Zg\">another famous Matthew (McConaughey) gives a great 2-minute speech</a>. &#8220;We need skeptics. Yes, we do. We do not need cynics. One cares enough to question, which we should, and the other one&#8217;s already quit.&#8221;</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 05 Jul 2026 06:59:52 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:12;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:61:\"Open Channels FM: Open Source as Foundation, Not Final Answer\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2556361\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:67:\"https://openchannels.fm/open-source-as-foundation-not-final-answer/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:175:\"In ecommerce, it’s not just about the tech but how it helps merchants grow. Open source can offer control and adaptability, especially with platforms like Woo and WordPress.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 02 Jul 2026 09:59:53 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:13;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:120:\"WPTavern: #223 – Ivana Ćirković on How WordPress Credits Bridges Education and Industry in the WordPress Ecosystem\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=206102\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:130:\"https://wptavern.com/podcast/223-ivana-cirkovic-on-how-wordpress-credits-bridges-education-and-industry-in-the-wordpress-ecosystem\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:38278:\"<details>Transcript<div>\n<p class=\"wp-block-paragraph\">[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Jukebox is a podcast which is dedicated to all things WordPress, the people, the events, the plugins, the blocks, the themes, and in this case how WordPress Credits bridges education and industry in the WordPress ecosystem.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox and use the form there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So on the podcast today we have Ivana Ćirković. Ivana is a digital marketer with 18 years of experience working both in and out of the tech industry, and currently leads marketing at WPBakery. She&#8217;s an active participant in WordPress events, having attended, and spoken at, numerous local and international word camps over the years.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In this episode, our focus is on the WordPress Credits initiative. We learn how this program, launched by the WordPress Foundation, connects students with real world opportunities to contribute to the WordPress ecosystem, earn certifications, and increase their competitiveness in the job market.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ivana discusses her own experience as a WP Credits mentor, working with students as they learn about digital marketing, remote work, and other open source contributions. We explore, how universities can modernise their curriculums, and real world value for students by participating in the initiative, and how businesses can get involved, not just to support the community, but to help shape and discover future talent.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The program&#8217;s evolving structure also gets attention, and we learn how students are guided through hands-on activities such as translation or documentation, and how their progress is tracked publicly via profiles on wordpress.org. Ivana shares the opportunities and challenges for both educators and businesses with thoughts on accountability, mentorship, and the need to bring new faces into the WordPress community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re interested in the future of WordPress, education, or bridging the gap between academia and industry, this episode is for you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d like to find out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so without further delay, I bring you Ivana Ćirković.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I am joined on the podcast by Ivana Ćirković. Did I get that right?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:14] <strong>Ivana Ćirković:</strong> Yes. Excellent.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:16] <strong>Nathan Wrigley:</strong> Thank you. This is my first interview at WordCamp Europe 2026. I&#8217;m guessing because we&#8217;re on the first day of the event and it&#8217;s quite early in the morning, it&#8217;s 10 in the morning, I&#8217;m guessing you cannot have done your presentation yet?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:30] <strong>Ivana Ćirković:</strong> Not yet. Tomorrow.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:32] <strong>Nathan Wrigley:</strong> Do you get nervous with these kind of things?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:34] <strong>Ivana Ćirković:</strong> I get nervous all the time. I&#8217;ve been doing this for 12 years, it never gets easier. It is what it is.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:39] <strong>Nathan Wrigley:</strong> Well, the presentation that you are doing is going to be the focus of what we&#8217;re talking about today. So do you just want to tell us a little bit about the topic that you&#8217;re talking about, but also just give us a bit of a general bio about who you are and what you do. So just tell us about you and about your presentation basically.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:56] <strong>Ivana Ćirković:</strong> Okay. First thing first, I would like to introduce my presentation, or the talk, that is build up around WordPress Credits initiative, which is something that WordPress has rolled out late last year in December. And I applied to be a mentor to support students into their entering into WordPress. Got accepted, did my courses, passed them and started working with students on their, first entering the WordPress society, how everything works, contributing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And out of all of this, I came up with the idea of sharing the story about WordPress Credits. What it is, why it is important, not just for the WordPress community, but also for universities all around the world for businesses to support, because there is an angle and huge opportunity for them too. And hopefully inspire people to join and become part of it more.</p>\n\n\n\n<p class=\"wp-block-paragraph\">As far as I&#8217;m concerned, my name is  Ivana Ćirković and I am a digital marketer for 18 years. I&#8217;ve been working inside tech organisations, tech industry, but also outside of it. So I&#8217;m the multiverse. And lately, for past couple of years, I&#8217;ve been working in WPBakery, in marketing their product, and talking to people, sharing knowledge of what we do, how we do it, and so on. In the meantime I am attending many, many WordCamps, local and international ones, giving lectures, giving talks about digital marketing and all things related.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:05:39] <strong>Nathan Wrigley:</strong> So are you here at this event, not just to give your presentation, are you also here on behalf of WPBakery to represent them and the products that they have as well?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:05:47] <strong>Ivana Ćirković:</strong> Yes, we are sponsors. I am speaker, I was table lead for marketing on Contributors Day. So we are wide into the ecosystem.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:05:56] <strong>Nathan Wrigley:</strong> I have to say, having only been in this event space for about an hour, I&#8217;m actually deeply impressed by this particular event. It really is a gigantic venue. It&#8217;s so pleasurable as well to see the WordPress community in such large numbers here. And so we&#8217;re looking forward to a really good event.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Okay, let&#8217;s kick off with the topic at hand then. So it occurs to me that many people listening, whilst they&#8217;re using WordPress and they&#8217;re kind of, I don&#8217;t know, they&#8217;re building websites for people, and they&#8217;ve got products and plugins and they&#8217;re just general users. It may be that the community piece, and the educational piece, is nothing that they&#8217;ve heard of before. So would you just tell us a little bit about what WP Credits is as far as you&#8217;re concerned, just to give us that broad background of what it is?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:40] <strong>Ivana Ćirković:</strong> Okay. So WP Credits program is initially made to bring new young people into the WordPress, to broaden the ecosystem with the new fresh blood, new contributors. And to do so, WordPress Foundation initiated this program to connect with universities all across the world. To connect students to some programs, to learn about WordPress through contribution. For that, they will get graded and get certification, which in the end will help them be more marketable, and have more modern knowledge of what is needed in today&#8217;s job market, and to be more competitive and more appealing to potential employers.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So by doing so, WordPress Credits aims to broaden the ecosystem, to strengthen the WordPress community, and WordPress itself. But also to put new generations in more marketable place, and to help them get more profitable jobs.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:07:45] <strong>Nathan Wrigley:</strong> Thank you. That was a really nice summary. In terms of your personal commitment to it and what have you, how did you fall into it as a thing that you were doing? And is this something that you get sponsored for from WPBakery, or is it personal and simply a sort of philanthropic thing that you are doing on the side?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:08:01] <strong>Ivana Ćirković:</strong> Yeah, so basically, I&#8217;ve been doing education my whole professional life. So it&#8217;s something that comes natural to me. In my local country, in Serbia, I do informal education for high schoolers and primary school&#8217;s children about digital marketing, digital literacy. This is like very natural to me. I&#8217;m being sponsored by WPBakery to do so.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And the program works like, initiative needs people, needs more mentors to get involved. More than it needs like product and businesses to support with their products. So if there are businesses who are maybe interested in support through their product, know that you need to put your people first to actually get involved and contribute, and then you can offer products as the side piece, so to say.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:08:52] <strong>Nathan Wrigley:</strong> So yeah, it seems that you&#8217;ve got a lifelong interest in education as well. Okay, that gives me some sort of hook there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Okay, if I was to say WP Credits to the people outside, the people who already knew about it, I think would probably peg it as entirely educational in nature, just an education initiative. But curiously, your presentation, the notes that went with that and the blurb that went on the WordCamp Europe website, you kind of make the point that it&#8217;s much bigger than that, and you get into businesses and the students themselves and universities.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So the students in universities bit, well, that&#8217;s the education piece. But the business bit, what&#8217;s going on there? Because I definitely hadn&#8217;t drawn that intuition. I thought education from top to bottom. But business, okay, where does that fit in?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:09:37] <strong>Ivana Ćirković:</strong> I will get the hot insights from the talk. So basically, there is more than what meets the eye, so to speak. Businesses have unique opportunity to shape people they want to employ by getting involved as mentors. They also get the chance to see firsthand how those young minds work in real environments, in real contribution. And they get the chance to pick and choose who they want to employ by seeing them work on some real things. Whether it&#8217;s documentation, whether it&#8217;s translation or programming, developing something, AI.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We need more people who know what they do, although they are young. By having students in this program, they are working on not fictional things, but actual things that really contribute to community and businesses as a whole. By supporting this initiative, businesses then in relations to that can get more insights into who they want to employ. So on top of that, they are building the better market for themselves as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:10:42] <strong>Nathan Wrigley:</strong> I guess the student university piece is fairly obvious. You know, WP Credits and the people working on that project communicate with universities, they&#8217;re probably easy to find. You know, if you go to a phone directory for example, they&#8217;ll all be there. And it&#8217;s an easy thing to do. You phone up the university and see if there&#8217;s interest. And I know that some universities have taken up the WP Credits program. And it seems to be, as far as I can work out, it seems to be working very successfully.</p>\n\n\n\n<p class=\"wp-block-paragraph\">How are you going to make the connection with businesses? Because that seems like a much more scattered, I don&#8217;t know if you&#8217;re going to be working with big businesses, you know, huge companies or if it&#8217;s going to be kind of more the businesses on the street, the smaller businesses, that kind of thing. So, I&#8217;ll just sort of hand it over at that point.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:11:23] <strong>Ivana Ćirković:</strong> So basically, web agencies, businesses around WordPress, we know they have an issue with new employees onboarding last, let&#8217;s say three to six months. That cost time and money and other people who are teaching them what needs to be done and how.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Then we have WordPress Credit students who are already doing that junior type of work within contribution. They&#8217;re already onboarded through using Slack, knowing how to do remote work, what needs to be done. So businesses supporting WordPress Credits initiative can choose those students and spend less time and money and energy in onboarding them because they already went through that by doing WordPress Credits program.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:12:10] <strong>Nathan Wrigley:</strong> Yeah, I guess if you are a small web agency, it&#8217;s highly likely that you won&#8217;t necessarily have an induction program finely tuned, so that the young people that are coming through have this sort of specialised system where they can get some accreditation. It&#8217;s probably more, okay, I&#8217;m going to assign you to John this week and then next week you&#8217;re going to go over to Susan and follow what they&#8217;re doing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So is there a sort of structured program that, let&#8217;s say a web agency based in London could drop into and receive documentation about? Where are we at with that whole process for the busineses?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:12:44] <strong>Ivana Ćirković:</strong> Yeah, so since this initiative is still fairly new and we already have just one generation of students that are passed the program, this is something in development. So at the moment, we still don&#8217;t have like a specific structure that is based just for agencies and businesses in general, but it is something that we are considering and working towards too. So definitely.</p>\n\n\n\n<p class=\"wp-block-paragraph\">On the other hand, the upper management organisational team might not be aware to the fullest what am I about to talk. So it might come as a surprise to them, but also it is something in the works as well. So give us some time and we will come up with something.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:26] <strong>Nathan Wrigley:</strong> Yeah, it feels like that would be something really credible. Because if you&#8217;re a small business owner, the last thing you want to be doing is kind of wasting time. And onboarding somebody might be something that you&#8217;d have to divert weeks into, you know, syphoning employees off, writing documentation, SOPs, those kind of things. And if you could just pick something up off the shelf that was tried and tested over many years, that would actually be really handy. So good luck. I hope that that initiative comes off.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In terms of students, if you were a student, let&#8217;s say you are at a university, or you are looking for work, what would you say would be some of the top line items that you would mention as to why WP Credits is worth looking at? Because, you know, if I&#8217;m at a university, there&#8217;s probably a thousand different things that I could be doing. WP Credits would be in competition with all of those. Why do you think it&#8217;s something that young people should be taking care of to look at?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:14:17] <strong>Ivana Ćirković:</strong> Yeah, I would think differently, in that sense. Universities curriculums are outdated comparing to the industry that we are living and working in. So WordPress Credits gives something that is in trend. That is happening now that people are using and working now. So students who choose to go to this program are gaining the most efficient and not outdated curriculum, and things that are being worked on in this moment.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And this is bigger than WordPress. It is initially for WordPress, but the knowledge students get, nobody can take that away. They learn to be outspoken. They learn to use all the necessary remote work tools that is applicable in all the industry.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So we are really encouraging them to be very marketable employees and people who have portfolios, whether they choose that category that brings them portfolio. That is very transparent throughout whatever they do. Because on wordpress.org, every contribution is noted. So they&#8217;re building their own business brand by doing WordPress Credits. And in that way they are more marketable and can get more business opportunities.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:15:42] <strong>Nathan Wrigley:</strong> I didn&#8217;t realise that the wordpress.org profile, is it the profile that you mean?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:15:47] <strong>Ivana Ćirković:</strong> Yes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:15:47] <strong>Nathan Wrigley:</strong> Each time you participate in one of these credit programs, that will be a badge, for want of a better word, that you can display and it will be freely available for the public. And presumably that will be difficult to acquire. That&#8217;s the wrong word. What I mean is, it won&#8217;t be simple to acquire. You will genuinely have had to.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:16:07] <strong>Ivana Ćirković:</strong> Yes, you need to do the work. Let&#8217;s say students are interested in translation. So they go to Polyglots team and they get assigned to a mentor who is on weekly basis working with them on onboarding, helping them how to navigate through wordpress.org website, translation, what needs to be done. And basically, for that student, they need to translate to have approved translation, 150 strings approved.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that doesn&#8217;t mean, okay, I will translate 150 words. No, no. You might need to translate 500 words out of which 150 is approved. And this is the bare minimum you need to do in order to get that badge that you contributed. Because that contribution, each contribution needs to be something very specific and tailored to help other people. That is very open and helpful.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:17:00] <strong>Nathan Wrigley:</strong> So you mentioned translations there, which obviously is just one of multiple things that you could do, and we could list them all out, but we won&#8217;t. How is that curriculum, I&#8217;m doing air quotes, how is that curriculum decided upon? In other words, how do you decide, okay, I&#8217;m going to do a bit of translation, I&#8217;m going to do a bit of work on Core, I&#8217;m going to work for the Plugin Review Team? How is that decided? And, how is it decided by the institution, I guess that that&#8217;s going to equal something which our university will stamp as part of your degree, let&#8217;s say?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:17:33] <strong>Ivana Ćirković:</strong> Yeah. So basically, that is all arranged between the foundation and universities. You won&#8217;t get IT students doing marketing if that&#8217;s not their preferable choice. So students opt in. They&#8217;re given the whole like curriculum, categories of things they can contribute to. And the one they choose, this is the one they stick to throughout all the programs.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So you cannot switch in between like translation and documentation, or plugins, or WP-CLI whatever. The whole program stick to one chosen category. And that is all aligned with the, let&#8217;s say, topic of university. So IT is preferable for IT related contributions. Communications are also more favourable towards translation community, marketing. So it&#8217;s aligned that way.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:18:23] <strong>Nathan Wrigley:</strong> So flipping that round, so we&#8217;ve been talking about it from the point of view of the students. Now let&#8217;s just flip it around to the point of view of the university. I guess the same thing applies. They would have to communicate with the Foundation and say, okay, these are the kind of things that we wish our students to do. These particular strands, we will, you know, if they do 500 translation strings, that will count as something. I guess there&#8217;s got to be some interface between the Foundation and each university to establish what a credit equals.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:18:50] <strong>Ivana Ćirković:</strong> Yeah, common ground as to how WordPress Credits adds to the official curriculum of the university. And the thing that university get out of it, they are in position to offer modern, in trend, teachings, and that makes them more appealing to next generation of students. Because the more their existing students who are in the WordPress Credits program are succeeding, the more desirable the university gets to newer generations because they don&#8217;t teach outdated curriculums. They&#8217;re aligning to what is now efficient and needed in the job market.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:19:30] <strong>Nathan Wrigley:</strong> I suppose also as well, when I was at university, there was a choice of about, I don&#8217;t know, four things to do each year. Something like that. You could do this or this or this. And you had to pick one of them and that was your pathway. This feels much more wide open because knowing the WordPress ecosystem, I know that there&#8217;s dozens, maybe multiple dozens of different things that you could be involved in.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that&#8217;s quite appealing as well, isn&#8217;t it? You know, you can just take a little nibble of this one thing, and another nibble of this. And so there&#8217;s potentially multiple dozens of different pathways that you could pick. And whilst you say that, once you&#8217;ve decided you&#8217;ve got to stick to that, well, that&#8217;s fair enough, but the fact that you&#8217;ve got so many different ways that you could choose. That to me as a university student would&#8217;ve been really appealing. The fact that there&#8217;s so many different things that you could do.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:15] <strong>Ivana Ćirković:</strong> Yeah. And once they got in, the overall input that we get from students that, first they don&#8217;t know that something like this exists. And once they go deep and start work, it&#8217;s like, wow. The whole mind just shifts, and they are amazed by all the possibilities that they can do within WordPress that isn&#8217;t talked about.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:36] <strong>Nathan Wrigley:</strong> Yeah. And I presume they get to do it in the way that the WordPress community works, which is remotely distributed and when you wish to do it. So long as I, you make the end of the university period of whatever a semester is or something, so long as you make the deadline, you can do it at night or in the early morning or.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:57] <strong>Ivana Ćirković:</strong> Exactly. So they are training to be like workers as we all are today, that are not restrained with some deadlines or by official university rules. They&#8217;re accountable for the final output. How will they come to that output? It&#8217;s entirely up to them because, yes, they are young but they&#8217;re not so young that they cannot be held accountable for their actions. So they need to do the work. We got weekly mentorships and assessments. So it&#8217;s a fun ride.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:21:31] <strong>Nathan Wrigley:</strong> So just touching on that, the sort of ongoing support that every student needs, because with the best rule in the world, there&#8217;s a proportion of students who will leave everything to the last minute. I&#8217;m looking at myself in the mirror when I say that. So that ongoing support, it&#8217;s a weekly sort of huddle. And is that like a one-to-one thing or is it a one to many thing?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:21:50] <strong>Ivana Ćirković:</strong> Yeah, so depending on the number of students, if a mentor has a one or two students, it can be one-to-one. If there are more like five or six, it&#8217;s better to have a group meeting on a weekly basis, and then Slack chats in between if anything is more needed than that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So basically we go through what they did last week, are there any setbacks or they need additional help, or do they need information from other parts of the team? Are they interested in something else? So we are really trying to get them involved in a way that matters to them.</p>\n\n\n\n<p class=\"wp-block-paragraph\">One of the things that each student needs to do, no matter section they chose, is to create a blog and to have weekly blog posts. So we discuss about that. What interests them. Whether they want to be something personal like, or professional like. So it&#8217;s very interesting to see how they think and how they express themself and how they build their online persona.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:55] <strong>Nathan Wrigley:</strong> Do those huddles take place on a, let&#8217;s say university by university basis? So for example, when you join and you mentor students, are they from the entire WP Campus project, or are you doing it from the university of this town and the university of that town?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:23:13] <strong>Ivana Ćirković:</strong> No, it&#8217;s mixed and matched.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:23:14] <strong>Nathan Wrigley:</strong> So, okay, well that&#8217;s a real strength as well it feels, because presumably then you&#8217;re on a call with people potentially from all over the world. Certainly people that you may not have encountered before. And those sort of serendipitous chance encounters can sometimes be some of the more meaningful ones. You know, work comes out of those things, and meetups come out of those things, and unexpected things come out of those things. So that must be really nice as well, watching those kind of things happen.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:23:42] <strong>Ivana Ćirković:</strong> Yeah, it&#8217;s like nothing I experienced before. And just to have the privilege to talk and work with those people, you never know what can come up out of them, and out of our connections. And I get inspired every time we have chats and they make me want to be a better educator.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:03] <strong>Nathan Wrigley:</strong> Oh, that&#8217;s interesting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:04] <strong>Ivana Ćirković:</strong> So, yeah, that&#8217;s my take out of all this.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:06] <strong>Nathan Wrigley:</strong> Yeah. Okay, so there&#8217;s actually some psychological benefit for you as well. You get a real nice feeling of it. Okay, that&#8217;s really good.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So with the best will in the world, a university, every year there&#8217;s a cohort of children, young adults, whatever it may be, whichever institution it is, and a proportion of them will work diligently and hard and they will succeed. And some others maybe not so much.</p>\n\n\n\n<p class=\"wp-block-paragraph\">How does that work? How do you ensure that everybody gets through it? And I don&#8217;t know if there&#8217;s enough data to answer this question. Again, I&#8217;m doing air quotes, how is the pass rate? Do most people that embark on this get through the necessary things? Or is there a fair bit of, I don&#8217;t know, discipline, for want of a better word, that needs to be applied and cajoling people to get through it?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:46] <strong>Ivana Ćirković:</strong> Yeah, so I touched base on the accountability. So we have not strict rules, but recommendations. Weekly mentor chats, async communication through Slack. They all have weekly tasks that needed to be done. So if a student don&#8217;t answer the message or come to weekly mentor call three times, they are no longer WordPress Credit students. And that is the accountability.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You need to show yourself that you are willing to do the work. So if you don&#8217;t care, we won&#8217;t force you to do that if you don&#8217;t want to. We will set reminders, we will call back, we will reach out. But if you are no show, no tell anything for three times, then evidently you are not for that. You don&#8217;t wish to be there, and we won&#8217;t force you to be there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:40] <strong>Nathan Wrigley:</strong> And then in some way, are you required then to report that back to the institution and sort of say, okay, we&#8217;ve reached the end of the road here, and then it&#8217;s for them to figure out how that impacts. And presumably the students can.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:53] <strong>Ivana Ćirković:</strong> Their grades, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:53] <strong>Nathan Wrigley:</strong> Yeah, their grades what have you, okay. Touching back on the sort of business side, because we&#8217;ve dwelled a lot with students and universities and we&#8217;re going to stay with students, because that&#8217;s really the underpinning of the whole thing. How has the business side of things, is it taking off? You were describing that it&#8217;s kind of like a new thing. Have you got any sort of success stories or anecdotal evidence that people do in fact want this?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:15] <strong>Ivana Ćirković:</strong> Yeah, so it&#8217;s still fairly new, so we don&#8217;t have those anecdotes yet. One of the reasons why I&#8217;m here at the WordCamp Europe is to find out and to get new perspective from businesses to like reach out to them to see what they think about the program. Would they want to be evolved. And how to give tips, maybe how we can improve. So stay tuned for more.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:38] <strong>Nathan Wrigley:</strong> Yeah. And it is interesting, when you walk around an event like this, I don&#8217;t have the exact numbers, but the demographic is definitely skewing older. There&#8217;s not so many 18 year olds. And if this community wishes to carry on, at some point the age demographic will get to retirement age.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:57] <strong>Ivana Ćirković:</strong> Yeah. Just last night we were talking. I&#8217;ve been in the community for 11 years. And for 11 years all the same faces are here. And we really need new faces. But to get new faces, WordPress Credits is one part of the solution. But then again, we need to meet young people where they are. And they are not on the conferences, they are not on websites, they don&#8217;t use websites, they don&#8217;t care about websites. They are on very specific social media channels. And if we want to get fresh, new, young blood, we need to go there and to present what we do in a way that matters to those kids.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:27:35] <strong>Nathan Wrigley:</strong> In terms of success, if you were to, I don&#8217;t know, let&#8217;s imagine that we could cast our minds forwards five years, let&#8217;s go for that. What would you like to have happened with WP Credits? Would you like, for example, to see a bunch of 20 somethings wandering around in an event like this? Does it matter that they&#8217;re involved in the community and doing WordPress events and contributing to Core and those kind of things? Or is success just more broadly, people are using WordPress? You know, it&#8217;s still a project. What&#8217;s your take on, what does success look like in five years?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:08] <strong>Ivana Ćirković:</strong> For me, I would like to see more young people involved. Yes, we will always have users because in its core, WordPress is a very useful tool. And I&#8217;m happy to stumble upon that tool many, many years ago to use it both personally and professionally. But I really want to see young people involved in a way that we were involved 10, 15 years ago, and to see what can happen with WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I strongly believe it&#8217;ll be transformed, not with AI or all other flashy trends. WordPress has always been about people. And we need new people, we need young people to get it where it needs to be.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We are getting older and don&#8217;t have strengths or stamina to do so for how many long years. By having new kids, fresh perspectives, I&#8217;m really excited to see what they can come up with next.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:29:08] <strong>Nathan Wrigley:</strong> Yeah, it&#8217;s kind of handing over the baton in a way, isn&#8217;t it? Seeing what the future holds. Yeah, I definitely have concerns that the age demographic is skewing. And no matter what has happened in the past, I don&#8217;t see it being backfilled with younger people moment.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But I think that&#8217;s largely because we just assumed that that age demographic would fill itself, because we were excited about it, so the younger generation will be excited about it. Well it turns out the world moved on. And TikTok came along, and YouTube became a massive thing and mobile phones and all the different platforms became a thing. And so the attention was put elsewhere by many young people.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so I suppose we needed to come up with a system where we are, in a sense, just putting it in front of their face and saying, look, it&#8217;s here. You know, you&#8217;re a university student, you are somebody looking for work in a small business. Here&#8217;s a credible way of getting involved in something which potentially could change your life. That seems like the most credible way of doing it at the moment. And I guess we&#8217;ll just have to see what the next five years brings.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In which case, is there anything that you felt you wanted to touch on that you wanted to get out of this chat before we finished?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:30:15] <strong>Ivana Ćirković:</strong> No, I think you did it masterfully. And we touched base on everything that needed to be said.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:30:20] <strong>Nathan Wrigley:</strong> Perfect. In that case, I will say Ivana, thank you for chatting to me today. Fingers crossed that your presentation goes well tomorrow, and that you pack the place out, and that by this time next week, you are extremely busy with the WP Credits program. Thanks for chatting to me.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:30:34] <strong>Ivana Ćirković:</strong> Thank you. Thank you for inviting me.</p>\n</div></details>\n\n\n\n<p class=\"wp-block-paragraph\">So on the podcast today we have Ivana Ćirković.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ivana is a digital marketer with 18 years of experience working both in and out of the tech industry, and currently leads marketing at WPBakery. She’s an active participant in WordPress events, having attended and spoken at numerous local and international WordCamps over the years.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In this episode, our focus is on the WordPress Credits initiative. We learn how this program, launched by the WordPress Foundation, connects students with real-world opportunities to contribute to the WordPress ecosystem, earn certifications, and increase their competitiveness on the job market.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Ivana discusses her own experience as a WP Credits mentor, working with students as they learn about digital marketing, remote work, and open source contributions. We explore how universities can modernise their curriculums and add real-world value for students by participating in the initiative, and how businesses can get involved, not just to support the community, but to help shape and discover future talent.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The program’s evolving structure also gets attention, and we learn how students are guided through hands-on activities such as translation or documentation, and how their progress is tracked publicly via profiles on WordPress.org. Ivana shares the opportunities and challenges for both educators and businesses, with thoughts on accountability, mentorship, and the need to bring new faces into the WordPress community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you’re interested in the future of WordPress, education, or bridging the gap between academia and industry, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://learn.wordpress.org/course/wordpress-credits/\">WordPress Credits</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wpbakery.com\">WPBakery</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://europe.wordcamp.org/2026/session/what-it-really-means-to-be-a-part-of-the-wp-credits-program/\">What it (really) means to be a part of the WP Credits program?</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 01 Jul 2026 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:14;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:75:\"Open Channels FM: BackTalk on Support, Decision-Making, Reputation and Risk\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2556251\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://openchannels.fm/backtalk-on-support-decision-making-reputation-and-risk/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:140:\"Insights on community support, decision-making, starting new projects, and the importance of agency reputation in hosting. Engage and share!\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 01 Jul 2026 13:11:31 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:15;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"Aaron D. Campbell: Open Source Support Can’t Depend on Charity\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://aarondcampbell.com/?p=2933\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://aarondcampbell.com/2026/06/open-source-support-cant-depend-on-charity/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:470:\"<p>Companies depend on open source software. Supporting the projects that support your business shouldn\'t be treated as charity; it should be part of sustaining the infrastructure, ecosystem, and user trust your products rely on.</p>\n<p>The post <a href=\"https://aarondcampbell.com/2026/06/open-source-support-cant-depend-on-charity/\">Open Source Support Can&#8217;t Depend on Charity</a> appeared first on <a href=\"https://aarondcampbell.com\">Aaron D. Campbell</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 30 Jun 2026 13:19:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:17:\"Aaron D. Campbell\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:16;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:63:\"Open Channels FM: Thoughts on the Human Side of AI Acceleration\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555792\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:70:\"https://openchannels.fm/thoughts-on-the-human-side-of-ai-acceleration/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:155:\"AI is evolving super fast, boosting productivity but also causing burnout and a loss of human touch. We need to balance tech with authentic human insights.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 30 Jun 2026 11:06:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:17;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:81:\"Open Channels FM: Aligning WooCommerce Marketing Strategies for Community Success\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2556016\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://openchannels.fm/aligning-woocommerce-marketing-strategies-for-community-success/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:185:\"In this episode we’re chatting about a topic that matters to everyone in the WooCommerce world and beyond: how OSS communities can come together to market themselves more effectively.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 30 Jun 2026 09:08:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:18;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:50:\"WordPress.org blog: The First AI Leaders Graduates\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20951\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://wordpress.org/news/2026/06/ai-leaders-graduates/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4846:\"<p class=\"wp-block-paragraph\">On June 23, around 40 students from the University of Illinois Chicago (UIC), Louisiana Tech University, and the University of Louisiana at Lafayette were celebrated in Chicago as the first cohort to receive the AI Leaders Micro-Credential through <a href=\"https://ai-leaders.org/\">AI Leaders</a>, the nation&#8217;s first workforce-focused AI literacy course tied to a recognized credential. Each of them earned it by building real projects, applying generative AI to genuine work, and contributing to the open source software that powers more than 40% of the web. Students who completed the course also earned $1,000, made possible by a donation from Automattic and UIC. This celebration was the moment the program had been building toward since it was <a href=\"https://wordpress.org/news/2026/02/ai-leaders-credential/\">first announced in February</a>.</p>\n\n\n\n<div class=\"wp-block-group has-background is-layout-constrained wp-container-core-group-is-layout-2431c55b wp-block-group-is-layout-constrained\">\n<p class=\"has-text-align-center has-white-color has-text-color has-link-color has-normal-font-size wp-elements-2 wp-block-paragraph\"><strong>Explore the project portfolios built by this year’s AI Leaders</strong></p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://aileaderswp.blog/\"><img alt=\"\" class=\"wp-image-20975\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/06/aileaderswpblog-scaled.png?ssl=1\" /></a></figure>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-3e41869c wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-text-align-center wp-element-button\" href=\"https://aileaderswp.blog/\"><strong>AI Leaders · Class of 2026</strong></a></div>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">When the pilot launched, the goal was to test whether open source learning could connect directly to job pathways rather than stopping at a certificate. What makes this program distinct is that it is built on open source from the ground up: students learn on WordPress, contribute to it, and use generative AI the way the WordPress ecosystem uses it every day, leaving with a credential that employers can verify and a community that continues long after the course ends.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The pilot reflects a shared belief that AI and open source skills should be within reach regardless of where someone lives or what they can afford.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">WordPress was built to expand access to publishing and participation on the open web.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">The program is a collaboration with distinct roles for each partner. It is funded through the <a href=\"https://osf.it.uic.edu/\">UIC Tech Solutions Open Source Fund</a>, with support from the <a href=\"https://www.uic.edu/\">University of Illinois Chicago</a> and <a href=\"https://automattic.com/?p=867048\">Automattic</a>, while the WordPress project and the <a href=\"https://wordpressfoundation.org/\">WordPress Foundation</a> contribute to the development of the curriculum itself.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What Comes Next</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The first cohort was just the beginning. The gathering in Chicago brought this group together with employers and agencies, and further job placements are already in motion. </p>\n\n\n\n<div class=\"wp-block-group has-off-white-2-background-color has-background is-layout-constrained wp-container-core-group-is-layout-2431c55b wp-block-group-is-layout-constrained\">\n<p class=\"has-text-align-center wp-block-paragraph\">The next round of AI Leaders is on the horizon. Subscribe for updates to be the first to hear when the next cohort opens and how to take part.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-3e41869c wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://ai-leaders.org/#apply\"><strong>Subscribe for AI Leaders Updates</strong></a></div>\n</div>\n</div>\n\n\n\n<hr class=\"wp-block-separator has-text-color has-dark-strokes-grey-color has-alpha-channel-opacity has-dark-strokes-grey-background-color has-background\" />\n\n\n\n<p class=\"wp-block-paragraph\"><em>WordPress offers a wide range of educational opportunities for people at every stage, from first steps to advanced contribution. Explore workshops, lesson plans, and community-created resources designed to help you build practical skills while connecting with others who are learning and contributing at <a href=\"https://wordpress.org/education/\">WordPress.org/education/</a>.</em></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 29 Jun 2026 20:29:26 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Mary Hubbard\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:19;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:85:\"Open Channels FM: Six Months In: What Open Channels FM Has Been Talking About in 2026\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555969\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:91:\"https://openchannels.fm/six-months-in-what-open-channels-fm-has-been-talking-about-in-2026/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:197:\"In the first half of 2026, conversations on AI\'s impact, WordPress 7.0 launch, and the importance of the open web emerged. Key themes included rethinking work, community, and embracing uncertainty.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 29 Jun 2026 07:31:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:20;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Matt: Om Links\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153359\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"https://ma.tt/2026/06/om-links/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:5363:\"<p class=\"wp-block-paragraph\">There has been a lot of excitement about the OmFest idea. If you&#8217;d like to attend or contribute, <a href=\"https://docs.google.com/forms/d/e/1FAIpQLScyY9c5MowPFW6BmIitqaaF3T-ykM_d8eD2pq2XqwSt7N50zg/viewform?usp=header\" rel=\"noopener\" target=\"_blank\">please fill out this form as soon as possible</a> so we can gauge the type of venue we need.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Update: <a href=\"https://thankyouom.com/\">ThankYouOm.com from Michael Galpert pulls together all the tweets, Instagram posts, and blog posts into a beautiful site</a>.</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">It&#8217;s truly a testament to how Om lived life to see the outpouring of remembrances <a href=\"https://om.co/2026/06/24/1966-2026/\">in comments on the post</a> and <a href=\"https://www.techmeme.com/260625/p50#a260625p50\">around the web on Techmeme</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I do wish he had been more public earlier in his health journey. You never know what you&#8217;ll learn. I&#8217;ll take that as a lesson for myself if I&#8217;m ever in a similar situation.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There have been some great long-form writings about Om:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://daringfireball.net/2026/06/om\">John Gruber ties together Apple, the Yankees, and luggage</a>. &#8220;<em>He not busy being born is busy dying</em>, wrote Dylan. Om Malik wasn’t busy dying even when he was dying.&#8221;</li>\n\n\n\n<li><a href=\"https://staceyoniot.com/thank-you-om-malik/\">Stacey Higginbotham</a> from the original GigaOM.</li>\n\n\n\n<li><a href=\"https://mathewingram.com/work/2026/06/25/om-malik-1966-2026/\">Mathew Ingram</a>.</li>\n\n\n\n<li><a href=\"https://www.nytimes.com/2026/06/26/technology/om-malik-dead.html\">The New York Times did an obituary</a>.</li>\n\n\n\n<li><a href=\"https://www.hodinkee.com/articles/in-loving-memory-of-om-malik-friend-writer-venture-capitalist-and-ever-the-believer\">Ben Clymer on Hodinkee</a>. &#8220;Om changed my life. He did it in many ways, often slowly and with subtlety, always with kindness and eminent belief in me.&#8221;</li>\n\n\n\n<li><a href=\"https://runtimewire.com/article/om-malik-taught-silicon-valley-to-read-itself\">Ryan Merket on RuntimeWire</a>.</li>\n\n\n\n<li>Om introduced <a href=\"https://krutal.blog/2026/06/26/om/\">Krutal Desai as his son</a>. &#8220;He had a rare gift of seeing 20 steps ahead while explaining things with remarkable simplicity. He gave wisdom freely, never seeking credit, only wanting to help others succeed.&#8221;</li>\n\n\n\n<li><a href=\"https://susanhobbs.blog/2026/06/27/the-gravity-of-om/\">Susan Hobbs</a>. &#8220;He was a teddy bear to those fortunate enough to know him.<br />[&#8230;] Om created gravity. He was someone you wanted to be around.&#8221;</li>\n\n\n\n<li><a href=\"https://pradeep.md/2026/06/25/om.html\">Pradeep Elankumaran</a>.</li>\n\n\n\n<li><a href=\"https://blog.naveen.com/2026/06/om-2/\">Naveen Selvadurai</a>.</li>\n\n\n\n<li><a href=\"https://explorers.com/my-friend-om/\">Christopher Michel</a>.</li>\n\n\n\n<li><a href=\"https://x.com/jgheller/status/2070267958891524448\">Jonathan Gheller</a>.</li>\n\n\n\n<li><a href=\"https://x.com/mamoonha/status/2070255545643364515\">Mamoon Hamid</a>.</li>\n\n\n\n<li><a href=\"https://boingboing.net/2026/06/25/om-malik-1966-2026.html\">Rob Beschizza on Boing Boing</a>.</li>\n\n\n\n<li><a href=\"https://www.airsugar.com/p/om-malik-1966-to-2026\">Brian Sugar</a>.</li>\n\n\n\n<li><a href=\"https://hugo.blog/2026/06/25/r-i-p-om-malik-%f0%9f%96%a4/\">Hugo Barra</a> on how Om got him to write.</li>\n\n\n\n<li><a href=\"https://everwas.com/2026/06/om/\">Ian Kennedy</a>, also with some great quotes.</li>\n\n\n\n<li><a href=\"https://toni.org/2026/06/25/om-malik/\">Toni Schneider</a>. &#8220;Om was a wonderful person, artistic soul, and original thinker. He was always curious, generous, and warm-hearted.&#8221;</li>\n\n\n\n<li><a href=\"https://seanbonner.com/2026/06/29/death-and-what-we-leave-behind/\">Sean Bonner</a>. &#8220;[H]is feedback and criticism could be sharp – but it was always with the hope that things could be better.&#8221;</li>\n\n\n\n<li><a href=\"https://battellemedia.com/archives/2026/06/remembering-om-malik\">John Battelle</a>. &#8220;Om quickly decided his integrity was more important than the ad dollars he was making with Federated&#8221;</li>\n\n\n\n<li><a href=\"https://winnielim.org/journal/om/\">Winnie Lim</a>. &#8220;Om was one of the very few people in this world I can have an intense conversation about form and content with.&#8221;</li>\n\n\n\n<li><a href=\"https://glass.photo/highlights/remembering-om\">Glass.photo</a>. &#8220;It’s not lost on us that <a href=\"https://glass.photo/om\">Om’s photography</a>, often taken in frozen lands in or around the arctic circle, was the polar opposite of his personality.&#8221;</li>\n\n\n\n<li><a href=\"https://spyglass.org/om/\">M.G. Siegler</a>. &#8220;The true natural born blogger.&#8221;</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">I know I&#8217;m missing a ton, I&#8217;ll update the above. I also added a <a href=\"https://ma.tt/2026/06/om-forever/\">few more vignettes and pictures to the last post</a>.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-153374\" height=\"453\" src=\"https://i0.wp.com/ma.tt/files/2026/06/IMG_0420-1024x768.jpg?resize=604%2C453&#038;quality=89&#038;ssl=1\" width=\"604\" /></figure>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 27 Jun 2026 16:34:31 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:21;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:73:\"Open Channels FM: Why “It’s Dead” Says More About You Than the Tool\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555736\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://openchannels.fm/pop-the-email-is-dead-bubble/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:143:\"Email isn’t dead. Sure, email marketing might not work for everyone, but it’s still crucial for many businesses and personal communication.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 26 Jun 2026 09:08:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:22;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:26:\"Matt: All Roads Lead to Om\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153320\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2026/06/om-forever/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:7253:\"<p class=\"wp-block-paragraph\">Yesterday, my best friend and brother from another mother, Om Malik, <a href=\"https://om.co/2026/06/24/1966-2026/\">passed away</a>. </p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">They say that blood is thicker than water, and what we had was way thicker than blood. — Bob Weir</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">Om&#8217;s request was for a small family prayer ceremony. In mourning, that will be all there is. In celebration and tribute, I love that everyone is <a href=\"https://www.techmeme.com/260625/p50#a260625p50\">sharing their Om stories online</a>, like the <a href=\"https://explorers.com/my-friend-om/\">writing and photography Christopher Michel shared</a>, which very much embody the OG spirit of blogging that Om pioneered.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h2 class=\"wp-block-heading\">A Renaissance Man</h2>\n\n\n\n<p class=\"wp-block-paragraph\">I knew Om contained multitudes, but sitting by his side these last few weeks, I&#8217;ve been amazed to learn how many deep and completely separate communities he was part of. He meant so much to so many, in so many different ways.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Om loved putting on a good conference, and I&#8217;d like to celebrate his life with an awesome event on September 29, 2026 (his 60th) in San Francisco, like an <strong>OmFest</strong>. (Update: <a href=\"https://docs.google.com/forms/d/e/1FAIpQLScyY9c5MowPFW6BmIitqaaF3T-ykM_d8eD2pq2XqwSt7N50zg/viewform?usp=header\">Sign up here</a>!) I&#8217;ll find a space where every community from the many facets of Om can come together. In the spirit of Open Source and co-creation, we can have some booths, flash talks, a gallery of his photography, pen showcase, and whatever other fun ideas people want to contribute. I can&#8217;t wait for the beautiful collision of his tech / journalism / Indian party planner / pen / coffee / shoes / photography circles, and probably some niches I couldn&#8217;t even imagine.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<h2 class=\"wp-block-heading\">A Few Vignettes</h2>\n\n\n\n<p class=\"wp-block-paragraph\">I have so much to say about Om, but right now I&#8217;m working on <a href=\"https://om.co/2026/06/24/1966-2026/\">moderating comments</a> and keeping his website tip-top, so here are a few snippets:</p>\n\n\n\n<p class=\"wp-block-paragraph\">Fundamentally, Om was a lover of humanity. He became a fast &#8220;regular&#8221; everywhere he went. He wouldn&#8217;t just buy coffee, he would also learn the name and story of every barista, the dogs and people in South Park. His deep curiosity and respect weren&#8217;t just for the fine and famous. It extended to every soul that crossed his path. His encyclopedic knowledge and photographic memory created connections not just in San Francisco, but all around the world wherever we traveled. (I need to pull the stats, but we went to five continents together, including Antarctica.)</p>\n\n\n\n<p class=\"wp-block-paragraph\">He loved people and their stories. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">Om and I were an odd couple. We met online through forums and email because Om was one of the earliest adopters of WordPress. We finally met in person in 2004 when I was 20 and he was 38. He connected me to the first investors I ever spoke to, Phil Black, who formed True Ventures, and Tony Conrad, and introduced me to Toni Schneider, my business soul mate, who became like a co-founder as the CEO of Automattic in our first 8 years.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And of course on the internet. I don&#8217;t know how we would count, but I would guess Om read at least 1 or 2% of the whole thing.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">Om was a voracious learner. I was there when he first used chopsticks, and only a few months later, he knew every sushi restaurant in San Francisco and exactly what he liked at each.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">Om is probably in the top ten in the world for finding things incredibly early. That&#8217;s why he has the best usernames! How does one guy get the @om username on WordPress.com in 2005 (user ID 719), <a href=\"https://x.com/om\">Twitter in 2006</a>, <a href=\"https://www.instagram.com/om\">Instagram in 2010</a>? The first WordPress meetup was at <a href=\"https://www.chaatcornersf.com/\">Chaat Cafe (now Corner)</a> in 2005, <a href=\"https://ma.tt/2005/01/meetup-aftermath/\">8 people showed up, and Om was one of them</a>.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">One of the biggest lessons I learned from Om is the deep appreciation of craft. When he took an interest in photography or pens, he would somehow find his way to the most obscure, highest-quality expression of that form. &#8220;What Would Om Want?&#8221; is a question I will always ponder. I want to craft products that would make Om proud.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">Om&#8217;s last word was &#8220;love.&#8221;</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-153336\" height=\"402\" src=\"https://i0.wp.com/ma.tt/files/2026/06/MCM_9460-1024x681.jpg?resize=604%2C402&#038;quality=89&#038;ssl=1\" width=\"604\" /><figcaption class=\"wp-element-caption\">In a jitney on our trip to India in 2009</figcaption></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-153338\" height=\"402\" src=\"https://i0.wp.com/ma.tt/files/2026/06/om-citizen-1024x681.jpg?resize=604%2C402&#038;quality=89&#038;ssl=1\" width=\"604\" /><figcaption class=\"wp-element-caption\">The day Om became a US citizen </figcaption></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-153340\" height=\"402\" src=\"https://i0.wp.com/ma.tt/files/2026/06/MAT_2822-1024x681.jpg?resize=604%2C402&#038;quality=89&#038;ssl=1\" width=\"604\" /><figcaption class=\"wp-element-caption\">In NYC with the True crew, 2008</figcaption></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-153342\" height=\"403\" src=\"https://i0.wp.com/ma.tt/files/2026/06/MCM_0056-1024x683.jpeg?resize=604%2C403&#038;quality=89&#038;ssl=1\" width=\"604\" /><figcaption class=\"wp-element-caption\">Matching dyed blonde hair, 2016</figcaption></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-153345\" height=\"805\" src=\"https://i0.wp.com/ma.tt/files/2026/06/IMG_0284-768x1024.jpg?resize=604%2C805&#038;quality=89&#038;ssl=1\" width=\"604\" /><figcaption class=\"wp-element-caption\">With a golden heart, 2025</figcaption></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Nothing Gold Can Stay, by Robert Frost</h2>\n\n\n\n<pre class=\"wp-block-verse\">Nature’s first green is gold,<br />Her hardest hue to hold.<br />Her early leaf’s a flower;<br />But only so an hour.<br />Then leaf subsides to leaf.<br />So Eden sank to grief,<br />So dawn goes down to day.<br />Nothing gold can stay.</pre>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 26 Jun 2026 03:02:51 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:23;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:71:\"Open Channels FM: The Rise of Messaging as the Universal Tech Interface\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555622\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://openchannels.fm/the-rise-of-messaging-as-the-universal-tech-interface/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:246:\"Messaging is emerging as the universal interface for interacting with technology, simplifying complex tasks into straightforward communications akin to texting, thereby enhancing productivity and reducing technical barriers in digital engagement.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 25 Jun 2026 12:11:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:24;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:113:\"WPTavern: #222 – Destiny Kanno, Anand Upadhyay, Maciej Pilarski on How WordPress Education Programs Are Growing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=204958\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:125:\"https://wptavern.com/podcast/222-destiny-kanno-anand-upadhyay-maciej-pilarski-on-how-wordpress-education-programs-are-growing\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:80884:\"<details>Transcript<div>\n<p class=\"wp-block-paragraph\">[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Jukebox is a podcast which is dedicated to all things WordPress. The people, the events, the plugins, the blocks, the themes, and in this case, how WordPress education programs are growing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox, and use the form there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So on the podcast today, we are joined by three WordPress Education Initiative leaders, Destiny Kanno, Anand Upadhyay and Maciej Pilarski.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Together, they have spent years at the heart of WordPress training and outreach, working in roles spanning community education management, plugin development, and credit program administration. Their efforts have helped shape student engagement and university partnerships across the globe, introducing thousands of learners to WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The conversation focused on the current landscape of WordPress education with particular attention to three key initiatives, the WordPress Credits Program, Campus Connect, and Student Clubs.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Each initiative is designed to provide unique entry points for students of all ages and education levels. From high schoolers building their first site in a library to university students earning official credits for open source contributions.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We discussed the different approaches these programmes take. WP Credits ties student work directly to academic credit and mentorship. Campus Connect provides flexible, community driven, events in diverse locations and Student Clubs foster sustainable, peer led, learning within schools and other institutions. We explore how these models feed into each other, building a sustainable ecosystem for ongoing growth in the WordPress community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We also get into the importance of repeat campus partnerships, the need for scalable facilitator training, and the role of recognition, certificates, badges, and public showcases in keeping students motivated and validated in their journey.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re curious about the growing movement to bring WordPress knowledge to the next generation, or are looking to get involved with education in your local community, this episode is for you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so without further delay, I bring you Destiny Kanno, Anand Upadhyay and Maciej Pilarski.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I am joined on the podcast by Destiny Kanno, by Anand Upadhyay and Maciej Pilarski. Hello, one and all. Nice to have you with us.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:29] <strong>Destiny Kanno:</strong> Hello. Thank you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:30] <strong>Anand Upadhyay:</strong> Hello.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:31] <strong>Maciej Pilarski:</strong> Hello.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:32] <strong>Nathan Wrigley:</strong> So a few months ago, back in, I think it was September 2025, I was joined by two of the three participants on the call today. I was joined by Destiny and I was joined by Anand. We were also joined at that point by Isotta, but she&#8217;s not on the call today. We&#8217;ve obviously got a wonderful replacement, Maciej who&#8217;s going to do a fabulous job explaining the bits and pieces here.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But the intention of that episode, which you can find on the WP Tavern website, it&#8217;s episode number 183, was to find out about all of the overlapping education initiatives in the WordPress space. And it was born, I think, largely out of a sense of curiosity on my part, but also a somewhat sense of confusion, because there were lots of things which were going on. Some of them seemed to be slightly overlapping. There was a conflict of names in some cases. So that episode was laying out the groundworks of what has been happening in the WordPress space.</p>\n\n\n\n<p class=\"wp-block-paragraph\">When that conversation finished and we&#8217;d click the stop record button, I said, that was absolutely fascinating. This seems to be moving at such a rate, wouldn&#8217;t it be good to revisit this whole subject in about six months time?</p>\n\n\n\n<p class=\"wp-block-paragraph\">Well, we missed that target, but here we are, maybe eight months later. I think my intuition at that point was correct, because being a close observer of what&#8217;s going on in the WordPress community, I think it&#8217;s fair to say that the educational space has been somewhat turbocharged during the last eight months.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so today&#8217;s episode, with the help of the three people I&#8217;ve just mentioned, is to describe what&#8217;s going on, what&#8217;s changed, maybe some things that have been mothballed, but certainly a lot of things that are new and interesting and have gained a lot of momentum.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But I think, dear listener, the intention of this episode is to get you involved. Is to get to the end of this episode and for your curiosity to have been turned into action. To have gotten you out of your chair, written an email, turned up to an event, helped organise a thing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So please have that in the back of your mind. If you&#8217;re sitting listening to this in a car, at your desktop, there is actual action that could be taken at the end of this. I think the intention of all four of us on this panel would be dearly for that to happen.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Okay, let&#8217;s establish the credentials of the people that we&#8217;re going to be talking to today. So we&#8217;ll just do a little potted bio of you one at a time. So we&#8217;ll begin with Destiny, if you could just tell us a little bit about you, your relationship with education in the WordPress space, I suppose would be apropos.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:01] <strong>Destiny Kanno:</strong> Yeah, absolutely. So again, Destiny Kanno. I&#8217;m currently working as an education program manager sponsored by Automattic. And I work directly with the Make WordPress Community Team. And I also work adjacently with the training team as well, because education training materials, they go pretty hand in hand. And I&#8217;ve been doing this now for about four years and, yeah, it&#8217;s just evolved since my original time working on Learn WordPress, and that relaunch that happened, to now, yeah, these wonderful programs that are spreading like wildfire as you said.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:37] <strong>Nathan Wrigley:</strong> Fantastic. Thank you so much. Okay, we&#8217;ll move over to Anand for the same sort of introductory moment.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:06:43] <strong>Anand Upadhyay:</strong> Yes. So my name is Anand Upadhyay, and I run the WordPress plugin development company, WPVibes. Apart from that, I&#8217;m very much involved in the WordPress community and I contribute in multiple ways. It can be documentation, it can be Core, Polyglots. But I&#8217;m also keenly involved in the community part, and specifically I can say with the education initiatives, I started with WP Campus Connect in WordPress Campus Connect in 2024. And since then, after that we started joining hands with Destiny and we started evolving this program in a much bigger shape. So that&#8217;s it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:07:16] <strong>Nathan Wrigley:</strong> Okay. Thank you so much. And last, but by no means least, Maciej.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:07:20] <strong>Maciej Pilarski:</strong> Yeah. Thanks for having me. My name is Maciej Pilarski. So I&#8217;ve been doing anything related to WordPress pretty much since 2007, so that&#8217;s been a while. But the biggest breakthrough for me was 2014 when I actually volunteered to WordCamp Europe in Sovia, Bulgaria. That opened my eyes to the whole community, everything that is happening around WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And since then, pretty much I&#8217;ve been working for multiple companies from the WordPress ecosystem. I joined Automattic in 2016. For many years I&#8217;ve been a Happiness Engineer, and since October last year, I&#8217;ve joined Isotta as one of the admins of the WordPress Credit program. And since that time, I will have been helping her out to grow that initiative.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And Destiny mentioned, it spreads like fire because at that time we had six universities onboarded, now we are at 21. The 21st, we got it after WordCamp Asia actually through a connection made there. And it&#8217;s our first institution from Africa, from Uganda. A huge shout out to Stephen Dumba, who I connected with during the event. And after that, pretty much a week after we signed our first partnership from Africa. So we&#8217;re actively growing and getting new institutions on board.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:08:42] <strong>Nathan Wrigley:</strong> Thank you so much. Gosh, there was an awful lot in there, wasn&#8217;t there? That was really interesting. We&#8217;ll try and unpack quite a lot of that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Firstly, a sort of slightly personal message from me. I don&#8217;t usually reveal much about myself on this podcast. I take the position that I&#8217;m a, kind of like an interested party, but don&#8217;t really give much of my own thoughts. However, this is different because I cannot think of a more interesting, meaningful, moral, let&#8217;s go with that word as well, use of time than educating people. It simply is the most profoundly useful thing to do with your life.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Now, obviously people will have different opinions about that, but the juxtaposition of free open source software, in this case WordPress, and education is a real sweet spot for me. I just think that is such an amazing thing to be involved in, to have going on in the background.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you think about it, an open source project, like how many open source projects have this level of stuff going on in the education space, this real international footprint. Things going on which we&#8217;ll find out about in a minute. It&#8217;s really fascinating.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I am sure that the listenership to this podcast, the vast majority of people listening will never have encountered much of this before. Maybe they&#8217;ve seen stuff on Learn because they want to technically learn about WordPress in an online capacity, but we&#8217;re going to be delving into real world events affecting real adults, real youngsters.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so anyway, that&#8217;s my little bit at the beginning, just how curious it is that the project is so big that we&#8217;ve got this international footprint of education. And so I suppose what we should do right at the beginning is lay out the different initiatives and just name them, and try to figure out how they differ from each other. Just so that we&#8217;ve got some kind of awareness.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So I don&#8217;t know which one of you wants to take that, but if maybe you take one each or something, I don&#8217;t know. If we just want to lay out the, just erect that tent basically so that we know what the initiatives are called, and how they differ from one another. So I&#8217;ll open that up. Whoever wants to step in.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:10:48] <strong>Maciej Pilarski:</strong> I can start with the Credits Program. So the Credits Program is based, it&#8217;s a contribution based program, internship, initiative by the WordPress Foundation that connects higher education students with the global open source community. So basically it&#8217;s an opportunity for the students as part of the educational curriculum to contribute to the WordPress community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There are two types of courses that the students can do. One of them is 50 hours, the second one is 150 hours. Usually the students do that during a full academic semester. And as part of that, students are first onboarded into the WordPress ecosystem and the wider open source ecosystem where they learn not only about WordPress, but open source as a whole, and how crucial it is for the internet.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Then the second phase is picking the contribution area to which they would like to contribute. All the contributions areas basically are the ones that are listed at make.wordpress.org. So any team that is listed there, students can pick from that area. During that phase, they work on a particular area that they have selected.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And finally, during phase three, they wrap up the whole achievements, the contribution, what they did, they publish a final post. And what is also very important as part of the credit scores, students have also assigned a mentor from the WordPress community that guides them through the whole process. We don&#8217;t leave them alone. We connect them with actual mentors from the WordPress community that are vetted by us, that guide them through the whole journey into the contribution and the whole WordPress ecosystem.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So it works on multiple levels. For me, this connection is also special because it builds this bridge between the previous generation of WordPress contributors to the new one where they are introduced and can start working on any fields of contribution.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What is also important is that this is not limited to technical universities. Pretty much any type of university can participate in the program. The first university that we started with was University of Pisa, and it was the humanity studies. So the students from humanity field were the first group who started the Credits Program. There&#8217;s room for pretty much anyone from any field.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:18] <strong>Nathan Wrigley:</strong> Okay. There&#8217;s a lot there. Wow. I&#8217;ve just been taking notes and I&#8217;ve almost filled an entire A4 page. So WP Credits, the WordPress Credits Program, I guess the name sort of gives it away. The idea here is that you trade time for university or higher education credit. So credit being, I suppose if you were to atomise your three year degree, you might do, I don&#8217;t know, 12 modules or something like that. The idea is that one of those modules, perhaps it&#8217;s more, becomes something in the WordPress, but also curiously the free open source software space as well. I didn&#8217;t actually know that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The idea is that you link up with real world institutions. So the first one was Pisa, and maybe we can get into which other ones have come along. And in exchange for 50 hours or 150 hours, you will be given that credit, which can then go to the overall awarding of a degree or whatever it is that you are hoping to get.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You&#8217;re then linked up with team members, WordPress community team members who will mentor you and shepherd you through this process. And the idea is that it culminates, I think you said in a final post, which I suppose in a sense is a bit like a dissertation or something like that, you sum up all the different bits and pieces. Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:14:29] <strong>Maciej Pilarski:</strong> Once that happens, the students also receives an official certificate from the WordPress Foundation, signed by Matt himself, that certifies that they completed the course. And what is also important to know, the whole progress through the course and what they did during the course, it&#8217;s also stored on the wordpress.org profile. So any contributions that they did, for example, photos that they&#8217;ve uploaded, this all will be visible on the wordpress.org profile. And they also receive a special badge dedicated to students who graduated from that program.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So it really gets them started into the WordPress ecosystem, and at the same time creates something like a small portfolio for any future company that would like to, for example, hire them. Because they have a proven history of contributing to the ecosystem.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:15:20] <strong>Nathan Wrigley:</strong> Okay, so that&#8217;s an interesting quid pro quo, isn&#8217;t it? So the idea is you do all this work, which on the face of it, I suppose looks very philanthropic, you know, you&#8217;re giving up your time, but you get a real thing at the back end of it. You get a certificate. You can then presumably apply for jobs and indicate, okay, I&#8217;ve done this, I&#8217;ve contributed in this meaningful way.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What I think is really interesting there, and it kind of gets lost, I&#8217;ve worked in education in the past and I know the red tape that&#8217;s involved in doing anything in the education space. There is so much red tape. And I can only imagine what&#8217;s happened in the background to enable these kind of things. You know, the back and forth, the tennis of emails that go on and on and the proof that&#8217;s required to categorically show that this thing that we are doing is worth something. You know, it&#8217;s not just this Mickey Mouse. We use that expression, Mickey Mouse kind of qualification that really, it doesn&#8217;t actually require any hard work. It&#8217;s just there, nothing really in it, but you get an accreditation anyway.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I can only imagine the hard work that has gone in every single time you touch a new institution, trying to convince them that this is legitimate, that this is real. You&#8217;ve just kind of glossed over all of that by just describing what is in existence, not necessarily what has gone on to make it happen. I know that there&#8217;s probably more than the three of you involved in this, but my profound thanks for all of that hard work, which presumably is utterly and completely invisible. And I can only imagine what&#8217;s going on there. So yeah, thank you for all of that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:16:54] <strong>Maciej Pilarski:</strong> Thank you for that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:16:54] <strong>Nathan Wrigley:</strong> So that was WP Credits. So that was one wing of the things that we&#8217;re going to discuss today. Should we move on to another one and maybe somebody else wants to take the helm?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:17:03] <strong>Anand Upadhyay:</strong> I think Destiny can take Campus Connect and then I will take Student Clubs.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:17:06] <strong>Nathan Wrigley:</strong> Okay. Destiny, let&#8217;s move over to you and see what you can tell us about something different.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:17:11] <strong>Destiny Kanno:</strong> Yeah, so I&#8217;d love to tell you more about WordPress Campus Connect. And the way we ended with WordPress Credits, I think is also very critical to the story of Campus Connect because, you know, it started with Campus Connect first, and that&#8217;s how organisers such as Anand and Pooja like were able to get those connections with the universities through being boots on the ground, you know, having those relationships. Proving through action that these activities that we&#8217;re doing with the students are having real impact and are showing real results.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Slowly building up these kind of case studies in a way has helped open a lot of doors, especially with Campus Connect now, we&#8217;ve done a lot of events, especially since we last talked. Like I think this year alone, we&#8217;ve already had 22 Campus Connect events. So, like it&#8217;s not even half the year and it&#8217;s quickly becoming one of the biggest run events, WordPress official series.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But these events are like a way of opening the door, right? Hey, here&#8217;s a free learning opportunity for your students. And as you said, like the red tape is there. A lot of institutions are like, wait, so what&#8217;s in it for you? Why is, there&#8217;s a little bit of dubiousness sometimes in the reaction, right? You&#8217;re going to give your time to educate our students, why? But once they see, it&#8217;s like, no, we really are just passionate about spreading WordPress, showing students what&#8217;s capable with their website, how it applies to different skillsets as well. Like it&#8217;s not just for coders, it is for marketers, it is for designers.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You know, there&#8217;s so many career opportunities that once we just get the foot in the door and we&#8217;re able to showcase that, a lot of institutions are like, okay, now I get it. I do want to highlight in Anand&#8217;s case, like they&#8217;re going to have their third WordPress Campus Connect in Ajmer this year. You&#8217;ve got repeat institutions. I&#8217;ve heard you also have institutions that are like, when are you going to come to our place and teach WordPress? You know, once the fire is lit and people see how bright and shiny it is, like people want to get involved.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But as you said, like getting it to click for people, that is like the most difficult part. And I&#8217;ll give an example of, right now in Japan, we had our first WordPress Campus Connect event on the 9th of May. So I&#8217;m like, woo hoo. Like it finally happened. But we have this community in Japan that is like very passionate, very active. So when I first was like introducing the concept of Campus Connect, people were like, okay, but like how do we do this? What&#8217;s it about? It takes like a lot of presentations, a lot of going to people in person and talking. Helping them even shape the conversation that they&#8217;re going to have with the institution to sell this amazing gift of WordPress on their campus.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And after this one on the ninth, like now we have a case study in Japan that others can now use to be a starting point for those conversations going forward. So I think, once you have that one step, the gate just slowly opens until it&#8217;s just, the doors bang open in each way. But yeah, we&#8217;ve seen really great success with Campus Connect and it&#8217;s just like honestly, it just keeps growing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:30] <strong>Nathan Wrigley:</strong> Can I just ask a quick question? So I just want to draw a very clear line for everybody that&#8217;s listening to this, what the difference may be between Campus Connect and WP Credits. Because from the description that we&#8217;ve had so far, it may be that you&#8217;ve fallen into the trap of thinking, well, they sound like they might be the same thing. So could you just, Destiny, just tease out where Campus Connect differs? Maybe in the nature of the event, the timing of the event, the availability, the age group, those kind of things that separate WP Credits from the Campus Connect initiative.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:21:02] <strong>Destiny Kanno:</strong> Yeah. Thank you, that&#8217;s like a really great distinction to make. So whereas WordPress Credits is geared toward higher education, Campus Connect is geared toward, honestly any level of students as long as they&#8217;re able to browse the web safely, and enjoy and participate.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that means, Elementary school students now are pretty good at devices. High school students, college students, vocational students. We honestly kept the door pretty open in terms of what a campus means. We&#8217;ve even had a Campus Connect event in Uganda in a library, the Lira Public Library because students were able to go there right?</p>\n\n\n\n<p class=\"wp-block-paragraph\">We were trying to make it as barrier free for students wherever their campus is. And so that&#8217;s, I think, the main difference. It&#8217;s more wide ranging in terms of who can participate as a student. And then also the fact that it could be a one-off event, so a one day event. A lot nowadays are multiple day events, they&#8217;ll maybe go two times out of a month, or a couple days consecutively. And then after that it&#8217;s up to really the organisers in the institution whether or not we have another addition on their campus the same year, or the next year.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:15] <strong>Nathan Wrigley:</strong> I&#8217;m going to tease out a few things. I just want to point out to, me as an English person, that is to say, not an English speaker, but somebody from England, campus has a really defined definition, and it&#8217;s usually bound to a university. Whereas it sounds like the description here, campus literally means the place where education happens, not it&#8217;s 18 years old and older, you know, people doing degrees, bachelors and PhDs and that kind of thing. Basically, if there&#8217;s an institution somewhere, that&#8217;s what the campus is in this case. Okay.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So the WP Credits program sounds like you forge your relationship with the university, and correct me if I&#8217;m wrong, it sounds like it takes place inside that institution, and it&#8217;s part of that program and what have you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The Campus Connect initiative is much more ad hoc. It could be a one-off, it could be monthly, it could be inside a library, it could be inside the school, it could be an inside an institution. It feels a bit more like, I don&#8217;t know, a WordPress Meetup, but geared towards a younger audience or something like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And the minimum age requirement is really driven by your capacity to type on a keyboard and hold a mouse and those kind of things. And that&#8217;s kind of curious to me because I think my educational experience was always younger children. It&#8217;s really interesting how patterns are laid down at a very, very early age. Patterns that go on into much later life get laid down, typically at incredibly young ages. So this is fascinating for digging into that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And it&#8217;s not just about, say, the code, it sounds like code is on the menu, but it could be about marketing, it could be about design. Basically the gamut of anything online, CMSy, those kind of things. Okay, is there anything you want to add? Did I misunderstand anything there, or misstate anything there?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:02] <strong>Destiny Kanno:</strong> No, I think you&#8217;re completely right. We&#8217;re trying to convey that WordPress isn&#8217;t just a blogging software that I think is still a lot of people have a mentality of. Like there are many ways to utilise it that goes beyond that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And one thing I did want to add are a couple numbers. So since WordPress Campus Connect became official in May of 2025, an official WordPress event series, I should say, we&#8217;ve had 42 completed events, with 71 participating institutions, and over 5,500 students have been reached.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:37] <strong>Nathan Wrigley:</strong> That&#8217;s something else. 42 events, 71 institutions, and I think you said five and a half thousand individuals. Good grief. I don&#8217;t know what the measure of success is for this, but that feels like success to me.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I mean, imagine turning up to a WordCamp, like a flagship WordCamp and five and a half thousand people descending on you. You&#8217;d feel slightly overwhelmed. That&#8217;s a lot, isn&#8217;t it? Gosh, that&#8217;s pretty remarkable. Wow. Congratulations.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:05] <strong>Destiny Kanno:</strong> And the majority, the outcome, the students make a website. So we could almost count those students as also new WordPress websites that are live now on the web. So within a year, organisers around the world have been able to make that happen.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:19] <strong>Nathan Wrigley:</strong> Could I just perhaps draw another distinction as well, just very quickly, because it sounds like the WordPress Credit system, because it&#8217;s binding itself to institutions, it sounds like there might be more paperwork going on there, and maybe more high level meetings that need to take place. Whereas Campus Connect feels much more community driven. It&#8217;s the kind of thing that, quite literally, anybody listening to this podcast with a fair wind could have one of those going in a handful of months. If they&#8217;ve got the right initiative and they can find the audience for that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Again, is that about right? There&#8217;s sort of more opportunity to become involved with the Campus Connect initiatives. You don&#8217;t need to have that academic background or have a point of contact at a university. You basically just need a building, some interest and a bunch of students.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:02] <strong>Destiny Kanno:</strong> Yeah, the key thing is, you know, having a real connection to the campus that you&#8217;re going to present at. But you&#8217;re exactly right. We tried really hard to lower the barrier to organise these events. Because I don&#8217;t know if you&#8217;ve organised a WordPress event before, there&#8217;s kind of a lot of hoops you have to jump through. And we&#8217;re like, okay, how can we think about this in a different way?</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I think that also has positive repercussions for how we organise other events too, that are, changes are being thought about too so that we can enable people and empower them to put these events, instead of bogging them down and process and a little bit of bureaucracy to say.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:38] <strong>Nathan Wrigley:</strong> So what&#8217;s really curious about that as well is we&#8217;re all in different parts of the world, aren&#8217;t we? People on the call today are in Japan and I&#8217;m in Europe and, Anand, are you in India? I think.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:47] <strong>Anand Upadhyay:</strong> Yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:47] <strong>Nathan Wrigley:</strong> Yeah. Each of those events, I guess would look quite different. The kind of nature of the attendees, the nature of the kind of building it might be in, the institution. And it really is, you just grab what&#8217;s around you I suppose, and work with that. If you&#8217;ve got a connection to an institution, you can go for it. Maciej, I feel like I crosstalked you. I think you wanted to say quite a few times and I&#8217;ve just interrupted. I&#8217;m very sorry.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:27:08] <strong>Maciej Pilarski:</strong> No worries about that. So I wanted to add that those initiatives set backgrounds for each other. Because in some uni institutions, the interest sparks with a Campus Connect event, and that gets the institution interested in those initiatives, which sets background for WordCamp Credit.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And it happens also the other way around, where we start with an institution that starts credits and then we get the students interested in WordPress in general, the community, which leads to a Campus Connect event during the Credits Program. What is important is that those initiatives don&#8217;t compete with each other. They support each other.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:27:51] <strong>Nathan Wrigley:</strong> Right, so there&#8217;s a lovely virtuous cycle there, isn&#8217;t there? Where the two things can be going on in harmony, one promoting the other and they&#8217;re definitely not in competition. Okay. That&#8217;s really interesting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">One final question on Campus Connect, and I&#8217;ll direct this at Destiny, just because she&#8217;s been handling that. With the WP Credits thing, there is this moment where you hold the certificate in your hand and you go, yay, did it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Is the same thing true of Campus Connect or is it more of a show up to the one event, you know that you did that, that was great, you can file that away in your own head as a thing? Or is there some sort of accreditation, or certificate giving, or badge giving, or profile updating that might go on on wordpress.org? Is there any sort of thing that the attendees receive, and I suppose that the people that are organising might receive as well?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:37] <strong>Destiny Kanno:</strong> Yes. So we do have a certificate of participation that students can receive signed by WordPress Foundation Executive Director, Mary Hubbard. And that just needs to be requested by the organisers ahead of time, because we need to get the signature and all that. So yes, they can come away with that. And we&#8217;ve heard really positive things about that, like it motivates them. They&#8217;re like, yeah, I did something, which they did.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:29:01] <strong>Nathan Wrigley:</strong> There we go. That was WP Credits and WP Campus Connect.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Can I just say at this point, dear listener, if at this point you&#8217;re thinking hang on a minute, there&#8217;s a lot going on here, don&#8217;t worry, there&#8217;ll be show notes. If you go to the WP Tavern website, there&#8217;ll be show notes. I&#8217;ll try to list out as many sensible links to get you to the root of each one of these initiatives, so that you can begin your journey and fan out from there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;m not sure what episode number this will be, but if you just go and search for, oh, I don&#8217;t know, Destiny or Anand or Maciej, you could probably find the episode that way. And all the show notes will contain all of the links.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Right, in which case, I think it might be Anand&#8217;s turn. What have you decided to take on Anand?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:29:39] <strong>Anand Upadhyay:</strong> So I will be sharing my thoughts on the third part of this whole education initiative ecosystem. So that is a Student Club. Just a few minutes before you were giving the analogue of meetup with this Campus Connect. So I would like to share the same analogue with us because we are more accustomed with like other terms of WordCamps and Meetups and contributer days.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress Campus Connect is kind of like a WordCamp happening in the campus, because it&#8217;s like a big day event that holds everything happening, different kind of sessions, maybe workshops happening. So I would compare it with that thing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And same way, credits thing, Credit Program is kind of like ongoing contribution series because more focused on the contribution part because the student devote 150 hours of their program. A lot of period goes to the contribution.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And now the same way we, if we talk about the Student club, it&#8217;s similar to like the Meetups that we have. But these are the in campus meetups for the students and by the students. How do things get started? Like the Campus Connect introduce the WordPress to those campuses and to those students, but since most of the campus, it&#8217;s a once in a year event. So once this event has sparked something about the WordPress in the students. So keeping that momentum going on, that&#8217;s where the Student Clubs come in.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So with the Student Club, it&#8217;s kind of like, as I mentioned, it&#8217;s like an in campus meet program. So a student can gather themselves, they can form a club and a couple of students can be nominated as club organisers, student club organiser from their campus. And then they organise the in-campus events, maybe like once in a month or twice a month, depending on academic calendar. There are a lot of hurdles in doing those things continuously.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But they usually do once or twice a month. They do a kind of a meetup in their campus. The students gathered together. They learn from variable resources available from WordPress. And from those resources, they share with the other students. It&#8217;s kind of a group learning, group study, that we use. Education live, we always do that. It&#8217;s kind of a group study. They&#8217;re learning from themselves. If someone has learned something, they are helping others to learn those things.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So I would just like to give some of the examples from my city. There are multiple Student Clubs are going on. When we went to the campus, we just taught like a small group of students about the WordPress, because we&#8217;d have some limitations of the resources, of the setting arrangement. We cannot call all the students of the campus and, okay, come together and I have a amazing workshop. So we have given the WordPress walk through to the limited number of students.</p>\n\n\n\n<p class=\"wp-block-paragraph\">After that, they form a Student Club in their campus because they got very much interested. Then the first session they did was like, they started teaching to their juniors, like the students who have just entered the campus. They took a session for them. So they told, whatever we have told them, they have taught the same thing to the juniors.</p>\n\n\n\n<p class=\"wp-block-paragraph\">After that, in the next few session, they experimented different things. Like in some session they&#8217;re just doing a fun quiz around WordPress. And in some sessions they are doing a kind of like a, I would say like a hackathon kind of thing. So they are just picking up a website. Or you can, just similar to the speed build challenge that Jamie do. So they have just one website open on the screen and everybody&#8217;s like cloning that website.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So there are different ways students are engaging through those student clubs. So it is helping to keep the momentum going on so that the student keep learning about WordPress and they are also connecting with the community members for the guidance about how they can learn more. What should they learn next if they are sharing their experience. Like we have covered these things and, what should we go next?</p>\n\n\n\n<p class=\"wp-block-paragraph\">And in the recent WordCamp Asia, they&#8217;re also one of the Student Club lead from my city. She joined the event and there are conversation with the, like other community members who has offered them like, okay, we can come to your campus, or we can do, have a webinar for your campus where we can teach you particular subjects, particular topics. Maybe they can talk about SEO, maybe they can talk about plugin development.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So this is also opening the horizon for them, to learn from people across the world. So that is how the Student Clubs are happening. The examples I&#8217;ve gave, again, from my own city because I&#8217;m closely mentoring them, but there&#8217;s similar things are happening across the world.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So it is helping to create a kind of sustainable environment for the long-term sustainable environment in the campus. So the next time when we go to that campus, we are not going to teach like the basics of WordPress, because we want like, the ecosystem should be built within the campus, so every student know about the WordPress. Because last time when we went to the campus, we have to tell everything about WordPress because why you should learn WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So the Student Clubs, my ambition is that, wherever the Student Club is from, next time a Campus Connect event is happening, next time we should not tell them about what is WordPress and why they should learn this thing. There should be already a sustainable ecosystem.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I feel that all these three programs are like very much interconnected. And the real impact of these programs, we will be able to see in the next two or three years. And there will be a regular ongoing activities around WordPress in the campus.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And these are also kind of a balance program as well. Like the Campus Connect is introducing WordPress to the students, Credits Program is motivating them more towards like the contribution part. And I would say that Student Clubs is more inclined towards getting new users to the WordPress. Because if we keep on focusing on the contribution, contribution, but if we discard the like increasing the number of new users, so we are not going to win. We need a balanced state.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The Student Club is trying to, learning how to build website, how to mastering the skills of the WordPress. And later on, many of them are going to join the contribution part as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So this whole ecosystem is built around bringing more people to the contribution, bringing more people to use WordPress, build websites, as in, for the individuals as a business as well. So that&#8217;s how all these three programrs are very much interconnected, and growing together fast.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:16] <strong>Nathan Wrigley:</strong> It feels like, of the three things that we&#8217;ve talked about, so WP Credits, Campus Connect, the Student Club, this final one that you&#8217;ve just covered, it feels like that&#8217;s got a very flat hierarchy to it. In other words, there&#8217;s like this peer learning. So it feels like more or less anybody can show up and demonstrate anything, which might then lead to somebody else thinking, okay, that was interesting, I&#8217;ll take on next month&#8217;s one because I&#8217;ve now seen that&#8217;s doable. Less hierarchy, if you know what I mean? So a much more flat structure.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:45] <strong>Anand Upadhyay:</strong> Because when we started Campus Connect, we also get a lot of attraction in the local community as well. And people join our Meetup groups. But then it becomes difficult for us, how to plan about the topics for our meetup. We have some experienced professionals coming in. We have some students coming in, and we plan the topics that suits the professionals. The student will feel like, okay, what&#8217;s they&#8217;re talking, we are not getting anything in our mind. If we bring the topics, very basic topics and the professionals who are joining the community meetups, they&#8217;ll feel like, okay, these are very basic stuff, why am I coming here?</p>\n\n\n\n<p class=\"wp-block-paragraph\">Student Clubs giving them their own platform, giving them a own opportunity. Okay, these are all the familiar faces. It is also giving the opportunity to come on the stage, come onto the stage and get out of your fear as well. It is also generating leadership qualities in them. Okay, we have to keep this momentum going on and we have to keep the activities going on. So there are a lot of ways, apart from learning WordPress, there are a lot of other ways it is helping the students as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:36:40] <strong>Nathan Wrigley:</strong> When you have to stand up in front of a bunch of people and deliver something, obviously there&#8217;s a whole bunch of us that are just really confident at doing that, quite happy to stand up and do that kind of thing off the bat. But equally, there&#8217;s people for whom that is just the most terrifying experience possible. You know, standing up in front of two or three people, oh boy, you know, anything above that is just off the books.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I was just wondering about that, whether or not there&#8217;s, in this particular style of event, the Student Club, whether there is a growing corpus of, I don&#8217;t know, previously done topics or topic suggestions or slide decks or anything like that, which might enable people to feel that level of confidence? I don&#8217;t know if that&#8217;s something which is being put together. Just resources which enable somebody who doesn&#8217;t have the confidence, let&#8217;s go with that word, who then may gain that confidence. And I&#8217;m going to pass this to Destiny because she&#8217;s waving her hand.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:37:30] <strong>Destiny Kanno:</strong> I was really hoping I could shamelessly plug this project. This is like, you&#8217;ve said the most opportune thing. So I&#8217;m actually developing right now what I&#8217;m like tentatively calling the Meetup Activity Library. It comes with like kits on certain topics. So for example, WordPress Playground was the first one I built. But it comes with the facilitation guide, which is a doc. So the facilitator can read through, understand the steps they&#8217;re going to go through in the activity, how to pace it. And then a presentation deck which they would display, if that&#8217;s available to them, to the folks that they&#8217;re presenting to. And it&#8217;s a hands-on activity only. So it&#8217;s not only presentation. The facilitator of course guides and talks them through things, but then people are getting hands-on experience with that topic along the way.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:38:16] <strong>Nathan Wrigley:</strong> That is a beautiful remover of barriers, because I think just having that little document, that little crutch, you don&#8217;t have to feel that you, okay, I&#8217;ve got to come up with a topic. Not only have I got to come up with a topic, but then I&#8217;ve got to research the topic, deliver the topic. If you can have it all on a thing that you can crib from, I don&#8217;t know, it just arms you with that confidence as you walk in. I think that&#8217;s such a brilliant topic. And, Maciej.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:38:40] <strong>Maciej Pilarski:</strong> Both Destiny and Anand mentioned two keywords, sustainability and facilitator. The goal of also getting all those educational initiatives going is also create in a sustainable way. We&#8217;re not pushing for numbers, but growing them in a smart way where we don&#8217;t get too many students so we get overwhelmed. We need to have enough mentors to accommodate those students, and also enough facilitators to be able to scale the program, to grow it in the future.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And it&#8217;s exactly what Destiny is now doing, the Facilitator Training Program, which gets more people from the educational sectors, community organisers, everyone on board, to jump on those educational initiatives and help us to grow. Because the number of every, all those students involved in participating in those programs is increasing and we need to be able to accommodate them. And through the Facilitator Training Program, this allows us to do that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:39:42] <strong>Nathan Wrigley:</strong> It&#8217;s so interesting in open source software spaces as opposed to corporate spaces. I suppose the metric of success for anything like this in the corporate universe would be how many people showed up and gave us money in exchange for this knowledge or, you know, something akin to that. Basically a metric of humans in a room and money gained. And of course, the measurement of this is so not that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I did wonder, Destiny obviously very proudly rattled off the statistics for Campus Connect, you know, the five and a half thousand attendees and all of that. I wondered if there were success criteria of some kind in the background, which guide you. You know, it&#8217;s not like, okay, well we didn&#8217;t meet that we&#8217;re going to abandon it all. But more, things like you would like to see happen, so aspirational goals. It sounds from what Maciej was saying that maybe the attendance growing slowly over time is some kind of measure of success. Maybe there is none of that, but I&#8217;ll just open that one up to see if you want to take that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:40:38] <strong>Destiny Kanno:</strong> I think one definite measure of success is repeat events on certain campuses. So if the campus is saying, we love that, please come back, or please come again soon. I think that is a really great indicator that, not only did the students get something great out of it, but the school believes in it. And that&#8217;s what we want to do. We want to create these systems that, not only bring people into WordPress, but also continue this cycle of, you know, growth within the community, but also ownership by the institution.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Another measurement of success is the institution is like, okay, great, how do we learn how to do that ourselves? So we have some folks now working in the institution that are organising WordPress Campus Connect events that are helping facilitate these Student Clubs. So the faculty and educators themselves, they&#8217;re directly getting involved. And that for us as community members too, whose volunteer time is quite limited, as Maciej was saying, like it is a great multiplier that makes everything much more sustainable.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:41:45] <strong>Maciej Pilarski:</strong> So from the WordPress Credits perspective, we don&#8217;t hope all the students to turn into contributors. That would be amazing but that might not happen. I can share with you some numbers. So currently we have 450 students globally enrolled. For the whole program so far, 75 graduates.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We hope that some or as many as possible of those graduates who completed the program will stay and become active contributors to the WordPress community, stay engaged.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That&#8217;s one of the goals we are aiming for the Credits Program, to not just get this done, but this is building the next generation of contributors. We know that like we are ageing, we&#8217;re getting older every year. We are not getting younger, unfortunately. Getting those students staying in the community allows us to build those next generations of WordPress contributors that will also have completely different perspectives to how the community functions, how it was built.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What brought us here might not move us forward. So these new students will bring us this new, fresh perspective of how they would like the community to function and move it to the future, to be current, to stay up to date with what&#8217;s happening globally.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:43:00] <strong>Anand Upadhyay:</strong> That&#8217;s why it&#8217;s very difficult to like measure the impact in numbers because how it is impacting in the longer term. But yeah, it&#8217;s going to impact. And I would say also, like Destiny mentioned, one of the metrics is like this campus is willing to have the Campus Connect again and again in the campus.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So I just want to share one more. Like I just recently got a call from one of the faculty coordinators from one of the campus where we have a Student Club. And now they have like two months of vacations. And he called me like, okay, now the vacations are going on, students will not be here, so what can we do for the students to keep their involvement with the WordPress in those two months? So can we do something online? Can we do something like this?</p>\n\n\n\n<p class=\"wp-block-paragraph\">When we get these calls, these kind of communications, that these are interactions that we have, this gives us a sense of like accomplishment. Okay, yeah, we were able to create some kind of interest in the students. Because we cannot expect that if we are going to like any campus and 100 or 200 students are participating in our Campus Connect, they are all going to jump into the WordPress. They are getting a lot of different kind of opportunities as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There are other technologies as well, which are, some students are going into that, some students are going into that. But we are showcasing the WordPress as one of the career opportunities. And they have a choice of multiple options, so they will choose what they do. But yeah, the impact will be seen in the next few years. Just like Maciej said, mentioned that he went to the WordCamp as a volunteer and it&#8217;s bring him into the community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And the same is with me. I attended the WordCamp and just after coming out of the WordCamp, I started the Meetup group in my city. So I got inspired from that. So that is a result of that WordCamp. And that cannot be measured in the numbers. That can only be sensed when we are doing this kind of conversation. Okay, that WordCamp helped me, that WordCamp helped me.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The same way in future, these students who will join the community or the WordPress industry, they will be talking about, okay, I got first introduced about WordPress through a WordPress Campus Connect event or I got introduced to the contribution through WP Credits Program. So when these conversation will be happening in the future, then we will say that those are the real metrics that we are looking for.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:45:00] <strong>Nathan Wrigley:</strong> That&#8217;s really interesting, and I like that. It sounds like there&#8217;s not so much a focus on statistics, you know, literal, brutal numbers, more kind of playing it forwards and measuring the impact over many years, not, you know, a handful of months into the future.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:45:15] <strong>Destiny Kanno:</strong> So yes, we&#8217;re not like, okay, here&#8217;s our KPIs, you know, and here&#8217;s our hard metrics. But one thing I really noticed that our community is, it could be better at doing, is just talking about what happened. Because then you hear all these success stories and there are numbers in that. So like for example, Ajmer again, Women&#8217;s Day event this year. 50% of tickets sold were to students. And that&#8217;s directly because of the involvement in going to these campuses and teaching WordPress. And I&#8217;m like, that&#8217;s amazing, that&#8217;s direct injection of 50% youth into the WordPress community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:45:52] <strong>Anand Upadhyay:</strong> And they sold out so fast.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:45:53] <strong>Destiny Kanno:</strong> And they sold out really fast, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:45:55] <strong>Anand Upadhyay:</strong> The organisers were hoping like, now we have to pitch out to sale our tickets. And they have planned a social media campaign around that. Okay, we will be periodically pitch a student on the social media to encourage the ticket purchase. And within one day, we sold out. And the whole social media campaign was like their whole planning was gone. We don&#8217;t have tickets.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:46:14] <strong>Nathan Wrigley:</strong> It&#8217;s really interesting that there&#8217;s all this success going on, and yet, as Destiny said, it is hard to get that discovered. Maybe it&#8217;s a case of shouting louder about the previous success. Maybe things like this podcast will help in some small way for things like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But I know what you mean. There&#8217;s a lot of people talking about the code, and there&#8217;s a lot of people talking about the plugins and the themes and whether or not we&#8217;re going to get collaborative editing in version 7 or 7.1. All of that seems to suck up all of the oxygen in the room. And yet, without a throughput of, let&#8217;s go for young adults, coming into the WordPress space, there&#8217;s not really a great deal of hope for a project over decades unless we get people of a much younger age beginning now. And I&#8217;ll just hand the torch to Maciej because I think he&#8217;s got something to add.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:47:05] <strong>Maciej Pilarski:</strong> But this is also changing because at WordCamp Asia, we were able to introduce the educational table during the contributor day. And I&#8217;m also organiser of WordCamp Europe that&#8217;s going to happen really soon in two, three weeks, beginning of June. And during WordCamp Europe, we will also have a contributor table, dedicated to education, but for the first time also educational track.</p>\n\n\n\n<p class=\"wp-block-paragraph\">During the second day, we will start the whole day with topics related to education. We will have a discussion panel rethinking learning in WordPress that Mary will be participating. And later in that afternoon, we will have actual students, who take part in the program. Sharing the experience, presenting the results. Not only students from universities, but I&#8217;m also leading a group of high school students who&#8217;ve been working for the whole past semester with a teacher on some projects related to WordPress building websites. So they are super eager and excited to show them.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We will also showcase some students, teachers stories, how both of those sites motivated each other, learn from each other, and basically help us keep growing the community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So WordCamp Europe definitely will feature some of those things. And we&#8217;re slowly introducing more and more those things into those flagship events and into the broader community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:48:28] <strong>Nathan Wrigley:</strong> Really nice. Yeah, that&#8217;s really nice to hear. I think it&#8217;s a difficult circle to square, the idea of making this stuff visible so that everybody&#8217;s aware of it. Even if they&#8217;re only interested in running their agency, or writing code or whatever it is. Maybe to realise that this is some version of the underpinnings of the WordPress community without which the software ultimately doesn&#8217;t exist.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And it is quite curious. I don&#8217;t know if I&#8217;m reading between the lines here, I think I&#8217;m not, but I get the impression that, I&#8217;m going to use the phrase like, I don&#8217;t know, from higher up, let&#8217;s put it that way. It feels like education is taking a more central place. It feels like for example, Mary Hubbard, it feels like you&#8217;ve got a real advocate there. Again, I could be reading between the lines, but it feels like the words coming out of her mouth, I hear the word education coming out of her mouth quite a lot when she&#8217;s on stage.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So it feels like you&#8217;ve got some big hitters, let&#8217;s go with that. I don&#8217;t know if you&#8217;ve got anything you want to add to that, but it feels like the importance of this is more profound this year than it was a few years ago.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:49:33] <strong>Maciej Pilarski:</strong> You are correct. Mary is a big supporter of that and she also created this space for us to grow those initiatives that like allows us to grow that. Isotta started the first Credits Program at the Pisa University as an experiment. And from there it was proven that this actually works. It gets us universities and new contributors.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And then on the other side, there was those Campus Connect events that also organically grew up on their own. So basically there was a need. It feels like there was this hive mind somehow that worked also for all of us. All of us felt this need to introduce those things. It looks like we&#8217;ve reached a certain growth level for the community that we organically felt that that&#8217;s the direction that we should start heading.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:50:24] <strong>Nathan Wrigley:</strong> Yeah. What&#8217;s interesting there as well is that it very much overlaps with maybe a concern. So we&#8217;ve touched on this at various points without saying it out loud quite. If you go to, and I&#8217;m going to exclude WordCamp Asia 2026 from what I&#8217;m about to say, because that event was very different. If you go to a typical WordCamp, the age skews, and I&#8217;m doing air quotes, older. You don&#8217;t typically look around and see a bunch of teenagers.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that&#8217;s a concern. There&#8217;s this, like a pyramid, like a reverse pyramid, and if we don&#8217;t get the younger people coming up, the edifice of this entire project kind of becomes a lot more shaky. And we&#8217;ve lived through 22 plus years of WordPress, and I think quite a lot of those people began, a lot of the people who&#8217;ve been involved in the community began their careers using WordPress and they&#8217;ve kind of moved through WordPress as it&#8217;s evolved over those 22 years.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And not to, I don&#8217;t know quite how to say this. At some point they&#8217;re going to stop contributing. Their age will become something, you know, they want to retire or they want to move on or do some other things. Unless we build the scaffolding and put things in place so that young people feel they&#8217;ve got a place here, feel that, I don&#8217;t know, some proprietary system is not the way they want to go, they want to support the ethic of open source.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Unless these building blocks, these educational building blocks are put in place, then that&#8217;s going to be a bit of a concern. So to your point, Maciej, it organically grew. And what a nice thing that it did kind of organically grow because it&#8217;s sorely needed at the same time. There isn&#8217;t really a question in there. But anyway, there&#8217;s my observation. Anand, did you have something to say? I think you did.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:52:04] <strong>Anand Upadhyay:</strong> Yeah. So just want to add that thing you have raised recently. So the way that we want to teach the students about the open source as well, because if you go to the WP Credit curriculum, so the initial lessons, they learn through the, given to them to learn from the learn.wordpress. So it&#8217;s all about like open source ethics, and how the WordPress community, WordPress project works.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So this opens up their mind about the open source. Because in the education system, it is something that is not clearly mentioned. There are simple, just simple definitions around the open source. But open source is much more than those definitions.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And especially the open source community like WordPress. It&#8217;s more about the people. So the students also learn about how the community is working, how the people are working from the different time zones, people are joining hands for running the bigger events like WordCamp Asia or these Credits Programs. The students will learn all those things as well, and I&#8217;m sure when they will join as a contributor in the future, they will have lot of experience before joining as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:53:02] <strong>Nathan Wrigley:</strong> Thank you. I love that expression, by the way. You just dropped it in in the middle of a sentence there. You said people are joining hands. What a perfect summation of the entire enterprise being discussed today. Maciej, you raised your hand.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:53:14] <strong>Maciej Pilarski:</strong> Yeah, and besides the community goals and keeping it going, I have also a very personal goal that also is behind all of those things that I do. From my own experience, I had a pretty difficult and bumpy educational path, let&#8217;s call it. Unlocking those possibilities for those students, helping them out, making it easier for them, it&#8217;s one of my very personal goals, because I know it does not need to be very difficult or crazy when you study, especially when you are young. You&#8217;re not sure fully which direction you would like to go. So creating for them, one of those opportunities that might click for them is also something very personal and close to my heart. Because not everyone needs to struggle or have like difficulties, so.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:53:58] <strong>Nathan Wrigley:</strong> I am so glad you said that because that encapsulates all of it. That&#8217;s the entire point. It&#8217;s got to be that, right? So we&#8217;ve spent a long time talking about the minutiae of this, that, and the other thing. It all goes, like they&#8217;re spokes on a wheel. And the whole point is that little bit in the middle, which is the child, the adult, the human being somewhere who just wants to make use, wants to grow, wants to learn things, wants to figure things out.</p>\n\n\n\n<p class=\"wp-block-paragraph\">With open source, with this kind of learning, there is potentially zero impediment, or at least very few impediments to actually get that learning underway. And so I think maybe we lost sight of that in this conversation a little bit. So I&#8217;m glad that you grounded it there, Maciej, right towards the end. That&#8217;s perfect. Destiny, was there anything you wanted to say? I don&#8217;t know if you were indicating that you did.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:54:48] <strong>Destiny Kanno:</strong> I know we&#8217;re like probably over time, but there&#8217;s still so much to share. Like even thinking about keeping WordPress relevant, right? For us and then also for youth. I think about the new AI Leaders Credential that was announced and is being worked on. And how tying WordPress to AI is like really helping students engage more, and see like the relevancy of it in a different way. Not even for the students, like for me, that&#8217;s challenging me and I think other organisers and learners of WordPress to be adaptable and think about WordPress differently in a new way of this year as AI keeps advancing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And then you were also talking about wins, right? How do we celebrate that? I did want to surface, we have the Education Buzz Report, which goes out every month, which aims to try to surface all of these educational wins that are happening in the community. And I just have received some further collaboration from marketing to hopefully also broadcast that on our socials going forward so that we do get the word out.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And lastly, like celebrating the students too. There was a post that went out about the Student Clubs and the success. And we just want to make sure that in this, that they feel seen, right? And that this feels like a space for them. And I know WordPress Credits, we&#8217;re working on something to showcase, no, something went out recently. A post went out recently to showcase some of the successes of the students. And we just want to keep highlighting that as well. Because their work and the way they operate, especially because they&#8217;re coming in with different lenses, is really important to showcase and highlight and make sure that they feel like they deserve that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:56:26] <strong>Nathan Wrigley:</strong> Yeah, there was a post, I&#8217;ll try and link to it. I think it was like a week ago about the Student Clubs. There were three or four images, three or four photos and there were so many smiling faces in those pictures. It was absolutely lovely. Lots of people gathered in classrooms. I couldn&#8217;t exactly tell where, but it was just so nice seeing people kind of enjoying WordPress, having a nice time, bit of camaraderie, hanging out with each other, learning things. It was absolutely wonderful.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Unfortunately, I think time might have got the better of us. Hopefully, dear listener, what you&#8217;ve gained is an understanding that there&#8217;s so many layers to this educational initiative. It doesn&#8217;t appear to be in any way standing still. It&#8217;s growing. It&#8217;s interesting. There&#8217;s a lot going on, and you can be involved.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I will put links in the show notes to any of the places where I feel you would be best making a start with that. Maybe the contributors to this panel can drop some things, you know, if they&#8217;ve got a particular link. So again, wptavern.com. If you want to go over there, we will look for the links.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This giant edifice that you maybe know nothing about, and maybe at the end of this episode, some parts of you is tuned in and thinking, I would like to be involved in that. And the truth is, you can be. It&#8217;s all available to you to get involved and you could start today.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So there we go. With that said, I&#8217;m just going to say a great big thank you to Destiny, to Anand, and to Maciej. It kinds of feels like we need to come back. Let&#8217;s do it again in six months or so, and we&#8217;ll see where we&#8217;re at. Oh, I&#8217;ve got a lot of nodding faces. That&#8217;s nice. So maybe we&#8217;ll revisit this in a few months time.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But seriously, from the bottom of my heart, Destiny, Anand and Maciej, profound respect to you and all of the different things that you are doing. Thank you so much for chatting to me today.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:58:13] <strong>Anand Upadhyay:</strong> Thank you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:58:13] <strong>Maciej Pilarski:</strong> Thank you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:58:14] <strong>Destiny Kanno:</strong> Thank you.</p>\n</div></details>\n\n\n\n<p class=\"wp-block-paragraph\">On the podcast today we’re joined by three WordPress education initiative leaders, Destiny Kanno, Anand Upadhyay and Maciej Pilarski.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Together, they have spent years at the heart of WordPress training and outreach, working in roles spanning community education management, plugin development, and credit program administration. Their efforts have helped shape student engagement and university partnerships across the globe, introducing thousands of learners to WordPress. You can see their bios further down.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The conversation focused on the current landscape of WordPress education, with particular attention to three key initiatives: the WordPress Credits Program, Campus Connect, and Student Clubs. Each initiative is designed to provide unique entry points for students of all ages and education levels, from high schoolers building their first site in a library, to university students earning official credits for open source contributions.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We discussed the different approaches these programs take: WP Credits ties student work directly to academic credit and mentorship, Campus Connect provides flexible, community-driven events in diverse locations, and Student Clubs foster sustainable, peer-led learning within schools and other institutions. We explored how these models feed into each other, building a sustainable ecosystem for ongoing growth in the WordPress community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We also got into the importance of repeat campus partnerships, the need for scalable facilitator training, and the role of recognition: certificates, badges, and public showcases, in keeping students motivated and validated in their journey.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you’re curious about the growing movement to bring WordPress knowledge to the next generation, or are looking to get involved with education in your local community, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Previous episode of the podcast related to this episode:<br /><a href=\"https://wptavern.com/forums/topic/183-destiny-kanno-isotta-peira-and-anand-upadhyay-on-how-wordpress-is-shaping-the-future-of-education-for-students-worldwide\">#183 – Destiny Kanno, Isotta Peira and Anand Upadhyay on how WordPress is shaping the future of education for students worldwide</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/community/\">WordPress Community Team</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://events.wordpress.org/campusconnect/\">Welcome to WordPress Campus Connect</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://profiles.wordpress.org/stephendumba1/\">Stephen Dumba&#8217;s WordPress.org profile</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/handbook/wordpress-credits-contribution-internship-program/\">WordPress Credits: Contribution Program for Students</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/education/student-clubs/\">WordPress Student Clubs</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://events.wordpress.org/campusconnect/2025/ajmer/\">WordPress Campus Connect in Ajmer</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/community/2026/05/01/peer-review-needed-hands-on-wordpress-meetup-activity-library/\">Peer Review Needed: Hands-On WordPress Meetup Activity Library</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/community/2026/04/03/introducing-the-wordpress-facilitator-training-program/\">Introducing the WordPress Facilitator Training Program</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/news/2026/02/ai-leaders-credential/\">Piloting the AI Leaders Micro-Credential</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://make.wordpress.org/community/2026/06/03/monthly-education-buzz-report-may-2026/\">Monthly Education Buzz Report – May 2026</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://learn.wordpress.org\">Learn WordPress</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/news/2026/04/student-clubs-build-momentum/\">WordPress Student Clubs Build Momentum</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Links provided by the guests</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li>WordPress.org Education page:<br /><a href=\"https://wordpress.org/education/\">https://wordpress.org/education/</a> (and all subpages)</li>\n\n\n\n<li>WordPress Credits Institution application form:<br /><a href=\"https://make.wordpress.org/handbook/wordpress-credits-contribution-internship-program/#get-involved\">https://make.wordpress.org/handbook/wordpress-credits-contribution-internship-program/#get-involved</a></li>\n\n\n\n<li>Call for WP Credits mentors and mentor application form:<br /><a href=\"https://make.wordpress.org/handbook/wordpress-credits-contribution-internship-program/a-guide-for-wp-credits-mentors/call-for-mentors/\">https://make.wordpress.org/handbook/wordpress-credits-contribution-internship-program/a-guide-for-wp-credits-mentors/call-for-mentors/</a></li>\n\n\n\n<li>Any companies interested in supporting the Credits Program:<br /><a href=\"https://make.wordpress.org/handbook/wordpress-credits-contribution-internship-program/get-involved-company-guide/\">https://make.wordpress.org/handbook/wordpress-credits-contribution-internship-program/get-involved-company-guide/</a></li>\n\n\n\n<li>Student form to apply their institution for the Credits Program:<br /><a href=\"https://airtable.com/appIzQKfwTn5dyPVp/shr6Gf1mMMEAxevw4\">https://airtable.com/appIzQKfwTn5dyPVp/shr6Gf1mMMEAxevw4</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/community/handbook/education/wordpress-facilitator-training-program/\">WordPress Facilitator Training Program</a></li>\n\n\n\n<li>Education buzz reports: <a href=\"https://make.wordpress.org/community/tag/education-buzz/\">https://make.wordpress.org/community/tag/education-buzz/</a></li>\n\n\n\n<li>Apply to organize a WPCC event: <a href=\"https://events.wordpress.org/campusconnect/organize/\">https://events.wordpress.org/campusconnect/organize</a></li>\n\n\n\n<li>Apply to create a student club: <a href=\"https://make.wordpress.org/community/handbook/education/student-clubs/request-the-creation-of-a-wordpress-student-club/\">https://make.wordpress.org/community/handbook/education/student-clubs/request-the-creation-of-a-wordpress-student-club/</a></li>\n\n\n\n<li>Ai credentials:<br /><a href=\"https://wordpress.org/news/2026/02/ai-leaders-credential/\">https://wordpress.org/news/2026/02/ai-leaders-credential/</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Guest bios:</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Destiny Kanno</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Destiny Fox Kanno, sponsored contributor acting as a Community Education Programs Manager at Automattic. Destiny works closely with the Community team and Training Team, with a focus on growing, enabling and amplifying WordPress Campus Connect, Student Club, WordPress Credits and other education initiatives.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Anand Upadhyay</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Anand Upadhyay is a long-time WordPress contributor and community advocate based in Ajmer, India. Active in the ecosystem since 2010, he has contributed to several Make WordPress teams including Core, Docs, Community, and Polyglots, with a strong focus on empowering others to get involved. He is the founder of <a href=\"https://wpvibes.com\">WPVibes</a>, a WordPress plugin development company that builds performance-driven tools for WordPress and WooCommerce users.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Anand is also a regular WordCamp speaker, Meetup organiser, and someone deeply committed to bringing WordPress education to students. In 2024, he launched the first WordPress Campus Connect event, which went on to become a global program officially recognised by the WordPress Foundation. Anand continues to support and mentor student communities through events, workshops, and open-source advocacy.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Maciej Pilarski</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Maciej Pilarski is a Community Wrangler at Automattic, where he works on WordPress.org with a focus on educational initiatives that connect the next generation of contributors to the global WordPress community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">As one of the admins behind the WordPress Credits Program, Maciej works with universities across Central &amp; Eastern Europe and Asia to bring students into open source contribution, pairing them with mentors, building institutional partnerships, and helping turn academic coursework into real-world impact on software used by 43% of the web.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Originally from Poland and now based in Okinawa, Japan, Maciej brings a uniquely cross-cultural perspective to community building, bridging local ecosystems in places like Kraków, Riga, Tallinn, and Tokyo with the wider WordPress world. He&#8217;s passionate about making open source contribution more accessible and making sure the WordPress community reflects the full diversity of the people who use it.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 24 Jun 2026 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:25;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:46:\"Open Channels FM: Revisiting What Matters Most\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2556050\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:53:\"https://openchannels.fm/revisiting-what-matters-most/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:205:\"In this episode, Bob Dunn recaps six months of key themes, highlighting the surge in AI discussions, ongoing debates about the open web, and WordPress\'s enduring relevance, while embracing honest dialogue.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 24 Jun 2026 12:58:56 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:26;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"Open Channels FM: BackTalk on Interoperability, Infrastructure and Pragmatism\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555826\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://openchannels.fm/backtalk-on-interoperability-infrastructure-and-pragmatism/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:147:\"Ongoing challenges in decentralized social networks, emphasizing the need for practical solutions and immediate usability for developers and users.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 24 Jun 2026 11:57:32 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:27;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:15:\"Matt: No Bubble\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153299\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://ma.tt/2026/06/no-bubble/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:425:\"<p class=\"wp-block-paragraph\">A throwback from 2007: a local Bay Area a cappella group called The Richter Scales made a Webby Award-winning viral video about how that bubble felt. <em>Hat tip: <a href=\"https://toni.org/\">Toni</a>.</em></p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n\n</div></figure>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 24 Jun 2026 06:57:52 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:28;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"WordPress.org blog: Browse the New Mercantile Swag Store\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20930\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:50:\"https://wordpress.org/news/2026/06/open-web-merch/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3868:\"<p class=\"wp-block-paragraph\"><a href=\"https://mercantile.wordpress.org/\">Mercantile</a>, the official swag store of the WordPress project, has a newly redesigned storefront with a catalog that now sits front and center, and a design tuned to hold up across a wide range of screen sizes. There are also small touches, like automatically selecting a variant when only one is in stock and order emails styled to match the look and feel of the store.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20931\" height=\"1055\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/06/image-1.png?resize=2048%2C1055&#038;ssl=1\" width=\"2048\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Throughout the design, the storefront leans into the history and culture of WordPress. Visual and copy choices nod to familiar elements of the project, from the metabox and the admin bar to Wapuu making the occasional appearance, with small open source and code references for those who look closely. The aim was a storefront that feels uniquely WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Under the hood, the storefront shows what a modern WordPress and <a href=\"https://woocommerce.com/\">WooCommerce</a> site can do. It is built almost entirely with blocks, including a block-based cart, checkout, mini-cart, and order confirmation, supported by a set of custom theme blocks created for the store. The <a href=\"https://developer.wordpress.org/block-editor/reference-guides/interactivity-api/iapi-about/\">Interactivity API</a> powers the catalog navigation and modal states, the store runs on WordPress 7.0, and accessibility is built in throughout, honoring reduced-motion preferences across animations and meeting color contrast standards. Product pages surface per-product attributes such as size, material, and care, so shoppers have the details they need before adding an item to the cart.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20932\" height=\"800\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/06/image-2.png?resize=2048%2C800&#038;ssl=1\" width=\"2048\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">This latest redesign supported the Mercantile booth at <a href=\"https://europe.wordcamp.org/2026/\">WordCamp Europe</a>. To make in-person sales work smoothly, the team enabled local pickup at checkout and added a set of event-only products refined to match the rest of the catalog. Fifty orders were completed at the event using in-person payments, a strong real-world test of the new checkout flow.</p>\n\n\n\n<p class=\"wp-block-paragraph\">There is more on the way! A playful experiment in progress will let curious shoppers explore a text-based version of the store from the command line, a small tribute to the developers who make up much of the WordPress community. Subtle hints pointing the way will appear once it is ready.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20933\" height=\"719\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/06/image-3.png?resize=2048%2C719&#038;ssl=1\" width=\"2048\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">The new Mercantile is the work of many contributors who designed, built, tested, and refined it together. Every purchase supports the <a href=\"https://wordpressfoundation.org/\">WordPress Foundation</a>, a 501(c)(3) nonprofit organization, in its mission to democratize publishing and preserve open source software for generations to come. Take a look around and find something you love.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-3e41869c wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://mercantile.wordpress.org/\">Shop at <strong>mercantile.WordPress.org</strong></a></div>\n</div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 22 Jun 2026 15:07:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"jillq\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:29;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:72:\"Open Channels FM: Navigating Burnout in the Age of AI-Driven Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555430\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://openchannels.fm/navigating-burnout-in-the-age-of-ai-driven-development/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:180:\"AI transforms developer workflows, causing cognitive overload and blurring work-rest boundaries. Establishing intentional breaks is crucial to maintain balance and prevent burnout.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 22 Jun 2026 10:08:08 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:30;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"Matt: Hill For A Stepper\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153269\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://ma.tt/2026/06/hill-stepper/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:798:\"<p class=\"wp-block-paragraph\">In honor of Father&#8217;s Day, I wanted to add to the <a href=\"https://ma.tt/chuck/\">two quotes from my Dad&#8217;s obituary</a>, &#8220;Seven days without chicken made one weak.” and  “If you fail at raising your children, nothing else mattered.” with another saying he had.</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Ain&#8217;t no hill for a stepper.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d like to learn more about this, <a href=\"https://waywordradio.org/stepper-like-you/\">check out this part of the A Way with Words podcast</a>, and apparently, it <a href=\"https://www.youtube.com/watch?v=Lui5y2AcYpM\">might have come from the musician John Gaar</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 22 Jun 2026 06:58:38 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:31;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:25:\"Matt: Death by PowerPoint\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153252\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:42:\"https://ma.tt/2026/06/death-by-powerpoint/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:760:\"<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">PowerPoint makes us stupid. </p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">— Gen. James N. Mattis of the Marine Corps, the Joint Forces commander</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><a href=\"https://www.nytimes.com/2010/04/27/world/27powerpoint.html\"><img alt=\"\" class=\"wp-image-153254\" height=\"340\" src=\"https://i0.wp.com/ma.tt/files/2026/06/27powerpoint_CA0-articleLarge.webp?resize=600%2C340&#038;quality=80&#038;ssl=1\" width=\"600\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Classic <a href=\"https://www.nytimes.com/2010/04/27/world/27powerpoint.html\">2010 NYT <em>We Have Met the Enemy and He Is PowerPoint</em></a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sun, 21 Jun 2026 06:03:40 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:32;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Matt: Best Trash\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153245\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2026/06/best-trash/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1194:\"<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">A typography savant on staff had spent a month designing link underlines (literally just lines) that were more visually pleasing than Chrome or Safari’s defaults. On Tuesdays, engineers stayed late at the office, fixing design imperfections over dinner. One of them began a 2,500-word <a href=\"https://medium.com/@fat/mediums-css-is-actually-pretty-fucking-good-b8e2a6c78b06\" rel=\"noopener\" target=\"_blank\">post</a> about Medium’s CSS code with a quote attributed to Lil Wayne: “I believe that to be the best, you have to smell like the best, dress like the best, act like the best. When you throw your trash in the garbage can, it has to be better than anybody else who ever threw their trash in the garbage can.”</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">From Harris Sockel&#8217;s essay <a href=\"https://www.piratewires.com/p/what-happened-to-medium\">What Happened to Medium</a>, which I think is meant to be a dunk? But I think it&#8217;s awesome. Medium&#8217;s design and typography has always been really impeccable. I love when people obsess like this.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 20 Jun 2026 13:51:14 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:33;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:24:\"Matt: Midjourney Medical\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153216\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"https://ma.tt/2026/06/midjourney-medical/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:3191:\"<p class=\"wp-block-paragraph\">I&#8217;m sorry I couldn&#8217;t be there in person, but I was so excited to watch the <a href=\"https://www.midjourney.com/medical\">Midjourney Medical</a> launch from afar. This is a really big deal. <a href=\"https://x.com/DavidSHolz\">David Holz</a>, one of the most underrated pioneers in AI, has taken money from <a href=\"https://www.midjourney.com/explore?tab=top\">making cat pictures</a> to build a full-body ultrasound scanner that can give you <a href=\"https://www.midjourney.com/medical/blogpost\">incredible visibility in 60 seconds</a>.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-153220\" height=\"302\" src=\"https://i0.wp.com/ma.tt/files/2026/06/female_lower_abdomen_mask-458023b86b6cf387-1024x512.webp?resize=604%2C302&#038;quality=80&#038;ssl=1\" width=\"604\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">You can <a href=\"https://x.com/i/broadcasts/1MJgNNoAPLyGL\">re-watch the livestream here</a>, which I recommend. You might remember David from Leap Motion, which <a href=\"https://ma.tt/2012/05/leap-motion/\">I blogged back in 2012</a>. It&#8217;s so cool to a small but mighty independent company innovate and apply learnings across seemingly disparate sectors.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I wish all my friends in jazz and the arts who are  despondent about tech could meet David:</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">“We’re going to be a little confusing for the next six months as we announce all the things, but I’m hoping as they all are out there, they form a picture which I hope feels cohesive. Most of them are around creativity, but some of them, like this, are just around positive human futures that we actually want to be a part of. And I think this is an important thing for AI companies to do—for all humans to do.” — David Holz</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">If you understand imaging, you know the tradeoffs between X-ray, CT (computed tomography), MRI (magnetic resonance imaging), and ultrasound, and Midjourney&#8217;s approach doesn&#8217;t cover everything, but what&#8217;s incredible is the speed, amount of data, and using AI to process and get something useful out of it. Ultrasonics will be an incredibly exciting area over the next few years, first for imaging and later <a href=\"https://www.mayoclinic.org/tests-procedures/high-intensity-focused-ultrasound/about/pac-20596150\">for intervention</a>. I can imagine a future where you dip into one of these once a month just to keep an eye on things, not just to find bad stuff but to see the impact of exercise or dietary changes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We&#8217;re fairly new to scanning healthy people, and I always advise friends getting their first whole-body MRI with <a href=\"https://www.biograph.com/\">Biograph</a> or <a href=\"https://prenuvo.com/\">Prenuvo</a> that it&#8217;s very common to hear something scary at first, only to find it&#8217;s benign. Also, I&#8217;ve now heard many examples of things that were caught and treated early, years before they might otherwise have been noticed.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 20 Jun 2026 04:09:58 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:34;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"WordPress.org blog: Kim Parsell Memorial Scholarship Opens for WordCamp US 2026\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20927\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"https://wordpress.org/news/2026/06/kim-parsell-wcus-scholarship/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4552:\"<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20941\" height=\"1080\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/06/Kim-Parsell-Blog-post.png?resize=1920%2C1080&#038;ssl=1\" width=\"1920\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Applications are now open for the 2026 Kim Parsell Memorial Scholarship, which supports one active WordPress contributor who identifies as a woman and has not previously attended WordCamp US. The scholarship helps make it possible for a community member with financial need to join WordCamp US 2026 in Phoenix, Arizona, and take part in one of the largest annual gatherings in the WordPress project.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The scholarship honors Kim Parsell, a longtime WordPress contributor whose work and presence left a meaningful mark on the project. Kim was known for her care, generosity, and commitment to helping others feel welcome in open source spaces. For readers who are less familiar with her story, the <a href=\"https://us.wordcamp.org/2019/memories-of-kim-parsell/\">tributes shared by friends and colleagues</a> offer a deeper look at her role in the WordPress community and the lasting impact she had on those who knew her. Through this scholarship, the WordPress Foundation continues to recognize contributors who reflect that same spirit of participation and community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress is built by people from many backgrounds, experiences, and areas of expertise. Events like WordCamp US create space for contributors to meet in person, learn from one another, and continue the work that supports the software and the community around it. For some contributors, the cost of travel, lodging, and registration can make attending difficult. The Kim Parsell Memorial Scholarship helps reduce that barrier for one eligible contributor each year.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Scholarship Details</h2>\n\n\n\n<p class=\"wp-block-paragraph\">One scholarship will be awarded for WordCamp US 2026. Applicants must:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Identify as a woman. </li>\n\n\n\n<li>Be actively involved as a contributor to WordPress.</li>\n\n\n\n<li>Have never attended WordCamp US before.</li>\n\n\n\n<li>Demonstrate financial need to attend the event.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">The scholarship includes the cost of a WordCamp US 2026 ticket, round-trip flight, and lodging. Applications are open through July 10, 2026, and all applicants will be notified of the decision by July 24, 2026.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"https://wordcampcentral.survey.fm/wcus-2026-kim-parsell-scholarship-application\" style=\"background-color: #6c214f;\">Apply for the Kim Parsell Memorial Scholarship</a></div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<p class=\"wp-block-paragraph\">WordCamp US 2026 will take place August 16–19, 2026, at the Phoenix Convention Center in Phoenix, Arizona. Contributors, attendees, volunteers, organizers, and sponsors will come together to share ideas, learn from each other, and continue building the future of WordPress. For many contributors, attending in person creates new ways to collaborate, find support, and stay connected to the open source work that happens throughout the year.</p>\n\n\n\n<p class=\"wp-block-paragraph\">To learn more about eligibility, visit the <a href=\"https://wordpressfoundation.org/kim-parsell-memorial-scholarship/\">Kim Parsell Memorial Scholarship page</a>. Community members are encouraged to share this opportunity with contributors who may qualify. You can also learn more about attending WordCamp US 2026 on the <a href=\"https://us.wordcamp.org/2026/tickets/\">WordCamp US tickets page</a>, explore <a href=\"https://us.wordcamp.org/2026/call-for-volunteers/\">volunteer opportunities</a>, or review <a href=\"https://us.wordcamp.org/2026/call-for-sponsors/\">sponsorship opportunities</a>.</p>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20939\" height=\"1978\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/06/WCUS26_Sign.png?resize=943%2C1978&#038;ssl=1\" width=\"943\" /></figure>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 19 Jun 2026 16:55:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:35;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:49:\"Open Channels FM: Open Channels FM v4.8 Changelog\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555724\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://openchannels.fm/open-channels-fm-v4-8-changelog/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:208:\"Bob Dunn has launched a blog commentary and a weekly series, \"Open Tabs.\" Do the Woo is now an independent podcast. Updates include a redesigned homepage, new episode features, and a newsletter format change.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 19 Jun 2026 09:23:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:36;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:92:\"WordPress.org blog: Global Partners Across the First Half of the 2026 WordPress Event Season\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20910\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:67:\"https://wordpress.org/news/2026/06/global-partners-first-half-2026/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:7579:\"<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20911\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/06/55169598894_0199c1bbb9_o-scaled.jpg?ssl=1\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">This post recaps how the WordPress project&#8217;s five Global Partners — Jetpack, WordPress.com, WooCommerce, Bluehost, and Hostinger — supported community events during the first half of 2026. Across more than a dozen regional <a href=\"https://events.wordpress.org/novisad/2026/developer-day/\">the first WordPress Developers Day</a>, and a growing network of <a href=\"https://events.wordpress.org/campusconnect/\">WordPress Campus Connect</a> events, Global Partners staffed booths, sponsored sessions, and connected with developers, freelancers, students, and agency owners around the world.</p>\n\n\n\n<h2 class=\"wp-block-heading\">A global footprint</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The year began in January with <a href=\"https://nepal.wordcamp.org/2026\">WordCamp Nepal</a>, where Jetpack joined the community in Kathmandu. The momentum carried into India, where <a href=\"https://kolhapur.wordcamp.org/2026\">WordCamp Kolhapur</a> and, a week later, <a href=\"https://pune.wordcamp.org/2026\">WordCamp Pune</a> brought Global Partners face-to-face with a student-heavy audience of roughly 200-250 attendees. In Pune, a session on connecting WordPress with AI workflows drew a large crowd, and attendees were curious about WordPress.com plans, new AI features, and Automattic for Agencies. </p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20920\" height=\"675\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/06/img_1932.jpg?resize=1206%2C675&#038;ssl=1\" width=\"1206\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">In February, Jetpack traveled to <a href=\"https://portharcourt.wordcamp.org/2026\">WordCamp Port Harcourt</a> in Nigeria, an inclusive and well-organized event with 256 attendees that featured talks on inclusion and accessibility. Locally produced swag was a standout success there, a reminder that the WordPress community&#8217;s reach extends well beyond Europe and North America.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Across Europe</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Spring brought a wave of European events. At <a href=\"https://madrid.wordcamp.org/2026\">WordCamp Madrid</a>, with 280 attendees, WordPress.com served as a Global Sponsor and ran a Wapuu treasure hunt that drew 97 participants. </p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img alt=\"\" class=\"wp-image-20921\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/06/55230328181_175ece15a5_o-scaled.jpg?ssl=1\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Down the coast in France, <a href=\"https://nice.wordcamp.org/2026\">WordCamp Nice</a> gave Jetpack a chance to connect with 247 freelancers and developers, an audience that appreciated concrete, easy-to-explain solutions and asked questions about newsletters, security, and Jetpack&#8217;s broader feature set.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://vienna.wordcamp.org/2026\">WordCamp Vienna</a> stood out for its developer-heavy crowd of 277. From a Jetpack-branded booth staffed on both days, the team engaged with agencies and merchants, fielded numerous questions about WooCommerce and security, and booked 8 agency meetings. Many builders were interested to learn that Automattic stands behind both WordPress.com and WooCommerce. In Italy and Germany, <a href=\"https://torino.wordcamp.org/2026\">WordCamp Torino</a> and <a href=\"https://leipzig.wordcamp.org/2026\">WordCamp Leipzig</a> both reflected growing curiosity about AI, a theme that resurfaced throughout the year. At Leipzig, with 109 agencies, hosting companies, and freelancers in attendance, WordPress.com staffed a booth where tote bags were in high demand, while conversations kept returning to AI and WordPress Studio.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://slovenia.wordcamp.org/2026\">WordCamp Slovenia </a>and <a href=\"https://portugal.wordcamp.org/2026\">WordCamp Portugal</a> closed the European stretch. WordPress.com brought a booth to Ljubljana, and in Porto, it appeared with both a booth and logo presence alongside WooCommerce, which suited an event filled with e-commerce builders and Woo payment providers. The first WordPress Developers Day in Novi Sad introduced a new format, with Jetpack as a global sponsor and nearly 30 in-depth conversations on Jetpack, WooCommerce, performance, and the realities of client work.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Community in Uganda</h2>\n\n\n\n<p class=\"wp-block-paragraph\">In May, <a href=\"https://kampala.wordcamp.org/2026\">WordCamp Kampala</a> brought four Global Partners onto the sponsor roster: Jetpack, WooCommerce, Bluehost, and WordPress.com. The event, themed &#8220;Tech for Social Good,&#8221; welcomed more than 200 attendees and reflected the energy of a fast-growing local community.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Support from Global Sponsors</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Behind every one of these events is a layer of support that does not always appear at a booth. In 2026, Bluehost and Hostinger both joined the <a href=\"https://events.wordpress.org/sponsor/\">WordPress community sponsorship program</a> as top-tier Global Sponsors, alongside Jetpack and WordPress.com. Their contributions help underwrite the global WordCamp program and the community events that make a year like this possible. That program-level backing is what allows organizers in Kathmandu, Porto, and Kampala to bring their events to life, and the WordPress community is grateful to every partner that invests at that scale.<br /></p>\n\n\n\n<h2 class=\"wp-block-heading\">Campus Connect reaches 6,200 students</h2>\n\n\n\n<p class=\"wp-block-paragraph\">One of the most notable stories of 2026 is not a WordCamp at all. It is <a href=\"https://events.wordpress.org/campusconnect/\">WordPress Campus Connect</a>. As of early June, the program has passed 6,200 students, with 25 events completed in 2026, 45 events all-time, and 42 more in planning or already scheduled. WordPress.com has played a direct support role throughout, including providing hosting for WordPress Campus Connect events around the world.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The connective tissue between these events and the broader community is real. An organizer first met at WordCamp Mukono went on to help lead WordPress Campus Connect work in Uganda. A student who built her first WordPress site at a WordPress Campus Connect event later attended a WordCamp. These events serve as a pathway for the next generation of WordPress contributors, builders, and professionals.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Looking ahead</h2>\n\n\n\n<p class=\"wp-block-paragraph\">If 2026 has shown anything, it is that interest in WordPress, and in the tools and services that Global Partners provide, continues to grow around the world. The questions being asked at booths and in sessions are sharper, the audiences more diverse, and the community&#8217;s reach more genuinely global. Thank you to Jetpack, WordPress.com, WooCommerce, Bluehost, and Hostinger for being part of that story this year, and to every organizer, volunteer, speaker, and attendee who made these events possible.</p>\n\n\n\n<p class=\"wp-block-paragraph\">To find an upcoming event near you, visit <a href=\"https://central.wordcamp.org\">WordCamp Central</a>. To learn how organizations can support the WordPress project, see the <a href=\"https://events.wordpress.org/sponsor/\">community sponsorship program</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 18 Jun 2026 17:01:21 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Harmony Romo\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:37;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"Open Channels FM: AI Hype and Hope Navigating Optimism and Skepticism\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555778\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:76:\"https://openchannels.fm/ai-hype-and-hope-navigating-optimism-and-skepticism/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:170:\"In this episode, hosts and guests share diverse perspectives on AI\'s rise, touching on its potential, challenges, and how it\'s reshaping industries and human interaction.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 18 Jun 2026 09:58:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:38;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"WPTavern: #221 – Rahul Bansal on Using AI Everywhere at rtCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=204828\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:78:\"https://wptavern.com/podcast/221-rahul-bansal-on-using-ai-everywhere-at-rtcamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:55356:\"<details>Transcript<div>\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Jukebox is a podcast which is dedicated to all things WordPress, the people, the events, the plugins, the blocks, the themes, and in this case using AI everywhere at rtCamp.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you or your idea featured on the show. Head to wptavern.com/contact/jukebox? And use the form there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So on the podcast today we have Rahul Bansal. Rahul has a long and accomplished history in the WordPress ecosystem. As the founder and CEO of rtCamp, a company he started 17 years ago, he&#8217;s led his agency through the rapidly changing landscape of the web, helping enterprise clients such as Google, Fortune 500 companies, and major publishers solve complex problems with innovative WordPress based solutions.</p>\n\n\n\n<p class=\"wp-block-paragraph\">rtCamp specialises in everything from large scale website builds, to more bespoke projects like Chrome extensions and SaaS connectors, and has grown to a team of hundreds over the years.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Today&#8217;s episode takes a deep dive into Raul&#8217;s recent talk at WordCamp Asia, which focused on what it will take to launch and scale an enterprise WordPress agency in the future.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The conversation focused on real, hard won, lessons from rtCamp&#8217;s journey, but also how rapidly the playbook is changing with advances in technology, particularly the explosion of AI tools and workflows.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We discuss Rahul&#8217;s philosophy around hiring, namely building a team of people whose strengths complement each other rather than just replicating your own skillset. This approach has allowed rtCamp to adapt to new challenges, fill gaps in expertise, and whether major industry changes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We then explore how this idea of complimentary sets can also apply to choosing the right kinds of clients, those who value your expertise because they need what you offer, rather than simply hiring somebody who does what they already know.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A theme that emerged in the conversation was specialisation. Rahul outlines how, whereas rtCamp&#8217;s earliest differentiator was a simple focus on WordPress, when virtually nobody else in India was, today&#8217;s agencies must drill down much further to stand out choosing niches within niches, such as WooCommerce, or payment gateway integrations, and becoming recognised experts in those areas in order to thrive in a much more crowded field.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Towards the end of the episode, the discussion turns to what might be the most significant topic for agencies today, artificial intelligence. Rahul describes how recent advances in AI have not only altered his agency&#8217;s practises, but given them a firm mandate. If something in rtCamp can be done by AI it will be.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We talk about how AI is being leveraged inside rtCamp to automate and optimise everything from sales and proposal writing to project management, and even technical proof of concept builds. With a unified platform for all business processes, the agency is now able to significantly reduce costs, speed up delivery, and focus on higher value consulting and creativity, reshaping roles and team composition as a result.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re interested in what it takes to stand out and succeed in the evolving world of enterprise WordPress agencies, how to confront uncertainty with both optimism and realism, and how AI can become not just a bolt-on feature, but the operational backbone of your business, this episode is for you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so without further delay, I bring you Rahul Bansal.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I am joined on the podcast by Rahul Bansal. Hello, Rahul.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> Hello Nathan. Thanks for having me here.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> You are very welcome. Rahul and I were both at WordCamp Asia and that is going to be the main focus of the podcast today. We&#8217;re going to be talking about agencies, growth in agencies, and then probably delving into AI a little bit at the end because of a recent announcement that came out of rtCamp, which is the company that Rahul founded many years ago.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In order to, I suppose, lend credibility to a conversation about agency work, would you mind Rahul, just introducing yourself and tell us a little bit about who you are, what you do in WordPress, and maybe give us a few little interesting facts about rtCamp and what you do over there.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> So I&#8217;m, as you mentioned, founder and CEO of rtCamp. We started this 17 years ago. We primarily help large enterprise client, sometimes we build websites for their marketing team, which is the most common use case of WordPress. But at the same time, we help large tech companies like Google communicate better with the WordPress ecosystem for their offering. Like sometimes we build products that includes neither thing, neither plugin, but something like Chrome extension. For large companies sometimes we build like SaaS connectors for technology companies.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Yeah, so we work with, like a big companies really Fortune 500, and the idea is to deliver something related to WordPress in one form or another form.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> If you go to the rtCamp website, you can probably Google it I would&#8217;ve imagined, then you&#8217;ll be able to get some impression of what the company is like.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I think last time we spoke you were into the sort of 200 employees level. I&#8217;m not sure if those numbers have gone up or down or what have you. But you get an impression of how large it is. And one of the interesting things that I spotted during my time at WordCamp Asia was just how vibrant the community, the WordPress community is. So maybe we&#8217;ll get into that a little bit as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;m going to concentrate to begin with on the presentation that you gave at WordCamp Asia. If you would like to see that, wordpress.tv will have a video. And if the video is already available, I will link to it in the show notes. But the presentation that Rahul gave was entitled, how to Start an Enterprise WordPress Agency in 2026. And I&#8217;ll just read the blurb that goes with it because it was fairly short and easy to manage.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Building a WordPress agency business for large enterprises. In this talk, I&#8217;ll share the story of how rtCamp grew from a small WordPress shop into a globally recognised enterprise agency, trusted by Fortune 500 companies and major publishers. If you&#8217;re starting an agency today or looking to move up market in 2026, this session will give you a realistic roadmap building on real lessons from my personal experience.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So I suppose what I&#8217;m going to do at the beginning, Rahul, if it&#8217;s all right with you, is just ask you to tell us some of the bits and pieces that you mentioned during that. Some of the advice that you would give an agency owner beginning in 2026.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> Yeah. So first, like I deviated a little bit from the blurb because when I applied this talk I had a different frame of mind that, hey, I&#8217;m going to do this. And then as I was preparing the talk, and in during those months, especially like last few months, the AI has reshaped everything. And then I realised that a lot of what worked for rtCamp won&#8217;t work even for rtCamp if I start again today.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Rather than making it as a nice story about what worked for us, I lean more towards practical advice, and that&#8217;s where the essence remained. But I focus more on the 2026 part, because when we started, it was 2006. The first time when I used WordPress was 2006. rtCamp started in 2009. 20 years is a big time. And then at the end of this 20th year, like we are going through this AI led change.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So a lot of things that worked for me won&#8217;t work anymore. And that is how I restructured my talk to take enough from our history, enough from our learnings, what worked for us.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The way we hire is very different. And after the talk, if that one line that stick with the audience, that many people told me that the hire your complementary set was the most different idea. And it&#8217;s timeless idea. It&#8217;s relevant in AI world also.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So the idea was basically that we have this bias that when we try to scale, like basically when we go from freelancing to agency business, the idea of building a business, we try to find people like us. But my idea was that we should initially, especially, we should find people who are opposite of us. Like I was good at engineering, bad at sales, so my co-founder is sales heavy. My English was not good. His English was very polished.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So I literally listed down my weakness and found people who were opposite of me. Even interesting part was that, to the few initial hires I asked the questions, whose answer I had no idea whether they&#8217;re saying right or wrong.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that was the most interesting idea and I think that&#8217;s still relevant today. I will do exactly same thing if I have to start building a new agency. I will build in WordPress, build in AI, any kind of business I will, my initial few hires will all together will cover each other&#8217;s weaknesses.</p>\n\n\n\n<p class=\"wp-block-paragraph\">It&#8217;s at certain scale then you need to replicate, like, you need 50 engineers, you need 20 React engineers, you need five people who can write same proposal. That comes much later. But starting is all about finding your complementary set. And this was inspired by a set theory from math class that I attended in when I was like some 12-year-old. That stuck around before the life. And that is what I put in this talk as a biggest lesson we learned and that worked.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The second most specific thing that I would say, practical advice, like that was more about hiring advice, but that is not only hiring address, that is, I advise in many walks of life applicable.</p>\n\n\n\n<p class=\"wp-block-paragraph\">When you&#8217;re looking for your client, you have to look for complimentary set there as well. Because you are trying to sell to agencies like yours, your margins gets hit a lot. You need to find people who do not understand WordPress at all because then, that is why your expertise become more important and premium for them, because they need to depend on you. They value you more. You are not commoditised for them.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that hiring your complementary set works across the board. But then the most specific advice I gave that I didn&#8217;t follow myself, I would say. Actually there was nothing to follow that. When I started WordPress was just a blogging platform. There was custom post type were not yet part of WordPress Core. Everybody was just building blogs. We were playing around themes, and the race was to make our blog look unique. The metric usually was like traffic and how many email subscribers you got.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So there was no niche to pick. Like, that was the only thing WordPress was doing. And after post type, people started building a lot more than WordPress. Actually people started pushing WordPress earlier, and as a result of that, WordPress created those APIs to make it easy to extend WordPress beyond blogging platform.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But today, in 2026, there is so many things happening. And if you&#8217;re starting new and you do what rtCamp did on day one, like, hey, we are WordPress agency. That is not going to work.</p>\n\n\n\n<p class=\"wp-block-paragraph\">It worked for us 20 years back because we were like, probably only one in India at that time who said at that time that we will be only taking WordPress project. Because India was a land of outsourcing. Like in supply chain, it was like a, it&#8217;s like a Chinese manufacturer saying that, hey, we are only going to assemble if you are building for iPhone. So it&#8217;s like, hey, we are only going to write PHP if it is going to end up as a WordPress theme or plugin. We are not going to do what was Cake PHP project at that time. We are not going to write custom PHP script.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So in a way we picked the whole WordPress as a niche among the largest set of choices available to us. But if your largest set of choices was building a iOS company, like mobile app company. Mobile app was big because with the introduction of iPhone, there was a sudden shift and huge demand for iOS apps, and we haven&#8217;t built one till 17 years. Like literally we built our first iOS app, public iOS app last month.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That time we were like, well, we are going to only do WordPress. So now that advice translate into, pick a niche within WordPress because WordPress itself is the web now. That time, WordPress was very small. Now you can choose e-commerce. Within e-commerce then you can probably pick WooCommerce. Within WooCommerce then probably you can pick like, depending on your market, payment gateway specialisation, ERPs, back office specialisation, subscription based businesses.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Start by picking a niche as small as possible and then go bottoms up, rather than starting with everything. So that was the key takeaway of my session, I would say that. Pick a niche, position yourself as a expert in the niche. Don&#8217;t just say that, hey, we build WooCommerce store, or we build WordPress site.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> Okay. Yeah, I&#8217;ve got all of that. So firstly, hiring. That&#8217;s an interesting one. Hire people that are different from you. I was imagining when you were saying that, I wonder how long you can do that, because you can&#8217;t, eventually, you have a company of a hundred people and all of them are not the same as you. Eventually it must be nice to find somebody who&#8217;s a little bit like you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But then also you mentioned picking clients who will trust your expertise, I think is a good way of describing that. Because they themselves are perhaps not expert within that WordPress platform.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And now of course, moving forwards, what worked for you in terms of being a WordPress agency 17 odd years ago, that was, as it turns out, really successful. But now you are going to be amongst tens of thousands in India alone, if all you say is that you are a WordPress agency. So you need to go a little bit more specialised and niche down.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I wonder, Rahul, with the benefit of hindsight, it&#8217;s always easy to look back and sort of see for example, from my perspective, I see rtCamp as an entirely successful enterprise. You know, you began all those years ago, and decisions were made and you grew and you grew and you grew and you grew, and now we are where you are now. Committing a lot to WordPress with incredible growth and a really amazing agency on your hands.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But I&#8217;m just wondering, looking back, with the benefit of hindsight, were there any moments where you made some decisions where you were very nervous about how it was going to be?</p>\n\n\n\n<p class=\"wp-block-paragraph\">So for example, one of those could be WordPress. There was no writing on the wall that said WordPress will be the successful CMS. That really could have gone either way. It could have been Drupal, it could have been something that some kid in a basement created. So I&#8217;m just wondering, are there moments when you look back and you think to yourself, gosh, I am so glad that we did that random choice than all the others that we could have made?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> Yep. So it&#8217;s a reality that, one of the co-founders we lost, within the first year of company formation was because, I refused to add Joomla to our offering. And Joomla I think was market leader at that time when we started. So we were like more like engineers, like some were good at sales, some were good at communication, but we were all from the same kind of school, like we didn&#8217;t know if there was any survey existed.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So we didn&#8217;t back by any data. The only reason we chose to stay with WordPress or build this agency with WordPress because we were using WordPress. So rtCamp for the most part, people missed that. So rtCamp was not started as an agency. rtCamp was basically a media company, a blog network. And that blog network was running on WordPress. As a technology blogger. It&#8217;s like just imagine WP Beginners, like that is more relevant example.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So by the way, we, and WP Beginner were operating at the same time, that&#8217;s the power of niche. Like say I chose to focus on WordPress and say very very well. And my technical blog was everything like from iPhone to Windows operating system to Mac OS update to web APIs, to HTTP2. Whatever, like it was a larger technology blog So we were more like a stripped down version of TechCrunch rather than picking a niche. And Syed picked this WordPress as a niche.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Both were contemporaries in that same era. Now just imagine Syed in those days I started an agency. So we were using WordPress, we needed to stand out because, social network or blogging or web was still a fancy place. Like minimalism wasn&#8217;t the trend. It was how much you can push, like how you can make your website look different without using Flash. That was the coolest thing. Like how much you can push jQuery, how advanced CSS you can write. So all those things led to we customising our WordPress a lot.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Another thing that worked in our part was, our blog was one of the biggest in India. Globally also, it had good traffic. In fact, it had so much traffic that one of the most Googled keyword in my name was Rahul Bansal, how much money this guy make. Like that was the first question I used to get asked because traffic was insane. We used to get a lot of traffic.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That led us to writing nice WordPress code. In early days, like especially when I was freelancer, I had to write amazing WordPress code that will scale and host it in a way that it will also scale. So not only WordPress, we choose Nginx before it become a norm. Like before there was. anybody started any WordPress managed hosting company. We managed to scale WordPress at a very high level.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so now we, are this famous blog running on WordPress handling so much traffic, on Linode&#8217;s $10 something plan. Customising it. So we got this natural market. We got initial customers were technically our competitors, like other tech bloggers. It&#8217;s like TechCrunch hiring Mashable to customise their blog So something like, because Mashable has a tech team. So that was at early story of rtCamp.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And then we realised that we are making more money and faster money via customising WordPress. So we started cutting down on our editorials. And then, slowly, slowly like the business has shifted from, being a blogging agency, to WordPress custom development agency. That&#8217;s why we chose WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And that has been the principle since then, like we only sell what we use. That was the reason we didn&#8217;t, so it wasn&#8217;t any ideological decision. So the ideology is at open source level. So rtCamp is committed to providing open source solution to its client from day one.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Joomla tick that box. But Joomla didn&#8217;t tick the box that we use Joomla. We don&#8217;t use Joomla. There was no reason for us to have our blog running on WordPress and website running on Joomla, and that&#8217;s why we stick around WordPress when there was no data, no trend. And I think in hindsight it was just luck. I would say like it could have backfired.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> Well, okay, I really like this story. Firstly, I like the fact that you are identifying luck as a component, because I think too often when you listen to people who have had success, they sort of chart this narrative of how brilliant the decisions were along the journey and how impeccable, you know, we did this and then we did this, and then we did this, and then we did this. But never a nod to luck.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And of course, with the benefit of hindsight, we did this, we did this, we did this does lead to where you are now. But I really enjoy it when founders and people have that confession in them. Yeah, there was a bit of luck.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But also, and we&#8217;ll get onto this in a minute, because a big part of what you are about to do, or have recently done with your business kind of leans into what you&#8217;ve just been saying.</p>\n\n\n\n<p class=\"wp-block-paragraph\">It sounds like you were led by what was in front of you, if you know what I mean? It doesn&#8217;t sound like there was a great big, okay, by 2016 or 2026, we want to be here. It was more like, okay, this is where we&#8217;re at now. These are the things that are coming to us. Okay, looks like WordPress, not only are we using it, but it looks like people want us to help them to use it. Well, let&#8217;s go there then. Let&#8217;s put the blogging to one side and let&#8217;s become more of a, I don&#8217;t know, a technical helper for you and your website.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So there&#8217;s this sort of lucky piece, but also the willingness to steer into favourable winds, if you know what I mean? I love that story. Thank you very much for that. I also admire your humility in all of that. That&#8217;s lovely.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So the next thing then, I suppose that I want to get into is some change in the landscape at the moment. And again, this maps to what you were just saying about move where the wind takes you. We all know that AI is a thing. You cannot have missed that. But I think a lot of people are taking nervous steps into their business and how they&#8217;re doing things with AI and maybe biting off a little bit here with AI and leaving the rest as it is, and biting off another chunk here, and leaving the rest as it is and slowly moving into AI.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You have a very different approach. And I will link in the show notes to a blog post on the rtCamp website, which I read several weeks ago. I&#8217;ve got to say, I was a little bit, not surprised, that&#8217;s the wrong word, but it was written in such a way that I thought, gosh, now that&#8217;s interesting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Because in it you painted the case that rtCamp in the future is going to do AI everywhere. And I know we hear that all the time. You know, we&#8217;re going to use AI here, and we&#8217;re going to use AI there. You have painted your colours on the mast, and literally, I think you said, if it can be done with AI, it will be done with AI. There will be no stone left unturned.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Okay. Firstly, why? Why have you got that approach? What&#8217;s the reason? Now, I&#8217;m sure it&#8217;s fairly obvious, but lay it out for us anyway.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> Yeah. So I don&#8217;t know from where it comes, anytime I see things going south across industry like COVID or, like AI, like everybody was gloomy, my brain kind of think of opposite. So in my brain, I&#8217;m not building, I&#8217;m actually imagining an AI only agency with humans required to probably feel capture. That&#8217;s how my brain works. So it&#8217;s like AI first.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Then again, like WordPress, so I have been lucky more than once in my life. So before this AI came, this famous saying by Steve Jobs like you can only connect the dots looking backward. Three to four years ago, riding on the digital boom, we survived the COVID, like all agencies grew. rtCamp grew a lot more, and a lot faster in very short span of time. And to manage this humongous workforce, we needed to refactor a lot internal tooling, softwares, processes, to the point that we have internally codified our mission that we want to build McDonald&#8217;s of consulting business, inspired by that movie Founder. That was also part of my talk at WorkCamp Asia.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And in fact, I had somebody to literally a complimentary set example. I know we want to build this, but I don&#8217;t have that kind of mental model. So that&#8217;s the brief I give to our chief delivery officer that you have to give me this. McDonald&#8217;s of agency business.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We start thinking of every process that we can repeat, and we realised that we need to take control of our software stack. And we ended up finding something, in open source. That&#8217;s, I would say truly a spiritually aligned to the WordPress ecosystem called Frappe ERPNext, which handle our accounting, payroll, project management, CRM. So many business processes in one single source of truth, like single source of truth for so many things. Earlier it was all siloed data.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So this was started with a different intent, to scale rtCamp, 2000 people, 5,000 people, 10,000 people, because that was a business model then. Agencies growth with capacity. You want to sell more, you need to hire more. Basically agencies growth was limited by on one dimension, the inventory, human inventory you can have. So we started implementing this open source back office software automation with the idea that we will own, central piece of our operating system of connecting, getting thousands of people working together.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Then AI happened, and then we realised we don&#8217;t need to hire those many people anymore. Year on year, we moved from 200 to 250, but I think next 50 will be very slow. Because, now we are no longer aiming to sell, or hire people. But as luck would&#8217;ve been, we ended up creating this system of record, which is unified and cleaned. When we think of a client or a project or a human. All aspect of their metadata is available in a single system.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that is why we can leverage AI more than a company, agency to agency. For agencies using say, Jira for project management. QuickBook for accounting, some other software. If their operations is scattered across 6, 7 software, we have leverage over them. Not only we are paying very less because all our software is open source. The data is first party. Like sitting duck there to query in any way we can. We are not limited by SaaS providers, enterprise plan or this AI capability.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that is where we realised that we can take this huge bet on AI where we can now build a lot more, in a lot less time using AI across the board. And if you look at a business like not just WordPress business, when you buy something, like you buy a car from a car company. You are actually paying for everything that company does, advertising, researching on the EV technologies, hiring a brand ambassador to put billboard, sponsoring F1. Anything that company does. every penny they spend on their business, the customer ends up paying it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So we thought like now we have a single stack, which technically takes care of 70 to 80% critical nature of our business operations. From when the lead enters the CRM, the project management, time entry, people&#8217;s new management, everything is linked. Everything is beautifully linked in a single unified interface and database. So why don&#8217;t we just use AI to cut down the cost.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Because now we cannot charge by hours, we can try, but, it&#8217;s not making sense anymore for clients. They want us to commit to fix output bid. Now when we say, hey, we can migrate this thing for 100k, or we can build this website for half million dollars. So those numbers, traditionally, and actually all the time will include all the operation cost. Like my salary. I&#8217;m not doing any coding work, but my salary will be eventually paid by all the clients. Electricity bill that is also going to be paid by all the client.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So we thought like rather than just thinking AI to build a website, let&#8217;s use AI to bring our operational costs dramatically down. Because we have single source of truth for maximum data we have, and that is where we went all AI in. Now it&#8217;s like we can submit a proposal in one third of the time.</p>\n\n\n\n<p class=\"wp-block-paragraph\">In old days we used to build PPTs. Now we vibe code a WordPress demo site and attach it to the proposal. Hey is this something that you want? Not just the screenshot, not just the Figma, like we are actually building Playground, like websites, and launching them and sharing those links to the client. Go play with it. We are even trying to copy the design systems if they&#8217;re migrating. So migration is a big category of work we do.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that is what we mean by going AI ready. So we are leveraging AI to reduce the cost of sale, increase probability of winning the project by pitching them something. And then while estimating the effort, like let&#8217;s say we would traditionally say, oh, this might cost us a thousand hours. Now we blindly said Make it 30% less, as if it will be done in 700 hours and it will be, sometimes it backfires.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But then on some project it&#8217;ll be 500 hours. In some project it&#8217;ll be 900 hours, but average will come back to 700 hours. Then again, the idea is we have a central operating system, which gives us, like bird&#8217;s eye view of how healthy our projects education are. Are we getting returns on our AI engagement? And all this is possible because few years back we took a bet in different direction.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Like we choose WordPress because we wanted to be a better media agencies, and that was what media agencies were doing in the early days. But we ended up building an agency business with the WordPress. Likewise we choose this Frappe ERPNext software. To operationalise our back office. But now it is starting out to be our advantage point in this areas like we are able to do AI a lot more. In the end, it&#8217;s all about bringing the cost down at certain quality. You have to keep the quality up, and just make it more affordable. If that is not. as a business you cannot do that with AI, then something is wrong.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So AI is not about building something new. I have another approach. So if you&#8217;re an agency people are hiring you to move things from A to B, like you are the movers and packers of internet. I put crudely, what rtCamp does. We move things, like a shipping company who moves your house, remove you from Sitecore to WordSpace.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And that&#8217;s still big part of our business. We don&#8217;t have to reinvent or reimagine different experiences all the time. Sometimes we have to just do what everybody&#8217;s doing, the boring part. Put AI there to make it efficient, more cost effective. And if you do that, that means more people wanting to shift to new house. Again, a different approach. People think that they need to build something out of the world to benefit from this AI way.</p>\n\n\n\n<p class=\"wp-block-paragraph\">My idea is that pick a boring thing and make it so affordable that people who were sitting on the fence, just imagine travel, Middle East travel. Like this is a very actually a bad example, might sound inhuman, but, say like X number of people wanted to experience Dubai as a destination, but let&#8217;s say, it was beyond their budget. For some even unfortunately now suddenly that comes within their budget, they will be able to do that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">People wanted to move to WordPress Initially, agencies were quoting a hundred thousand dollars for that big shift. Now if you can, suddenly you can do it in 50k a lot more people will shift. So, you don&#8217;t have to do things like out of the world thing. You don&#8217;t have to invent new. You have to sometimes just make existing problem more efficient to solve.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And it was not always about money, especially in large client. It was not always about 100k versus 50k versus half million versus 1 million. It was about timeline. It&#8217;s like you are refurbishing your home and it is going to take three month, then it&#8217;s a different mental model, like to put up yourself in a hotel or a second home for three months. If a magically a new company appears and hey, we can refurbish your home overnight. You don&#8217;t mind checking into hotel for one night. And that is where I feel like this WordPress will be net gain because of AI. Agencies has to be optimistic, and think differently to gain from AI.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Like, what people are doing is everybody&#8217;s trying to act like a ChatGPT, OpenAI, it&#8217;s their job to invent AI algorithm. We are agency. Our job is to apply AI, not invent AI. We don&#8217;t have to think of what is Opus 4.8 will do. Let cloud engineers think of that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So we need to understand we are AI&#8217;s consumers or consultant, and that is where some people are getting it wrong by vibe coding things that they&#8217;re not able to sell to anyone. Then they will cry that, hey, six months later they will realise they built stuff nobody bought. Now they don&#8217;t have money to pay AI bills, or their developer salaries and then they will try that, hey, AI took over job, AI killed our business. No, think what existing problems we can solve with AI cheaply, efficiently, with better quality. And a lot of work is there to be done.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> There&#8217;s a lot in there, but one of the things that I&#8217;m taking out is. So prior to AI coming along and demonstrating to us all what it could do, which by the way didn&#8217;t kind of happen overnight, although it feels like it did, there was a sort of, a year in which we could suddenly see, oh boy, it&#8217;s getting much more performant and much more interesting. But prior to that, it sounds like post COVID, you kind of inspected your business and were thinking, okay, how can we refine everything that we&#8217;ve got in the business and how can we put it all into this one system?</p>\n\n\n\n<p class=\"wp-block-paragraph\">And again, with the benefit of hindsight, and I&#8217;m maybe going to use the word luck, maybe that&#8217;s not the right word. You, having done that work, then meant that when AI did come along, you weren&#8217;t trying to link up four or five or six or ten different things. You had this one source of truth. Which meant that you could cut waste, for want of a better word. You know, waste could be measured in terms of dollars or it could be measured in terms of time or it, whatever it may be.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You happened to be in that place because you&#8217;d done that preparatory work, not necessarily knowing that AI was going to come along and make all of this fun stuff possible. But with the benefit of hindsight, that&#8217;s exactly what it did.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And it&#8217;s curious, you said 70 or 80% of the business could be streamlined in that way. And I&#8217;m so staggered by that number. I thought you&#8217;d be in the kind of, I don&#8217;t know, 20, 30% or something like that. But a full 70 to 80%. So does that mean 70 to 80% of the things available, or do you mean that you were able to cut 70 to 80% of the cost or the time? Because I wasn&#8217;t sure which 70 or 80% you were meaning.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> It meant different things. First like, as I mentioned that we are not thinking AI adds just something to sell, but something to consume first. Because, again, dog fooding principle. We managed to sell WordPress better because we were a blog network. That&#8217;s why we could understood publishers better. We got into this Frappe ERPNext consulting because we built our backend with it. Now before we make any promise with AI, we have to be net gainer with the AI. And we believe that our internally, we will be.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So there are two parts, actual cost of building something and the meta cost. Like cost of sale, like the writing proposal. marketing costs, like case studies, going to even preparing for articles. Non build cost is definitely, we are able to bring, I would say it&#8217;s already half, but it&#8217;ll be, further down. I will give you a very simple example.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Like in early days is when somebody used to submit rtCamps form, inquiry form, a human, would manually check like, Hey, what is the domain name of this email id? Are they on LinkedIn? Some 30 minutes and then they will write a note hey, this looks like a good quality lead. We are fortunate that we get a lot of inbound inquiries, so we had to have prioritise, like which leads we are going to respond first.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Now, as soon as somebody submits a form an AI integration does that, within minutes. And the notes are much more details, it creates action items. Across like WordPress our Frappe CRM, our Slack, everything runs like a clockwork, and we don&#8217;t need a human. So that, junior human job is definitely gone. So in sales team, we used to have like this entry level job. That is no longer there. Some jobs are actually going to get vanished. So now going on a call, meeting notes, a lot of those things are getting automated. So the cost of sale has dramatically came down.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What is the effect? Like, say we can now assume flat 10% discount compared to earlier pricing when we are thinking of a migration project. Like, let&#8217;s say, in early days, we used to think like hey, anybody wanting to migrate from Adobe Experience Manager? We must assume that they need to pay us 100k. On the initial call, we can say, hey, that would probably cost something like minimum 50,000 dollars.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The minimums, the starting numbers has came down because we need less energy to have those pre-sales conversations. Less number of minutes of ours spent building those demos. Very fast discovery. Data mapping sometimes happens in minutes. In fact we did one 10 days to prepare this migration literally in five days, that was unthinkable. And that included data migration, QA testing, like automation testing where somebody built a bought in panel, which would randomly open a Zendesk ticket and verify that all metadata and deploys are migrated into new health desk system, all within five days.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This is where I have been saying that the cost of building custom solutions will fail. For like so low, like it&#8217;s 60, 70, 58. Like definitely more than half. It&#8217;ll be reduced by half more. People will buy custom solutions. So agencies are going to grow from here in just these one or two years. Because agencies, to price something upfront, we need consistencies. Like I&#8217;m running an airline and if my jet fuel is my biggest cost, and that is out of my control. Then how do I price my tickets? That&#8217;s AI hallucination, which is, I would say the jet fuel version of aviation industry.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Something happens in Middle East and fuel prices goes up. A war starts. So now when AI hallucinates so it&#8217;s like what we are internally tracking, or what we call as a KPI or internal metric is that, worst case, AI gains, that&#8217;s already 20%. Best case is more than 90%. In some cases it&#8217;s literally 90%. This range will keep compressing and that&#8217;s what I think 70% is my expectation in two years. We will have that maturity that, the build time will fall by 70%. That means. the client companies will hire more agencies to do more work.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress will emerge as a winner, not only for its ecosystem, but its ability to expose structured data without any proprietary walls. AI was so fast that only an open source can keep up with it. In fact, we are seeing more migration inquiries with with the AI boom.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> Oh, interesting. I was going to ask a sort of follow up question. Do you think that you, so you were mentioning, how to describe it, a rising tide carries all boats, or you certainly implied that the pie is getting bigger, if you know what I mean? So you are getting more phone calls, more migrations, more work, and you can obviously do that more affordably. And because you can pass on some of those savings to the clients, the price point lowers and so you get more inquiries because there&#8217;s this virtuous cycle of price going down, but quality staying the same or getting better.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I wonder if you, given your success in the past, I wonder if that transition will be easier for you, because the phone is already ringing, than it would be for somebody who was beginning in 2026? Because we all know when you begin, getting the phone to ring is probably the hardest thing. You know, getting those first 5, 10, 15 reliable clients, whatever it is that makes you work.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I wonder if you are in a uniquely good position, having a history of clients, a roster of clients that will come back to you. And also just being famous, for want of a better word, in the WordPress space, for doing the kind of things that you do. I wonder just what your thoughts are on that.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> They&#8217;re both pros and cons. The only con for rtCamp is that our business model, a big part of what&#8217;s traditional like setting our flagship revenue stream for last 8 to 10 years was staffing solutions. We used to provide engineers, sometimes to other agencies, sometimes to publishers. So usually they used to have the leadership layer with them. We were more of executors, and if AI within the IT industry, the first casualty of AI revolution was that people who code, or people who can only code but cannot think. But luckily our hiring was very different.</p>\n\n\n\n<p class=\"wp-block-paragraph\">While it is taking time, so as I said, net headcount addition has been slowed down. I think this is probably first time rtCamp&#8217;s career site doesn&#8217;t have any engineering opening. If we would&#8217;ve been like a publicly listed or like a shareholder owned company, we might have got mandate to fire a hundred people right now, because we have already gained by, so much that, our one third of our WordPress engineers are currently out of work when the work is rising.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Because traditionally, when we needed eight people, now we were able to do in four people. But now we are using this. We have our own challenges, going from one kind of business to another kind of business model. The switch is causing some friction, but we are communicating it openly. We are giving people like more freedom. You give us ideas like which part of the entire business equation you can optimise. Is it editorial experience, is it migration cost? Is it data mapping, visual testing? So people are constantly building.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So change is there. Change is scary. It is scary for us also because we don&#8217;t want to fire people. We don&#8217;t want to lay off people. We want to return this team. From here onwards, we don&#8217;t see we are hiring more engineers for at least a year, because we have enough of them. But, we are so optimistic about this WordPress growth and the pie getting bigger.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We are hiring more sales and marketing team. Two days back I was telling like traditionally, we had this 90 to 10% ratio, like in 200 people, our headcount team, we would have 20 people. That would be, we can call as a sales and marketing department, I think next 50 hires will be only sales and marketing.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> Oh, that&#8217;s a big skew, isn&#8217;t it? So you&#8217;ll go to more like 30% marketing as opposed to 10% marketing.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> Yeah sales and marketing. By the way, when we say sales, sales in rtCamp means slightly different. It&#8217;s more of a initial consulting, basically making those solid promise, which can be backed by engineering, not over promising. So our sales team needs are more like a WordPress consultant, but we have a category within rtCamp which we call Growth Engineers, who are some of our best coders. But rather than writing code, they go on the first client call and make promises on behalf of WordPress which are practical, feasible, and real.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That is what our internship look like, because coding is race to bottom. Eventually the cost of building will shrink to the point that you don&#8217;t need many, you won&#8217;t need many traditional developers in any agency. You will need people who can imagine what needs to be built. There might be 20 different ways and which way this project should be executed. That prompt engineering, context in engineering.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So the value is shifting and it&#8217;s definitely shifting away from people who can only code. That is why, probably from two years now, we might be at 300 people. Hundred of them will not be coding at all. But they will be prompting AI. They will be building vibe coded prototype in pre-sale stage to gain that customer confidence like early on that day. What you want is possible with the WordPress. It won&#8217;t cost that much. It&#8217;ll be given you fast enough that your life won&#8217;t be disrupted for many months, like your business operations won&#8217;t be disrupted for many months, so this is a thing</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> Yeah, nobody could deny that we&#8217;re in interesting times. I think a lot of people are very confused by what&#8217;s going on at the moment. You know, they&#8217;re trying to figure out a path. They&#8217;re trying to figure out how it affects their business. They&#8217;re probably in, I would imagine, quite a lot of cases, quite keen to stick to the ways that they&#8217;ve done it in the past. But certainly the picture that you&#8217;ve painted over at rtCamp is that you are aligning yourself with a very different future, kind of embracing AI, seeing where it can take you, trying to adapt your business. Being optimistic about it rather than pessimistic. Because I think there is quite a lot of pessimism around there at the moment. But seeing the opportunity and seizing it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Absolutely fascinating. There was so much to unpack there. I feel like we could talk probably for another nine hours about this because it genuinely is never ending. I would love to prize back the curtain a little bit more. However, time allows only this much. So what an interesting conversation. Thank you very much, Rahul.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Just before we end, could you just tell us where we can find you online, should somebody want to, you know, maybe they&#8217;re experiencing a bit of anxiety of their own. Their agency is in a rudderless ship at the moment and they&#8217;re trying to figure it out. Where can people get in touch with you best?</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> I am actually available on all social networks. I use LinkedIn least and email is most level way, I&#8217;m a bit old school there. But, yeah, Twitter. I check daily.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Nathan Wrigley:</strong> I will link to your bio in the show notes, but also, I will link to the presentation that you gave and any other bits and pieces that we discussed that I can find links for. I will mention those well. So head to wptaven.com, search for the episode with Rahul in it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Thank you so much for chatting to me, and all I can say is all the best. I hope that all of the intuitions that you have turn out to bear fruit and be fruitful for you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Thank so much for chatting to me today.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Rahul Bansal:</strong> Thank you Nathan.</p>\n</div></details>\n\n\n\n<p class=\"wp-block-paragraph\">On the podcast today we have <a href=\"https://www.linkedin.com/in/rahul286/\">Rahul Bansal</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Rahul has a long and accomplished history in the WordPress ecosystem. As the founder and CEO of  rtCamp, a company he started 17 years ago, he’s led his agency through the rapidly changing landscape of the web, helping enterprise clients such as Google, Fortune 500 companies, and major publishers solve complex problems with innovative WordPress-based solutions. <a href=\"https://rtcamp.com\">rtCamp</a> specialises in everything from large-scale website builds to more bespoke projects like Chrome extensions and SaaS connectors, and has grown to a team of hundreds over the years.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Today’s episode takes a deep dive into Rahul’s recent talk at WordCamp Asia, which focused on what it will take to launch and scale an enterprise WordPress agency in the future. The conversation focused on real, hard-won lessons from rtCamp’s journey, but also on how rapidly the playbook is changing with advances in technology, particularly the explosion of AI tools and workflows.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We discuss Rahul’s philosophy around hiring, namely, building a team of people whose strengths complement each other, rather than just replicating your own skillset. This approach has allowed rtCamp to adapt to new challenges, fill gaps in expertise, and weather major industry changes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We then explore how this idea of “complementary sets” can also apply to choosing the right kinds of clients, those who value your expertise because they need what you offer, rather than simply hiring someone who does what they already know.</p>\n\n\n\n<p class=\"wp-block-paragraph\">A theme that emerged in the conversation was specialisation. Rahul outlines how, whereas rtCamp’s earliest differentiator was a simple focus on WordPress (when virtually no one else in India was), today’s agencies must drill down much further to stand out, choosing niches within niches, such as WooCommerce or payment gateway integrations, and becoming recognised experts in those areas in order to thrive in a much more crowded field.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Towards the end of the episode the discussion turns toward what might be the most significant topic for agencies today, artificial intelligence. Rahul described how recent advances in AI have not only altered his agency’s practices, but have given them a firm mandate, if something within rtCamp can be done by AI, it will be.</p>\n\n\n\n<p class=\"wp-block-paragraph\">We talk about how AI is being leveraged inside rtCamp to automate and optimise everything from sales and proposal writing to project management and even technical proof-of-concept builds. With a unified platform for all business processes, the agency is now able to significantly reduce costs, speed up delivery, and focus on higher-value consulting and creativity, reshaping roles and team composition as a result.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you’re interested in what it takes to stand out and succeed in the evolving world of enterprise WordPress agencies, how to confront uncertainty with both optimism and realism, and how AI can become not just a bolt-on feature but the operational backbone of your business, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://rtcamp.com\">rtCamp</a></p>\n\n\n\n<p class=\"wp-block-paragraph\">Rahul&#8217;s presentation at WordCamp Asia 2026: <a href=\"https://asia.wordcamp.org/2026/session/how-to-start-an-enterprise-wordpress-agency-in-2026/\">How to start an enterprise WordPress agency in 2026</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.tv/2026/04/21/how-to-start-an-enterprise-wordpress-agency-in-2026/\">The same presentation on WordPress.tv</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://rtcamp.com/blog/17-years-of-good-work/\">A year of reinvention as we turn 17</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://frappe.io\">Frappe tools</a> mentioned several times during the podcast</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://x.com/rahul286\">Rahul on X</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://www.linkedin.com/in/rahul286/\">Rahul on LinkedIn</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 17 Jun 2026 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:39;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:94:\"Open Channels FM: BackTalk on Mission, Media, Localization, AI, and Giving Back to Open Source\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555607\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:97:\"https://openchannels.fm/backtalk-on-mission-media-localization-ai-and-giving-back-to-open-source/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:189:\"The content reflects on past discussions highlighting the importance of amplifying diverse voices, localizing strategies, and contributing to the open-source ecosystem for future relevance.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 17 Jun 2026 09:40:01 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:40;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:16:\"Matt: Audio Wars\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153172\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"https://ma.tt/2026/06/audio-wars/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1875:\"<p class=\"wp-block-paragraph\">It looks like Ubiquiti is coming for Sonos with its <a href=\"https://store.ui.com/us/en/category/premium-iot/products/upl-port\">PoE Audio Port, a $199 device</a> that closely resembles <a href=\"https://amzn.to/4vXqjcH\">the $499 Sonos Port</a>, and <a href=\"https://store.ui.com/us/en/products/upl-amp\">$599 PowerAmp</a>. Sonos is going up-market with <a href=\"https://www.sonos.com/en-us/shop/amp-multi\">the Amp Multi</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Sonos has <a href=\"https://www.bloomberg.com/news/features/2026-03-10/sonos-new-speaker-heralds-revival-under-ceo-tom-conrad-after-app-fiasco?sref=tT7Af65V\">had a rough patch</a>, but I&#8217;m pretty ride or die for them, and some of my favorite people are there: <a href=\"https://www.linkedin.com/in/tomconrad/\">Tom Conrad, the CEO</a>, <a href=\"https://www.linkedin.com/in/hbarra/\">Hugo Barra on the board</a>, and <a href=\"https://miketatum.com/\">Mike Tatum</a> in CorpDev (he&#8217;s the guy who got me to drop out of college and join CNET back in 2004!).</p>\n\n\n\n<p class=\"wp-block-paragraph\">The only time I don&#8217;t do Sonos in a home is for the <a href=\"https://syngspace.com/\">amazing audio experience of Syng Alpha</a>. The triphonic thing can be really magical. (Analog/vinyl is <a href=\"https://ma.tt/2009/04/visiting-shindo-labs/\">still Shindo Laboratories</a>, but that&#8217;s just for special occasions.)</p>\n\n\n\n<p class=\"wp-block-paragraph\">For headphones right now, it&#8217;s either <a href=\"https://www.colorware.com/collections/wordpress\">some custom Airpods Pro 3</a> or <a href=\"https://amzn.to/44c5wGf\">the Sennheiser HDB 630</a> (<em>Hat tip: <a href=\"https://pud.com/\">Pud</a></em>, who is also making some crazy headphones).</p>\n\n\n\n<p class=\"wp-block-paragraph\">On the go, I love pairing two <a href=\"https://amzn.to/4fQSchD\">Logitech Megaboom 4s</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 17 Jun 2026 06:59:03 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:41;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"Open Channels FM: Summer Updates New Features and Changes to Open Channels FM\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555698\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:84:\"https://openchannels.fm/summer-updates-new-features-and-changes-to-open-channels-fm/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:192:\"Bob Dunn updates on Open Channels FM\'s recent developments, including a homepage redesign, the launch of \"Do the Woo\" as a standalone podcast, and upcoming features like Open Channels FM Live.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 16 Jun 2026 11:55:19 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:42;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:20:\"Matt: Assorted Links\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:23:\"https://ma.tt/?p=153102\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:39:\"https://ma.tt/2026/06/assorted-links-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:10498:\"<p class=\"wp-block-paragraph\">Sometimes you have to just start with beauty.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Listen to <a href=\"https://open.spotify.com/album/3eXr4s3rCLxNJpxqaIDyqJ?si=Z2vNOEF2Rm-s6BAkCVN4hg\">Jon Batiste&#8217;s <em>Beethoven Blues</em></a>, then <a href=\"https://www.youtube.com/watch?v=7VM8MsR4K10\">relish this interview, where he plays and talks about it</a>. I can&#8217;t <a href=\"https://theisolationjournals.substack.com/p/black-mozart\">wait for Black Mozart</a>, which is already starting <a href=\"https://open.spotify.com/prerelease/4WWjrjAmp0Xqah9zqgir4M?si=6ea98fbd9d1d40ee\">to trickle on Spotify</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Forget all <a href=\"https://www.ferrari.com/en-EN/auto/ferrari-luce\">that Ferrari stuff</a>, what <a href=\"https://www.wallpaper.com/design-interiors/lighting/jony-ive-lovefrom-balmuda-sailing-lantern\">Jony Ive did with his LoveFrom Sailing Lantern</a> is divine. I&#8217;ve now seen it in person, and it&#8217;s the light at the end of the tunnel.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-153109\" height=\"340\" src=\"https://i0.wp.com/ma.tt/files/2026/06/sailing-lantern-1024x576.jpg?resize=604%2C340&#038;quality=89&#038;ssl=1\" width=\"604\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">That led me to discover how awesome <a href=\"https://us.balmuda.com/\">Balmuda is</a>, and stumble upon the Japanese word <em>Monozukuri</em>, which, according to Google, &#8220;(ものづくり) is a foundational Japanese philosophy that translates literally to <em>the art and science of making things</em>&#8221; It goes far beyond standard manufacturing or production, representing a deep, holistic mindset that embraces craftsmanship, a relentless pursuit of perfection, pride in one&#8217;s labor, and a deep respect for materials.&#8221; Look <a href=\"https://global.toyota/en/newsroom/corporate/39758220.html\">at how Toyota embodies it</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Om has a <a href=\"https://om.co/2026/06/07/the-myth-the-mythos-and-the-man/\">beautiful and prescient post on The Myth, the Mythos and the Man</a>.  It predicted some of this <a href=\"https://www.techmeme.com/260615/p20#a260615p20\">Fable kerfuffle</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Connection</h2>\n\n\n\n<p class=\"wp-block-paragraph\">How <a href=\"https://source.android.com/docs/core/ota/modular-system/tethering\">amazing is tethering on Android</a>? I have a <a href=\"https://amzn.to/49TXYeM\">Pixel 10 Pro</a> with a USB-C Ethernet hub plugged into the WAN port of a <a href=\"https://store.ui.com/us/en/products/udr-5g-max\">Unifi Dream Router 5G Max</a> because the <a href=\"https://www.qualcomm.com/modems/products/snapdragon-x62-5g-modem-rf-system\">Qualcomm chip Unifi uses</a> is two generations behind what&#8217;s in the phone. (Hat tip: <a href=\"https://jesse.blog/\">Jesse</a>.) How <a href=\"https://satellitemap.space/constellation/starlink\">amazing are the 10,653 Starlink satellites floating above us, providing broadband from space</a>, from a company I heard <a href=\"https://x.com/gjurvetson/status/2065452568902279655\">might have had an IPO last week</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I reconfigure ports, channels, and flows, as nurses do for arteries and cannulas.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Numbers Don&#8217;t Lie, Check The Scoreboard</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Not <a href=\"https://www.nytimes.com/athletic/7355407/2026/06/13/knicks-nba-championship-game-5-win/\">just the Knicks</a>. After a 3-year hiatus of Review Signal benchmarks, the headline was <a href=\"https://www.therepository.email/review-signal-publishes-2026-hosting-benchmarks-after-three-year-gap-powered-by-its-own-open-source-load-testing-platform\">that Pressable dominated every category</a>, and with perfect uptime. However, the real story is about <a href=\"https://wp.cloud/\">WP.cloud</a>, which is behind the top scores for not just Pressable and WordPress.com but also the <a href=\"https://www.bluehost.com/cloud-hosting\">Bluehost Cloud plans</a>, beating <a href=\"https://www.oracle.com/cloud/\">Oracle Cloud</a> and <a href=\"https://cloud.google.com/\">GCP</a>-based solutions. </p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wp.cloud/\">WP.cloud</a> is <a href=\"https://ma.tt/files/2026/06/bezos-aws.jpeg\">our AWS</a>; <a href=\"http://pressable.com/\">Pressable</a> is our demo site. We want <em>every</em> host to offer the fastest and <em>most secure</em> WordPress possible. I&#8217;m happy to focus on infrastructure and let others figure out marketing and such <a href=\"https://en.wikipedia.org/wiki/Hi_and_Lois\">foofram</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you speak Danish and would like a random Radical Speed Month art project detour, check out <a href=\"https://automattic.github.io/nima/\">Joen Asmussens&#8217; Nima</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://automattic.com/\">Automattic</a> has been shipping, shipping, shipping. <a href=\"https://wordpress.com/blog/2026/06/10/wordpress-com-is-now-available-in-stripe-projects/\">Start a WP.com site from the terminal with Stripe Projects</a>. <a href=\"https://akismet.com/blog/introducing-the-official-akismet-php-sdk/\">Akismet PHP SDK</a>. Fun experiments from Radical Speed Month like <a href=\"https://wordpress.com/blog/2026/04/27/studio-code-beta/\">Studio Code</a>, <a href=\"https://www.stattic.net/\">Stattic</a>, <a href=\"https://wordpress.com/workspace/\">Workspace Mac App</a>, <a href=\"https://github.com/Automattic/cortext\">Cortext</a>, <a href=\"https://pressship.org/\">Pressship</a>, <a href=\"https://wapuu.studio/\">Wapuu Studio</a>,  <a href=\"https://studiowrite.app/\">Studio Write</a>, <a href=\"https://wordpress.org/plugins/desktop-mode/\">Desktop Mode</a>, <a href=\"https://flavorpress.io/\">FlavorPress</a>, <a href=\"https://github.com/jonathanbossenger/concilium\">Concilium</a>, <a href=\"https://developer.woocommerce.com/2026/05/07/woocommerce-for-claude/\">WooCommerce insights in Claude</a>, and <a href=\"https://en.wikipedia.org/wiki/Kaizen\">the <em>kaizen</em></a> of hundreds of behind-the-scenes bug fixes and improvements across our product suite. </p>\n\n\n\n<p class=\"wp-block-paragraph\">Much of this came from those not historically in a product or engineering role, which we&#8217;re learning to navigate. I loved how customer-centric many things were. We also made a lot of rookie mistakes, but that&#8217;s part of how you learn, and I believe the acceleration of learning will be the biggest legacy of the Radical Speed Month experiment. That, and the fun games on <a href=\"https://automattic.com/work-with-us/\">our intranet</a>. <img alt=\"🙂\" class=\"wp-smiley\" src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f642.png\" style=\"height: 1em;\" /></p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-153136\" height=\"201\" src=\"https://i0.wp.com/ma.tt/files/2026/06/automattic-game-center-banner-1024x341.jpeg?resize=604%2C201&#038;quality=89&#038;ssl=1\" width=\"604\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">AI Hangover</h2>\n\n\n\n<p class=\"wp-block-paragraph\">I have <a href=\"https://ma.tt/2023/10/wowza/\">drunk from the sweet nectar of Waymo</a>, and now find myself calling an Uber so I can talk to 72-year-old Antoly from Azerbaijan, whom I slip a hundred-dollar bill as I step out. I weep when I see talented colleagues speak and write with words not quite their own. I <a href=\"https://www.pangram.com/\">masochistically Pangram everything</a> even though it sometimes mistakes my own hand-crafted prose for slop, or is that actually my soul being sanded down by consuming too many statistically probable next tokens?</p>\n\n\n\n<p class=\"wp-block-paragraph\">The uncanny valley of software, writing, products, and presentations so polished on the surface but built on thin foundations of understanding gives me an almost physical, nauseous reaction. I write this even as I listen to <a href=\"https://www.youtube.com/watch?v=tRsQsTMvPNg\">Claude FM music for thinking and building</a>,  probably <a href=\"https://ma.tt/files/2026/06/mythos-jailbreak-791x1024.jpeg\">Mythos-injected with subliminal messages</a> to remind me of the hours of audio transcribed in minutes; the programs that would have taken a team months, conjured from my hand in hours; the way I feel <a href=\"https://www.youtube.com/watch?v=8XV8aBNOIqI\">like Neo in the Matrix</a>, rapidly downloading new domains of knowledge.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What&#8217;s the name for the paradox, <a href=\"https://en.wikipedia.org/wiki/Jevons_paradox\">like Jevon&#8217;s</a>, that AI abundance and polish makes you crave messy, imperfect humanity even more?</p>\n\n\n\n<p class=\"wp-block-paragraph\">It&#8217;s good to debate and ruminate, but only in small doses. Like salt in a dish, a little goes a long way. Avoid the <a href=\"https://pmc.ncbi.nlm.nih.gov/articles/PMC11036542/\">existential angst</a> of charting new territory by getting your hands dirty and trying things. You learn the most from failures when you can <a href=\"https://apagefrommunakusbook834350529.blog/2023/02/03/learning-to-laugh-at-yourself/\">laugh at yourself</a>.  <a href=\"https://amzn.to/4vmWaDB\">Build one to throw away</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Write Different</h2>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Writing is not the most important thing; thinking is. But writing is probably the best way to improve your thinking.</p>\n</blockquote>\n\n\n\n<p class=\"wp-block-paragraph\">I saw this quote attributed to me and didn&#8217;t remember it, so I thought it might be an AI hallucination, but it&#8217;s actually something I said! In <a href=\"https://perell.com/podcast/matt-mulleweg/\">this early-years podcast with David Perell</a> buried on some corner of his site. Now <a href=\"https://www.youtube.com/@DavidPerellChannel\">David&#8217;s production quality is stellar</a>, and he gets amazing guests like <a href=\"https://www.youtube.com/watch?v=yb9Tz-RQFN4\">Maria Popova to discuss their craft</a>. I&#8217;ve enjoyed his rise and look forward to <a href=\"https://perell.com/\">following him</a> in the decades to come.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\" />\n\n\n\n<p class=\"wp-block-paragraph\">I could edit and link much more, but sometimes you have to just <a href=\"https://vimeo.com/12238385\">press the Publish button</a> and <a href=\"https://www.youtube.com/watch?v=bJVOo4K_GGM\">let go</a>.</p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 15 Jun 2026 19:20:04 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"Matt\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:43;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:96:\"Open Channels FM: The Balancing Act: Freedom, Convenience, and Open Source in an AI-Driven World\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555638\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:100:\"https://openchannels.fm/the-balancing-act-freedom-convenience-and-open-source-in-an-ai-driven-world/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:341:\"So many of us are in a evolving relationship between freedom, convenience, and open source software in the world shaped by AI. The promise of freedom which is central to the open web and open source movements has to be continually weighed against the growing demand for convenience and simplicity. While open source software offers [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 15 Jun 2026 12:16:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:44;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:49:\"Akismet: Introducing the official Akismet PHP SDK\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:28:\"http://akismet.com/?p=284799\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:66:\"https://akismet.com/blog/introducing-the-official-akismet-php-sdk/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:4711:\"<figure class=\"wp-block-image size-large\"><img alt=\"\" class=\"wp-image-284805\" height=\"429\" src=\"https://akismet.com/wp-content/uploads/2026/06/screenshot-2026-06-10-at-11.38.37-am.png?w=1024\" width=\"1024\" /></figure>\n\n\n\n<div class=\"wp-block-jetpack-markdown\"><p>For twenty years, Akismet has kept spam out of WordPress. But spammers don’t care what your site runs on and neither do we.</p>\n<p>Last month we launched the <a href=\"https://akismet.com/blog/introducing-the-official-akismet-drupal-module/\">official Akismet Drupal module</a>. Today we’re introducing the engine that powers it: the official Akismet PHP SDK, a first-party client that brings Akismet to any PHP application.</p>\n<h2 id=\"what-it-is-and-who-itâ€™s-for\">What it is, and who it’s for</h2>\n<p>The Akismet PHP SDK is a first-party PHP client for the Akismet API. It’s built for the platforms the WordPress plugin doesn’t reach: custom apps, SaaS backends, and PHP frameworks like Laravel and Symfony. (The official plugins are still the way to go for <a href=\"https://wordpress.org/plugins/akismet/\">WordPress</a> and <a href=\"https://www.drupal.org/project/akismet_antispam\">Drupal</a>.)</p>\n<p>Under the hood it’s built to feel at home in a modern PHP codebase:</p>\n<ul>\n<li>Covers the full Akismet API, from comment-check and spam/ham submissions to key verification, usage limits, and account stats.</li>\n<li>Works with any PSR-18 HTTP client you already have (Guzzle, Symfony HttpClient, and the like) through auto-discovery.</li>\n<li>Ships a typed exception hierarchy that redacts your API key, so credentials never leak into your logs.</li>\n</ul>\n<h2 id=\"a-two-minute-quick-start\">A two-minute quick start</h2>\n<p>Install it with Composer:</p>\n<pre><code class=\"language-bash\">composer require automattic/akismet-sdk\n</code></pre>\n<p>Then check a submission:</p>\n<pre><code class=\"language-php\">use Automattic\\Akismet\\Akismet;\nuse Automattic\\Akismet\\DTO\\Content;\nuse Automattic\\Akismet\\Enum\\ContentType;\n\n$akismet = Akismet::create(\n    apiKey: \'your-api-key\',\n    site: \'https://your-site.com\',\n);\n\n$content = new Content(\n    userIp: $_SERVER[\'REMOTE_ADDR\'],\n    userAgent: $_SERVER[\'HTTP_USER_AGENT\'],\n    body: $formData[\'message\'],\n    authorEmail: $formData[\'email\'],\n    type: ContentType::ContactForm,\n);\n\n$result = $akismet-&amp;gt;check($content);\n\nif ($result-&amp;gt;isSpam()) {\n    // Reject it, flag it, or queue it for review.\n    // $result-&amp;gt;shouldDiscard() marks the blatant spam you can drop outright.\n}\n</code></pre>\n<p>That’s the loop: build a <code>Content</code> object, call <code>check()</code>, act on the result.</p>\n<h2 id=\"already-running-in-production\">Already running in production</h2>\n<p>The official Akismet <a href=\"https://www.drupal.org/project/akismet_antispam\">Drupal module</a> is built on this SDK. The SDK handles the API contract and type safety, while the module handles Drupal’s service wiring, queues, and moderation UI. That’s the pattern for Laravel, Symfony, and anything else you build: the SDK owns the Akismet integration and your framework owns the glue.</p>\n<h2 id=\"whatâ€™s-new-in-1-5-0\">What’s new in 1.5.0</h2>\n<p>We have just released v1.5.0, which is about giving Akismet more to work with, and giving you more back:</p>\n<ul>\n<li><strong>Richer content signals:</strong> <code>Content</code> now carries the site’s language and character set, plus the surrounding conversation context, so every check has more to go on.</li>\n<li><strong>More insight into every verdict:</strong> <code>CheckResult</code> now surfaces the error and classification Akismet returns, so you can log and act on <em>why</em> something was flagged, not just whether it was.</li>\n<li><strong>Extended multi-site reporting:</strong> For keys that span many sites, the new extended key-sites data adds per-site metadata for cleaner reporting and account hygiene.</li>\n</ul>\n<h2 id=\"get-started\">Get started</h2>\n<p>The SDK is open source and live on Packagist today.</p>\n<ul>\n<li>Install: <code>composer require automattic/akismet-sdk</code></li>\n<li>Packagist: <a href=\"https://packagist.org/packages/automattic/akismet-sdk\">automattic/akismet-sdk</a></li>\n<li>Source and docs: <a href=\"https://github.com/Automattic/akismet-sdk-php\">github.com/Automattic/akismet-sdk-php</a></li>\n</ul>\n<p>You’ll need an Akismet API key to make calls. Akismet’s <a href=\"https://akismet.com/pricing/\">Personal plan</a> is pay-what-you-can and free for personal, non-commercial sites. If you’re running something commercial, pick a paid plan that matches your traffic. Either way your code stays identical, since the plan lives with your API key, not in the SDK.</p>\n</div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 15 Jun 2026 10:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Derek Springer\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:45;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"Open Channels FM: The Changelog: Still Here, Still Doing It\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555551\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:64:\"https://openchannels.fm/the-changelog-still-here-still-doing-it/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:305:\"A bit over four years ago, in 2022, I recorded an episode from San Diego. I was getting ready for an event, about to attend my first-ever Contributor Day (which, yes, felt a little absurd given how many WordCamps I&#8217;d been to by that point). To fill the time before things kicked off, I sat [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Fri, 12 Jun 2026 08:10:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:46;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:40:\"Dennis Snell: Gutenberg Package Activity\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:36:\"https://fluffyandflakey.blog/?p=3901\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:67:\"https://fluffyandflakey.blog/2026/06/11/gutenberg-package-activity/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:1001:\"<p class=\"wp-block-paragraph\">Last week at <a href=\"https://europe.wordcamp.org/2026/\">WordCamp Europe</a> there was a get-together among WordPress Core committers and a question arose concerning the separate Gutenberg <code>npm</code> packages that are built and distributed. I was curious about how frequently they are updated and which ones are most active, so I asked Codex to review <code>git</code> commit activity, gather commits per package which touch files in that package, and then render it into a plot. It produced this.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Also available <a href=\"https://fluffyandflakey.blog/wp-content/uploads/2026/06/gb-package-rates.html\">as a PNG image</a>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Script available <a href=\"https://gist.github.com/dmsnell/107642d8791e5bb88c4a3f9c521dad3d\">in a gist</a>.</p>\n\n\n\n<div class=\"wp-block-group alignwide\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n\n</div></div>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 11 Jun 2026 20:34:47 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Dennis Snell\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:47;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:97:\"Open Channels FM: WordCamp Europe Takeaways: Community Vibes, Tech Advancements and Smarter Tools\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555456\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:102:\"https://openchannels.fm/wordcamp-europe-takeaways-community-vibes-tech-advancements-and-smarter-tools/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:215:\"This Open Channels FM episode from WordCamp Europe discusses the event\'s vibrant atmosphere, the integration of AI in WordPress workflows, and the positive community outlook on evolving technology and opportunities.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 11 Jun 2026 08:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:48;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:104:\"WPTavern: #220 – Cathy Mitchell on Why WordPress Events Matter: Community, Connection, and Giving Back\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"https://wptavern.com/?post_type=podcast&p=204704\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:115:\"https://wptavern.com/podcast/220-cathy-mitchell-on-why-wordpress-events-matter-community-connection-and-giving-back\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:52587:\"<details>Transcript<div>\n<p class=\"wp-block-paragraph\">[00:00:19] <strong>Nathan Wrigley:</strong> Welcome to the Jukebox Podcast from WP Tavern. My name is Nathan Wrigley.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Jukebox is a podcast which is dedicated to all things WordPress, the people, the events, the plugins, the blocks, the themes, and in this case, why WordPress events and community matter.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;d like to subscribe to the podcast, you can do that by searching for WP Tavern in your podcast player of choice, or by going to wptavern.com/feed/podcast, and you can copy that URL into most podcast players.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you have a topic that you&#8217;d like us to feature on the podcast, I&#8217;m keen to hear from you and hopefully get you, or your idea, featured on the show. Head to wptavern.com/contact/jukebox, and use the form there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So on the podcast today, we have Cathy Mitchell. Cathy has been working with WordPress since 2007. What began as a fun personal project during her maternity leave soon evolved into a fully fledged business with the launch of WPBarista in 2008. Over the years, Cathy has garnered extensive experience in the WordPress space, and is now working towards the 2026 WordCamp Canada.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The conversation focuses on the powerful role of community within the WordPress ecosystem, something that Cathy is deeply passionate about. We discuss how open, welcoming, and international the WordPress community feels, compared to more traditional corporate or volunteer environments. A theme that emerged was how involvement in WordPress has provided Cathy, and many others, with a sense of belonging and fulfilment, especially after life changes like becoming an empty nester.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The discussion explores the motivations for volunteering and organising within the WordPress community, both from the perspective of newcomers looking for purpose and connection, and business owners assessing the return on investment from contributing or sponsoring events. This includes how easy it is to get involved, the unique lack of barriers and red tape, and the value of altruism and camaraderie.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Other topics we explored with a broader impact of technology and loneliness, the importance of service and community for wellbeing, challenges in sponsorship amid changes economic times, and the vital need to engage the next generation in open source.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re interested in the human side of WordPress, how volunteering shapes both individual and the broader community, and what the future might hold for WordPress events and contributors, this episode is for you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you&#8217;re interested in finding out more, you can find all of the links in the show notes by heading to wptavern.com/podcast, where you&#8217;ll find all the other episodes as well.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so without further delay, I bring you Cathy Mitchell.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I am joined on the podcast by Cathy Mitchell. Hello, Cathy.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:25] <strong>Cathy Mitchell:</strong> Hello. Thanks for having me.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:27] <strong>Nathan Wrigley:</strong> You are very welcome. Cathy and I have been having, well, 15 minutes or so of chit chat just before we started the podcast. I&#8217;ve been learning a little bit about Cathy and we&#8217;re going to share all sorts of information.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I think probably broadly we could talk about it as being the WordPress community, which is a subject which is dear to my heart.</p>\n\n\n\n<p class=\"wp-block-paragraph\">However, before we get into that, Cathy, I&#8217;ve had an introduction from you over the last few minutes, but would you mind sort of giving us your potted version of that, your shorter version, your bio if you like. Tell us who you are and how come you&#8217;re featuring on a WordPress podcast.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:03:58] <strong>Cathy Mitchell:</strong> Well that&#8217;s a whole lot of imposter syndrome. Why I am featuring, because you&#8217;re kind enough to have me. I&#8217;ve been working with WordPress since 2007 and it was just something fun that I did to begin, much like you with podcasting.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And then a couple years in, I told my friends that they&#8217;d have to start paying me, or I was going to go back to work, find a real job. This was during my mat leave, and so it kind of just took off from there in 2008, started WPBarista.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And now I&#8217;m very interested in the community because I was looking for something to do in the WordPress community last year. Dan in the Canada Slack got a hold of me and said, hey, do you want to help with the WordCamp? And I said, sure. You know, I had time.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And he got me in and brought me right up to like being on the organising team. And it was so fun but so shocking. Like, there is a lot of red tape in the corporate world before they let you do anything meaningful. Like you have to sweep the floors for a whole long time before they let you actually do something you&#8217;re good at. So this was remarkable. And this year I find to my surprise, I&#8217;m leading the 2026 WordCamp Canada.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So that&#8217;s what I&#8217;m doing now. And we&#8217;re going to focus on community too. So I&#8217;m very excited about this topic, both from a corporate, like what do we get out of this? Or are we supposed to get something out of this? And from a personal standpoint, it&#8217;s been amazing to meet these people, and to be given a chance. And I found out I&#8217;m not the only one. This is like normal, which is bizarre and wonderful.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:05:37] <strong>Nathan Wrigley:</strong> My experience of the WordPress community, so I started in WordPress actually quite a long time after you did. Maybe sort of six or seven years after you began using WordPress. I really didn&#8217;t know that there was a community at all. I just downloaded the software and used the software. And then I can&#8217;t even remember really how it happened. It might have been through things like Facebook Groups or something like that, where I was trying to learn a particular thing? Or perhaps there was something in the dashboard which indicated that there was an event nearby.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But I found myself, to my own surprise actually, I found myself at a WordPress event in London, WordCamp London, which at the time was going really strong. You know, hundreds and hundreds of people would show up every year.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I remember purchasing a ticket and getting the train ticket and thinking, what am I doing? What am I possibly hoping to get out of this? And showing up and kind of being a bit like a timid rabbit sitting in the corner a little bit, and then it kind of worked out fairly quickly. Okay, this is all fairly benign. Nobody seems to be all that boastful. Nobody seems to be sort of shoving corporate speech down my throat, or trying to sell me anything unnecessarily.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And during the course of a day or maybe a couple of days, opened up a little bit and got chatting to people. And lo and behold, within a couple of years, a significant proportion of my free time, let&#8217;s call it that, outside of the commitments of daily life and family and all of that kind of thing, was taken up with doing WordPressy things in my spare time.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so I, I don&#8217;t know if the story maps the same as you, I&#8217;ve shared mine, maybe you&#8217;ll share something similar in a moment. The community to me is much more than just, oh, there&#8217;s a community there. It genuinely is a seriously important part of my life. To the point where if that was to be sort of whipped away, or somebody like a Thanos type character suddenly clicked their fingers and that disappeared, I don&#8217;t know what I would do with myself. I would really have to go out there and find an awful lot of other things to do. Was it a bit like that for you?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:07:41] <strong>Cathy Mitchell:</strong> Not at all. I went to the forums first. And in 2008, 2009, there were some big names nowadays that were just answering us in the support forums. And so I learned from the best of the best, I think. And they would answer my ridiculous questions. I had no idea about PHP. I didn&#8217;t even know HTML. I didn&#8217;t even know what the internet was, like as broad concept. I asked my husband at the time like, okay, I don&#8217;t understand how my computer is talking to someone else&#8217;s computer, like you need to draw me a picture.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So anyway, I&#8217;ve only recently, I went to a couple of events, but I&#8217;ve always had the business mind. If I can&#8217;t see an ROI financially, I&#8217;ll say, from what I&#8217;m doing, then I don&#8217;t have time for it. But that was also during a time when I had a young family and then I became a single mum and then I had to work this business. And so it&#8217;s only really recently that I&#8217;m looking around and seeing people like you and going, this is unique.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I&#8217;ve been in volunteer communities, and now that my kids are all grown up, I&#8217;m kind of looking for those opportunities. What meaningful thing can I do with my time? And this just seems so unique. Like I volunteered at other places and there&#8217;s so much red tape and there&#8217;s so much, I don&#8217;t know, different feelings than this one. This one&#8217;s very open.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:09:09] <strong>Nathan Wrigley:</strong> I think the bit that is so curious to me is you can sort of dip in and dip out of it. Because, I don&#8217;t know, let&#8217;s say for example, you do something much more local, involved with your hometown or something like that. And you get involved in it and there&#8217;s a certain kind of, pressure is the wrong word, I suppose you can dip in and dip out of that as well, but do you know what I mean? You get involved in those philanthropic things locally and you get to know things and it becomes more of a habit, and you do the same thing over and over again. At least that&#8217;s my experience.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What I quite like about this is the international flavour of it. The fact that I&#8217;m being introduced people from really different parts of the world and cultures. And it&#8217;s very, very open, and it&#8217;s a real contrast to the bit that you just mentioned, where the corporate bit, and obviously there&#8217;s a side of our community which is very much devoted to turning a profit and what have you. But there&#8217;s a significant proportion of the people who don&#8217;t have that metric in their head when they&#8217;re introducing themselves to people.</p>\n\n\n\n<p class=\"wp-block-paragraph\">They are just trying to be helpful and trying to deliver on the promise that the internet gave us back in the 1990s of, here&#8217;s the infrastructure to pass information around freely. Wouldn&#8217;t it be nice if everybody had the capacity to publish things, or to share things online without some sort of corporate overlord or paywall or algorithm? Which we&#8217;ve now probably regret deeply allowing that to happen to the internet.</p>\n\n\n\n<p class=\"wp-block-paragraph\">All of those kind of things come into play. I have constantly, for the last decade, tried to sum up and capture what this is. And I always fail. It simply feels nice, is all that I&#8217;ve got, really. This community, the people in it that I hang out with, it just feels like a nice thing to do. That&#8217;s all I&#8217;ve got. No wisdom beyond that. It&#8217;s bizarre, isn&#8217;t it?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:10:53] <strong>Cathy Mitchell:</strong> I&#8217;ve been trying to quantify it too, and especially planning this next conference. I feel much like a student because there&#8217;s a large group, probably most people are not like me. Like they&#8217;re like you, at least the ones, in Slack that I&#8217;m talking to on a daily basis. And they&#8217;re the original nerds who are so happy, like were inspired and spent their free time, like this wasn&#8217;t their job. Promoting this and like answering my questions in forum as an absolute noob. So in that way I feel like I would really like to give back now.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But the community, yeah, I can&#8217;t quite put my finger on. I just talked to a sponsor yesterday and she is of course wanting to get in front of her audience, which is agency owners. But there&#8217;s a real sense of promoting the community because the healthier the community, the healthier all of us are. Not just financially, but it creates the forward momentum, I think as far as open source as a whole too. Like there&#8217;s a bunch of us, me included, even though I kind of am taking a corporate angle that really believe that open source could change the world. I still do, maybe even more so because AI is, can actually talk to things that are open source. Less so if everything&#8217;s behind a paywall.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:12:09] <strong>Nathan Wrigley:</strong> I think one of the things that you mentioned there, which suddenly sort of struck me is whilst there are a handful of people out there, and I say a handful, there&#8217;s obviously many millions of people. I think it&#8217;s fair to say that many people prefer to be in proximity to other people, to do things, to be in conversation with people, to have a shared experience. You know, we go to the cinema or the movie theatre to watch a movie. I mean I know the screen&#8217;s bigger and everything, but part of it is to be with other people and to go ooh and ah, at the same time and go to firework displays and concerts and things like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Now all of that stuff can be done in an isolated environment in your house. You know, you can watch Netflix and you can watch the TV and get a similar kind of experience. But I think there&#8217;s some sort of core part of me at least, and the people that I hang out with at these kind of events and online who just enjoy that shared experience, that willingness to be involved in a similar task. Just to be pointing in the same direction as a bunch of other people, pulling together on the same team. And it&#8217;s unquantifiable. I literally can&#8217;t encapsulate it, but I think you and I are talking about the same thing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What&#8217;s interesting is I accidentally found it fairly early on in my WordPress journey. Serendipity played a really blinding hand for me there. But I think had I not had, bit like that film Sliding Doors, I could easily have missed the cues which sent me to that WordCamp or whatever it was that got me started. And I probably could have gone for a decade or more and not even noticed it was a community and maybe discovered it much more recently.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And it sounds like that&#8217;s kind of happening to you. You mentioned that you are, I think in the show notes you described it as, it&#8217;s a lovely phrase, empty nesting. Does that mean when your children grow up and go away? Is that what that means?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:53] <strong>Cathy Mitchell:</strong> Yeah. That&#8217;s a pretty common phrase over here.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:55] <strong>Nathan Wrigley:</strong> Oh, okay.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:13:56] <strong>Cathy Mitchell:</strong> This side of the pond. You know, you kick the little birdies out, and they&#8217;re spreading their wings. All of a sudden we&#8217;re left with, it&#8217;s a different life stage. I think we were talking a little bit about it. You&#8217;re getting there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:14:08] <strong>Nathan Wrigley:</strong> I&#8217;m going to there very, yeah, awh, it&#8217;s kind of filled with melancholy. On the hand, obviously I would love for my children to grow up, but on the other hand it&#8217;s, pulls all the heartstrings, doesn&#8217;t it?</p>\n\n\n\n<p class=\"wp-block-paragraph\">So you are finding space in your life to do this kind of stuff. I&#8217;m going to ask a question, which is maybe a little bit personal, I don&#8217;t know. Hope you don&#8217;t read it in the wrong way. Do you find this stuff like meaningful and significant? Do you get a sense of fulfilment and satisfaction from the work that you are doing? For example, with WordCamp Canada.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Because there must be moments when it&#8217;s a real chore and, you know, you&#8217;ve got far too many tasks which are spilling over, and you think, gosh, I&#8217;m just a volunteer. There&#8217;s no quid pro quo here. I&#8217;m just doing it out of the goodness of my heart. But on balance, do you get that warm and fuzzy feeling from doing all of this?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:14:54] <strong>Cathy Mitchell:</strong> That&#8217;s a good question. I had time, so I started volunteering at a bunch of things. I started volunteering teaching kids, and then to go the complete other end of the spectrum, I did a seniors class at my local college last month. I just started volunteering because in my opinion, as a little amateur psychologist, I think service, serving our community is kind of the best way to, like you said, pull alongside someone. And then when you have like a focused goal, there&#8217;s a togetherness and I really need to grow my community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Me, and I think quite a few other people, there&#8217;s this whole epidemic of loneliness to be frank. Having raised the kids and then having done the job, now all of a sudden it&#8217;s like, I have time to invest in a real community. And I really want it to be worthwhile. I don&#8217;t want to sweep the floors for, maybe it&#8217;s an age thing, I don&#8217;t know. I&#8217;m so, so grateful that they let me do something that I&#8217;m good at, as far as organising, because they didn&#8217;t have to. That&#8217;s a big responsibility to put on somebody. And I am praying it all works out in the fall.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But it comes because of the huge number of volunteers that all work together. So my job&#8217;s just basically pulling all these people together, and making sure that we&#8217;re talking to each other. Because one person can&#8217;t possibly do all of the work that comes with putting on a conference. At least not part-time. But yeah, I&#8217;m finding it immensely rewarding because I also feel like I&#8217;m good at it. Everybody loves to do something they&#8217;re good at.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:16:28] <strong>Nathan Wrigley:</strong> You mentioned something earlier where you sort of implied that you were very surprised that in the WordPress world, you were given a bunch of responsibility for an event. I mean, basically, I think a lot of that, isn&#8217;t there? There&#8217;s a lot of, whoever can show up does get the job really, because there&#8217;s a paucity of volunteers. And for an event of the magnitude of WordCamp Canada, if you&#8217;ve ever been to events like that, you sort of walk in and on every level it feels like a corporate event. You know, it&#8217;s very polished, highly polished. There&#8217;s catering, the venue&#8217;s all been booked, you&#8217;ve got name badges and there&#8217;s probably some translation going on, and there slides and every, there&#8217;s timetables and everything. And it&#8217;s all done by volunteers.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I remember the same sort of thing, being asked to do a variety of different things and thinking, wait, really? You don&#8217;t know the inside of my head. I will mess this up so badly. But that is such a nice characteristic of our community. And you&#8217;ll fail together, if you know what I mean? You know, it is not like anybody&#8217;s going to let you deeply fail. People will step in and help you, should you need to.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:17:31] <strong>Cathy Mitchell:</strong> Yeah, we have to say yes, like it&#8217;s part of the culture is, if people volunteer, we have to find a way to say yes. Like our default is yes, not, well, have you done this first?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:17:43] <strong>Nathan Wrigley:</strong> Yeah. It&#8217;s interesting because you obviously have done a lot of this kind of corporate stuff, and so have the impression that you ought to be qualified, I don&#8217;t know, a decade or two decades of this particular thing in order to be trusted to do it. And this is just, yeah, this is so different. Anybody? Bueller. Okay, you&#8217;ll do it. Great. Fine. That&#8217;s great, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:18:03] <strong>Cathy Mitchell:</strong> Yeah. You&#8217;re hired.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:18:04] <strong>Nathan Wrigley:</strong> Yeah, that&#8217;s it. That&#8217;s I&#8217;ve never done it before. It doesn&#8217;t matter. You&#8217;ll be brilliant.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:18:07] <strong>Cathy Mitchell:</strong> We&#8217;ll help you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:18:08] <strong>Nathan Wrigley:</strong> Yeah. And that camaraderie of binding together on a particular thing, in your case WordCamp, but the broader project, you know, the WordPress project as a whole, I feel it&#8217;s full of these kind of people. And we will get into in a minute I&#8217;m sure, how that maybe has changed for some people in the more recent past, and about the fact that the community does feel like it&#8217;s in a bit of a challenging place at the moment.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But I just want to go back a little bit because you mentioned, and neither of us I suspect will have the answer to this, but I&#8217;m interested in your intuitions anyway. You mentioned that people nowadays, maybe this has always been the case, but it feels like there&#8217;s been a change. Loneliness seems to be a very common thing now. And my sort of back of the napkin calculus points me in the direction of wondering if it is actually oddly technology. The very thing that we&#8217;re celebrating. If technology might be responsible for it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">For example, I look around and I see a lot of people who give an awful lot of what would&#8217;ve otherwise been free time, time that they could have gone out and socialised and what have you. And, you know, you sort of end up sitting on the couch and scrolling through social media and things like that.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Television has become so absolutely fascinating. You know, there&#8217;s like a billion different channels, and essentially there&#8217;s a thousand ways to keep yourself entertained all by yourself, and never speak to another human being, or be in proximity to another human being. There&#8217;s no question there, I just wondered if you had an observation or a similar thought process.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:19:39] <strong>Cathy Mitchell:</strong> I looked up, because I knew we were going to talk about this, the stat on it. Because I know I&#8217;ve had the same feeling. And I&#8217;ve heard people talk about it, but I didn&#8217;t really know if that was like true or not, because whenever I am thinking or researching something, of course that&#8217;s what the algorithm shows me. So I&#8217;m always kind of hesitant, like is this actually real or am I just seeing this?</p>\n\n\n\n<p class=\"wp-block-paragraph\">But it did say in a 2021 report, the US Surgeon General, and this is in the States, no 2023, that the health impact of a loneliness epidemic. Okay, General Vivek Murthy declared a loneliness epidemic in 2023. And he said that the health impact is the same as smoking 15 cigarettes a day. It&#8217;s not good for us. And that the biggest effect, 79% reported feeling lonely of the 18 to 24-year-old group, which is more like 40 some percent. What was it? 41% of 66 plus.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:35] <strong>Nathan Wrigley:</strong> Okay, so the younger you skew, the more lonely you are likely to be.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:40] <strong>Cathy Mitchell:</strong> Yeah. And we also see, now I don&#8217;t know if this is correlative or causative, but technology has also skyrocketed in that period of time.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:20:48] <strong>Nathan Wrigley:</strong> Yes. Yeah, and also probably, again, I&#8217;m drawing conclusions which are not based in fact or research or anything like that. You and I were both born in an era where that technology wasn&#8217;t available. So I imagine patterns were set down in our infant brains, which are perhaps different to the patterns that are set down now.</p>\n\n\n\n<p class=\"wp-block-paragraph\">It&#8217;d be curious to see if there is a there, there. If the broad adoption, certainly in the UK, I can&#8217;t speak to Canada, but the broad adoption of technology to ever and ever younger children, to a really alarmingly early age. You know, you see children who are not even at school age who seem to have access to every technology under the sun, and who don&#8217;t seem to get that interaction from another human being. I wonder. And I&#8217;m going to sound all curmudgeonly and there&#8217;s probably going to be people shouting at me.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:21:34] <strong>Cathy Mitchell:</strong> I have seen it change with the Gen Z that they&#8217;re talking about. And my kids fall in that category. Whereas I wanted to be, okay, it&#8217;s personal responsibility, so we&#8217;re going to raise them. It was new to me, so I raised my kids thinking, okay, tablets, I&#8217;m going to teach you how to use it, not restrict it. I was all open-minded about all.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Now they&#8217;ve told me that if they have kids, they will restrict it far greater than I ever did. They were like, they won&#8217;t have nearly the freedom that I gave them in my open-mindedness.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:06] <strong>Nathan Wrigley:</strong> Yeah, well, but you are forgiven for your open-mindedness because I guess humanity perhaps needed more evidence to draw conclusions around that. And perhaps those conclusions are now landing.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:16] <strong>Cathy Mitchell:</strong> I think so.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:22:16] <strong>Nathan Wrigley:</strong> Yeah, well, certainly as an example, I know that in Australia more recently, there&#8217;s now a widespread ban, I think under the age of 16, and I&#8217;m going to use the word illegal, maybe that&#8217;s the wrong word. Maybe there&#8217;s a technical definition, but social media is not permitted for children under the age of 16. And I think that there&#8217;s legislation being talked about in the UK of a similar nature, and some other European countries.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I don&#8217;t know how much traction that will have because I feel that there&#8217;s a persuasive argument, much like you described of, it&#8217;ll all work itself out. You know, we don&#8217;t need the government to tell us what to do, and all of that, and that all makes sense.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But my, I can well understand, I think in the UK also, there is a growing, a groundswell of this alternative way of looking at it. Like a rejection of the phones and the technology.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Anyway, there we go. That was an aside. Do you want to contribute into that a little bit more before I push us back in the WordPress space?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:23:11] <strong>Cathy Mitchell:</strong> Yeah, I don&#8217;t want to be all, it&#8217;s bad, it&#8217;s bad, but I think that we&#8217;re seeing an effect. I really do believe that volunteerism, whether it&#8217;s with WordPress or anything else, in my faith background, being a person, a Christian person, I grew up seeing the service as an answer, as just part of our lifestyle. You just serve others. But now I&#8217;m seeing it come in a secular sort of way as well, where service is an antidote to loneliness.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I think no matter where you&#8217;re serving, not the church or any, like just pick a service. Being that cameraderie with people, having a similar goal, going in the same direction, like I really do think there&#8217;s hope. There&#8217;s hope out there for all of us. And it&#8217;s a great way to do something meaningful. Like you get to do all those things. You get to practise a skill, you get to do something meaningful, you get direction, you get cameraderie all by serving.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:24:03] <strong>Nathan Wrigley:</strong> I&#8217;m going to, say something now, and I&#8217;m going to caveat it heavily before I say it because A, it relies on my prodigiously bad memory, and B, it could just be fabricated anyway because the source could be utterly wrong. But it feels like there&#8217;s a kernel of truth in it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I was doing some research recently about happiness, that broad subject. You know, we would all like to be happy I&#8217;m sure. There&#8217;s a lot of people who spend a lot of time thinking about what this actually means, and trying to drill it down to some fairly basic maxims, if you like, for what leads to happiness.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Two of the biggest indicators of happiness are really interesting. One of the two is how often you spend with other people basically. How much time you interact with other human beings. Now I know that that&#8217;s not for everybody, but broadly speaking, that seems to be a huge indicator. If you actually get yourself out and you do things with other human beings, there is a definite benefit.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And the other one, which is very curious because I think it&#8217;s fair to say, you know, Canada and the UK, we&#8217;ve been brought up to worry about our own finances and amassing as much stuff as we can, and lining your nest for the future and everything. Well, this other one, controversially, the second one that I&#8217;m going to mention is the amount of stuff that you basically give away. And that could be time, or it could be finance, it could be any of those things. The more that you give away with no expectation of a return, that also apparently is a real indicator of happiness.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I think we can all identify that. That moment where you give somebody a gift and you&#8217;ve really thought about it, and you hand it over and you watch the face change as they unwrap it. And you think, they&#8217;ve loved that, haven&#8217;t they? And you&#8217;re not thinking to yourself, well, I did that. I made them happy there. You&#8217;re just thinking, oh look, they&#8217;re really happy. Isn&#8217;t that wonderful? So anyway, there&#8217;s my 2 cents of utterly unproven thoughts.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:25:59] <strong>Cathy Mitchell:</strong> Okay. Learned something. Those are two, so the two things were being around people and altruism basically, with nothing expected in return.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:08] <strong>Nathan Wrigley:</strong> And funnily enough, they map very closely to what we&#8217;re talking about, right? We&#8217;re talking about events and socialising with other people, but also that, in this case, it&#8217;s not a financial thing that you are giving away, but you are definitely giving away an awful lot of your time for doing these kind of things. And maybe, given that little bit of information, it kind of becomes a little bit easier to justify because if you can say to yourself, this makes me happy, it might not seem it in those stressful moments.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:36] <strong>Cathy Mitchell:</strong> Yeah, today.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:37] <strong>Nathan Wrigley:</strong> Yeah, that&#8217;s right. But ultimately that might be causing your happiness.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Okay, so there we go. That was our little segue. Let&#8217;s sort of bring it back to WordCamps. You were very kind to write me a bunch of show notes, and they really drew me in as I was reading them. And I want to sort of dwell on a few of them because you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:53] <strong>Cathy Mitchell:</strong> Had to convince you to get me on the podcast.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:26:54] <strong>Nathan Wrigley:</strong> Yeah, no, there not a lot of convincing needed. I loved it. You&#8217;ve got some sort of bullet points if you like, not really bullet points. You&#8217;ve touched on different areas where you feel that you&#8217;ve got something to say about, I dont know, why people might contribute and why they might volunteer and what have you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So it&#8217;s things like, why might new people, newbies, as you&#8217;ve described them, volunteer and why might business folk volunteer?</p>\n\n\n\n<p class=\"wp-block-paragraph\">So the first one was, let me go back. So I&#8217;ll read into the record what you wrote because it makes a lot of sense. You said, in 2025 I helped the organisers for WordCamp Canada and this year found myself the lead organiser. And this has been consistently one of the nicest, most open groups, that I&#8217;ve ever been part of. And then you strayed into why other people, for example, new people and business people might like to contribute.</p>\n\n\n\n<p class=\"wp-block-paragraph\">So on the business side, you said, volunteers, boundaries when not getting paid, giving back, sponsoring folks, not necessarily a financial return on investment. And then for the newbies, you said, there&#8217;s other ways to contribute, for example, contributing in code or non-coding ways, and also just being a recipient of the open, friendly community that you encounter. So that was really it. Maybe I&#8217;ve said everything that you wanted to say.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:28:07] <strong>Cathy Mitchell:</strong> Well, those are kind of questions that I had coming from a corporate, and I keep talking to different people trying to figure out, I guess I&#8217;m looking for something other than altruism when comes to the corporate people at least. Like why are they sponsoring? And I can see, the pessimistic, or maybe the pragmatic, side of me to be positive wants to know why. Why are they putting the dollars in?</p>\n\n\n\n<p class=\"wp-block-paragraph\">But then on the other side, I think, well, if WordPress doesn&#8217;t do well, then they don&#8217;t do well. Like, if their businesses are based on WordPress. But then I also saw something that, if you sponsor open source projects, it makes hiring people that much easier, and also vetting people that much easier. Because it gets you into the community and so it goes both ways. People will be more likely to apply for your jobs and you will be more likely to have a way to vet them. That&#8217;s one thing I saw.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:29:04] <strong>Nathan Wrigley:</strong> I think there&#8217;s a lot of truth in that, or at least I&#8217;d like to believe there&#8217;s a lot of truth in that. That makes me feel happy about the whole situation. But what&#8217;s curious about what you&#8217;ve just said, and I don&#8217;t know how much of an intuition you&#8217;ve got on this, but if you were to go back to, let&#8217;s say the year, oh, I don&#8217;t know, 2018 or something like that, WordPress was experiencing this really stratospheric growth. You know, in terms of market share of the internet broadly, you know, the number of websites as a percentage, WordPress was going from sort of the low twenties to the mid twenties, high twenties, and then through the thirties, and then finally landing at this sort of 40%.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And during that time, saying this phrase sounds ridiculous because it is ridiculous, WordPress could kind of do no wrong, I think. There was just growth upon growth upon growth and a lot of companies, I don&#8217;t think needed to explain themselves to their directors quite so much. The return on the investment didn&#8217;t need to be made. It was just, look, we&#8217;re part of this thing, and there&#8217;s this rising tide, and we are one of the boats. And look, we&#8217;re going up as it all goes up. So it just happened.</p>\n\n\n\n<p class=\"wp-block-paragraph\">However, during COVID, and then especially over the last few years, and then now especially the last couple of years, inject AI into the mix, I feel that that calculus has changed a little bit. And there&#8217;s this inkling when you speak to the same corporate people who a few years ago were willing to open their wallets to sponsor events, the wallets are much, much harder to open.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Again, in much the same way that I don&#8217;t really know why the community is so fabulous. I don&#8217;t really know why the wallets are harder to open. But I think the landscape for sponsorship, and the requirement of a return on investment, as opposed to, well let&#8217;s just join in because WordPress is growing. I think that calculation is going to be harder and harder to make. And maybe you&#8217;ve got experience of this over at WordCamp Canada trying to gather sponsors. Perhaps you found it straightforward. Perhaps it&#8217;s been difficult. I don&#8217;t really know.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:31:08] <strong>Cathy Mitchell:</strong> There&#8217;s almost like a perfect storm right now because wallets are tighter because over the last few years, at least in the States where my clients are, it&#8217;s become, economically there&#8217;s uncertainty. And so that trickles down and trickles up, right? And so more wallets are going to be a little bit more restrictive on what they&#8217;re going to buy, and they&#8217;re going to want to see more bang for their buck.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Corporately, also there&#8217;s been this huge rise in competition in the corporate world. There&#8217;s just way more competition over the last five or six years for just about anything when it comes to agencies or plugins or themes or whatever, there&#8217;s a lot more great competition, like good products out there. But then there&#8217;s also a lot more competition to get the clients, like clients have a lot more options.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And so I think it&#8217;s a perfect storm. Like, do you want to put your money into WordPress because is that the future? Is there money for sponsorship? Plus WordPress has become stricter on what they require to sponsor, as far as trademark use and different things that have been put higher on the priority list.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I kind of see it like a levelling off. Like not as a bad thing because every industry can&#8217;t just, go, go, go, go. Like there&#8217;s going to be a levelling, right? Can&#8217;t be that easy. When I started, I didn&#8217;t even advertise. And I&#8217;ve had this business for 19 years. I&#8217;ve never advertised. That is going to go away. Like it was just, you know, I lucked out starting somewhere, but that&#8217;s not realistic.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:32:44] <strong>Nathan Wrigley:</strong> So what&#8217;s interesting in that is I think I am the same. The only period in which I&#8217;ve been in the WordPress community was during this stratospheric growth period really. Everything has been, you know, people have argued on the inside about this, that, and the other thing, and whether a feature should ship in Core, or whether or not we should do this thing at an event or what have you. So there&#8217;s been some minor disagreements.</p>\n\n\n\n<p class=\"wp-block-paragraph\">But broadly speaking, the whole project has just swelled and swelled and swelled. There&#8217;s this overarching sense of optimism and growth, and now the brakes are on. And so for me, it feels like unfamiliar territory. And because it&#8217;s unfamiliar, it feels a little bit scary because I don&#8217;t know what that means. I don&#8217;t know whether that means that things are going to just level out as you just described, or whether it means things are going to decline, or whether it means some of my friends are going to go away because the community, it&#8217;s no longer going to be something that they wish to frequent because their profitability is under question and they need to seek revenue from other different options. Maybe AI, maybe, whatever it might be. And so I think my concern just, it&#8217;s probably self-interest really. I&#8217;m just concerned because I don&#8217;t know what&#8217;s coming and that fear is, well, it&#8217;s fear.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:33:57] <strong>Cathy Mitchell:</strong> I think this brings me perfectly into the WordCamp Canada thing that I wanted to mention. Just because I see this event, and even the community team, as a whole in WordPress. There are teams in WordPress, by the way, for people that don&#8217;t know, that help you get involved. It&#8217;s not just coders, like there&#8217;s all kinds of teams. And one of them is the community team, and all we have to know how to do is plan an event or host an event or serve coffee. It&#8217;s amazing. But anyway.</p>\n\n\n\n<p class=\"wp-block-paragraph\">I am excited about WordCamp Canada, and the reason I&#8217;m putting so much time and effort into this conference is because I really see it as a light at the end of this tunnel. Not at the end. Maybe midway. I have no idea what&#8217;s going to happen to my own business, to WordPress, I don&#8217;t know. But I think there&#8217;s one thing that I&#8217;m fairly certain of, even now, even in the midst of AI, and that&#8217;s open source. I really still believe that open source is the way of the future. I still think it is, open source and AI are probably the way of the future. Yeah, I don&#8217;t know how else to say it.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I think the exciting thing, and the thing that we need to do as people who got to take advantage of that uprise and that uptick, is you and I need to get young people involved. Like we need to get those young people involved in open source. I don&#8217;t even care if it&#8217;s WordPress or not, but they need to become part of a community that is exciting, that is beyond themselves. They need to see that we&#8217;re nice. We don&#8217;t bite. We&#8217;ll hire them. There&#8217;s just so much good that can come out of being together. And these are the nicest people. They&#8217;ll talk to people that are just standing around in the hallways with nobody to talk to, which is me. I&#8217;m an introvert, ironically.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:38] <strong>Nathan Wrigley:</strong> You definitely don&#8217;t come across like that, just so that you know.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:40] <strong>Cathy Mitchell:</strong> Well, we&#8217;re I&#8217;m pretending nobody else is listening.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:35:43] <strong>Nathan Wrigley:</strong> The other thing that I would add, as you were saying all of those things, it occurred to me that, I would imagine that people in more senior positions, I don&#8217;t really know how to describe it in the WordPress world, have got a similar intuition to the one that you just described. In that they can definitely see that the future needs to be thought about in terms of the youth coming in. Because there&#8217;s an awful lot of work being done at the moment and an awful lot of hours being put into educational initiatives.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And also, not just where you and I are living, but all over the world. And it was kind of interesting at WordCamp Asia recently, that was a big focus. A lot of people talking about exactly this thing and these kind of overlapping initiatives that are beginning to bear fruit. So people coming out of universities who&#8217;ve had experience of open source and WordPress in particular. And children at schools having experience of open source and WordPress.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And I think, as much as we would like open source and WordPress to win, just from a moral point of view, wouldn&#8217;t that be a great thing if everybody just noticed it and got on and used it? I think we need to do a bit of work to make sure that it&#8217;s being put under their noses so that they can make those judgements for themselves. And that is definitely a part of the future.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:36:57] <strong>Cathy Mitchell:</strong> Yeah, the Campus Connect and the Credits where they can university credits, like it is getting popular in other places we haven&#8217;t heard so much. But I really want to introduce it and bring it to the conference in Vancouver this fall. Because we can have universities in Canada and the US, on this side of the pond get involved in this and actually give kids credits that they can use to graduate.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:37:21] <strong>Nathan Wrigley:</strong> It&#8217;s so interesting as well because it&#8217;s very hard to, how to describe this, that&#8217;s a difficult one to sell, let&#8217;s put it that way. The people that are really into those initiatives really love it, but it&#8217;s hard to get people to notice that that&#8217;s going on, and hard for people perhaps to notice how important that is. But without those little foundational bricks being put in place for the future, this rising tide carries all boats metaphor, that&#8217;s not going to happen. You know, I think maybe another good metaphor there is they&#8217;re kind of building the harbour wall to make sure that the boats have got something to rise against. And I think that&#8217;s really important.</p>\n\n\n\n<p class=\"wp-block-paragraph\">And your part of the world is definitely open to that, I&#8217;m sure. Seems to be that some European institutions, colleges, universities and South American institutions and parts in India and Southeast Asia and places like that are also beginning to bite on those ideas as well. So it&#8217;d be really interesting to see how that all goes.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You&#8217;re painting a picture, Cathy, which makes me feel optimistic. Feels like there&#8217;s a lot of positivity coming out of where you are, yeah.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:38:24] <strong>Cathy Mitchell:</strong> I&#8217;m probably going to get in trouble for saying this, but for all of the faults that Matt might be accused of, somehow he put something in place that became very, very popular. And the culture that I have been a part of, I haven&#8217;t worked for Automattic, but the culture at the WordCamp level and volunteering and the community team has been unbelievably positive, and foreign to me. Like I&#8217;ve had to learn this culture. What do you mean there&#8217;s no application process? How do I say yes? What are you talking about? So somehow this has grown. And he has had a lot to do with it. People don&#8217;t like that he&#8217;s had a lot to do with it, but there&#8217;s some truth there.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:39:07] <strong>Nathan Wrigley:</strong> It&#8217;s really interesting and it doesn&#8217;t matter how many times I have conversations like this, I&#8217;m always confused by it. I can never get my hands around it and work out what the secret sauce is so that I could copy and paste it into a different locale or a different jurisdiction or different era. But there&#8217;s a there, there. There&#8217;s something very satisfying about this community. And from everything that you&#8217;ve said, it sounds like you are very positive about it. And I share your positivity, even though sometimes it seems quite hard to grasp in the more recent times.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Oh, Cathy, that&#8217;s been absolutely wonderful. I&#8217;ve enjoyed chatting to you today. We&#8217;ve hit the sort of sweet spot of the amount of time that we&#8217;ve got, so if it&#8217;s okay with you, we&#8217;ll wrap it up there. Just before we go, if anybody wants to get in touch with you, or just sort of wants to pat you on the back for your wisdom there, where would we find you?</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:39:55] <strong>Cathy Mitchell:</strong> Well they can find me at WPBarista. And right now they can also find me at canada.wordcamp.org.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:40:02] <strong>Nathan Wrigley:</strong> Okay. Well I will make sure that that goes into the show notes. So if you&#8217;re listening to this, head to wptavern.com, search for the episode with Cathy Mitchell, that&#8217;s Cathy with a C, and you&#8217;ll be able to find the details in the show notes there. So Cathy Mitchell, thank you very much for chatting to me today. That was lovely. Thank you.</p>\n\n\n\n<p class=\"wp-block-paragraph\">[00:40:19] <strong>Cathy Mitchell:</strong> Thank you. I enjoyed it.</p>\n</div></details>\n\n\n\n<p class=\"wp-block-paragraph\">So on the podcast today we have Cathy Mitchell.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cathy has been working with WordPress since 2007. What began as a fun personal project during her maternity leave soon evolved into a fully fledged business with the launch of WPBarista in 2008. Over the years, Cathy has garnered extensive experience in the WordPress space, and is now working towards the 2026 WordCamp Canada.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The conversation focuses on the powerful role of community within the WordPress ecosystem, something that Cathy is deeply passionate about. We discuss how open, welcoming, and international the WordPress community feels compared to more traditional corporate or volunteer environments. A theme that emerged was how involvement in WordPress has provided Cathy, and many others, with a sense of belonging and fulfillment, especially after life changes like becoming an &#8220;empty nester&#8221;.</p>\n\n\n\n<p class=\"wp-block-paragraph\">The discussion explores the motivations for volunteering and organising within the WordPress community, both from the perspective of newcomers looking for purpose and connection, and business owners assessing the return on investment from contributing or sponsoring events. This included how easy it is to get involved, the unique lack of barriers and red tape, and the value of altruism and camaraderie.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Other topics we explored were the broader impact of technology and loneliness, the importance of service and community for well-being, challenges in sponsorship amid changing economic times, and the vital need to engage the next generation in open source.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you’re interested in the human side of WordPress, how volunteering shapes both individuals and the broader community, and what the future might hold for WordPress events and contributors, this episode is for you.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Useful links</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wpbarista.com\"> WPBarista</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://canada.wordcamp.org/2026/\">WordCamp Canada 2026</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://london.wordcamp.org/2019/\">WordCamp London</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://events.wordpress.org/campusconnect/\"> WordPress Campus Connect</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://wordpress.org/education/credits/\">WordPress Credits</a></p>\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jun 2026 14:00:00 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Nathan Wrigley\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:49;a:6:{s:4:\"data\";s:21:\"\n	\n	\n	\n	\n	\n	\n	\n	\n	\n	\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:2:{s:0:\"\";a:5:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:117:\"Open Channels FM: BackTalk on AI Burnout, Bridging Innovation and Standards, and the Risks of Single-Maintainer Tools\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:34:\"https://openchannels.fm/?p=2555405\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:122:\"https://openchannels.fm/backtalk-on-ai-burnout-bridging-innovation-and-standards-and-the-risks-of-single-maintainer-tools/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:212:\"Conversations reveal insights on deep work, innovation standards, and the risks of underappreciated developer tools, highlighting challenges of mental fatigue, standardization, and reliance on single maintainers.\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 10 Jun 2026 09:40:19 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Bob Dunn\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:9:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Fri, 10 Jul 2026 16:09:47 GMT\";s:12:\"content-type\";s:8:\"text/xml\";s:13:\"last-modified\";s:29:\"Fri, 10 Jul 2026 15:45:29 GMT\";s:4:\"vary\";s:15:\"Accept-Encoding\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:4:\"gzip\";s:7:\"alt-svc\";s:5:\"clear\";s:4:\"x-nc\";s:9:\"HIT dca 2\";}s:5:\"build\";i:1760643936;s:21:\"cache_expiration_time\";i:1783742986;s:23:\"__cache_expiration_time\";i:1783742986;}','off');
